import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [scans, setScans] = useState<ScanningData[]>([]);

  // Orders Master Filter
  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');

  // Scanning Form State
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // Seed initial scans for realistic dashboard view
  useEffect(() => {
    const initialScans: ScanningData[] = [];
    const nowStr = new Date().toISOString();

    MOCK_ORDERS.forEach(order => {
      // Seed Cutting
      initialScans.push({
        id: crypto.randomUUID(),
        qr_id: `PG-CUT-${order.style}`,
        process: 'Cutting Done',
        qty: 3500,
        status: ProductionStatus.COMPLETED,
        line: 'N/A',
        scanned_by: crypto.randomUUID(),
        scan_time: nowStr
      });

      // Seed Sewing Lines 1-15
      for (let i = 1; i <= 15; i++) {
        const line = `Line-${i}`;
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-SEW-IN-${order.style}-${i}`,
          process: 'Sewing Input',
          qty: 300,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-SEW-OUT-${order.style}-${i}`,
          process: 'Sewing Output',
          qty: 280,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
      }

      // Seed Washing
      initialScans.push({
        id: crypto.randomUUID(),
        qr_id: `PG-WASH-IN-${order.style}`,
        process: 'Wash Input',
        qty: 2000,
        status: ProductionStatus.COMPLETED,
        line: 'N/A',
        scanned_by: crypto.randomUUID(),
        scan_time: nowStr
      });
      initialScans.push({
        id: crypto.randomUUID(),
        qr_id: `PG-WASH-OUT-${order.style}`,
        process: 'Wash Output',
        qty: 1950,
        status: ProductionStatus.COMPLETED,
        line: 'N/A',
        scanned_by: crypto.randomUUID(),
        scan_time: nowStr
      });

      // Seed Finishing Lines 1-10
      for (let i = 1; i <= 10; i++) {
        const line = `Line-${i}`;
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-FIN-IN-${order.style}-${i}`,
          process: 'Finishing Input',
          qty: 180,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-FIN-OUT-${order.style}-${i}`,
          process: 'Finishing Output',
          qty: 170,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
      }
    });

    setScans(initialScans);
  }, []);

  // Aggregated Stats for Dashboard Cards
  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    // 1. Search in QR Master first
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Code Loaded Successfully from Master.', type: 'success' });
        return;
      }
    }

    // 2. Fallback for unique code starting with PG-
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanStatus({ message: 'Dynamic scan code detected. Auto-assigning to default order.', type: 'success' });
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100, // Default bundle pieces for dynamic codes
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid QR Code. Format must be PG-YYYYMMDDXXXXXX', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;

    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: crypto.randomUUID(),
      scan_time: new Date().toISOString()
    };

    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Recorded ${scanningDetail.bundle_qty} pieces for ${selectedProcess}`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string, line?: string) => {
    return scans.filter(s => {
      const belongs = qrCodes.find(q => q.qr_id === s.qr_id && q.order_id === orderId) || 
                      s.qr_id.includes(orders.find(o => o.id === orderId)?.style || '---');
      const lineMatch = line ? s.line === line : true;
      return belongs && s.process === process && lineMatch;
    }).reduce((a, b) => a + b.qty, 0);
  };

  const getTableData = useCallback(() => {
    const baseCols = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'country', label: 'Country' },
      { key: 'color', label: 'Color' },
      { key: 'size', label: 'Size' },
      { key: 'po_qty', label: 'PO Qty' },
    ];

    let headers = [...baseCols];
    let rows: any[] = [];

    if (orderProcessFilter === 'all') {
      headers.push(
        { key: 'c_qty', label: 'Cutting' },
        { key: 's_in_qty', label: 'Sewing In' },
        { key: 's_out_qty', label: 'Sewing Out' },
        { key: 'w_in_qty', label: 'Wash In' },
        { key: 'w_out_qty', label: 'Wash Out' },
        { key: 'f_in_qty', label: 'Finishing In' },
        { key: 'f_out_qty', label: 'Finishing Out' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
        s_in_qty: getOrderProcessQty(o.id, 'Sewing Input'),
        s_out_qty: getOrderProcessQty(o.id, 'Sewing Output'),
        w_in_qty: getOrderProcessQty(o.id, 'Wash Input'),
        w_out_qty: getOrderProcessQty(o.id, 'Wash Output'),
        f_in_qty: getOrderProcessQty(o.id, 'Finishing Input'),
        f_out_qty: getOrderProcessQty(o.id, 'Finishing Output')
      }));
    } else if (orderProcessFilter === 'cutting') {
      headers.push({ key: 'cutting_done', label: 'Cutting Done Qty' });
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        cutting_done: getOrderProcessQty(o.id, 'Cutting Done')
      }));
    } else if (orderProcessFilter === 'sewing') {
      headers.push(
        { key: 'sewing_input', label: 'Sewing Input' },
        { key: 'line', label: 'Line' },
        { key: 'wip', label: 'WIP' },
        { key: 'sewing_output', label: 'Sewing Output' }
      );
      orders.forEach(o => {
        for (let i = 1; i <= 15; i++) {
          const l = `Line-${i}`;
          const inp = getOrderProcessQty(o.id, 'Sewing Input', l);
          const outp = getOrderProcessQty(o.id, 'Sewing Output', l);
          if (inp > 0 || outp > 0) {
            rows.push({
              ...o,
              timestamp: new Date().toISOString(),
              sewing_input: inp,
              line: l,
              wip: inp - outp,
              sewing_output: outp
            });
          }
        }
      });
    } else if (orderProcessFilter === 'washing') {
      headers.push(
        { key: 'wash_input', label: 'Wash Input' },
        { key: 'wash_output', label: 'Wash Output' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: new Date().toISOString(),
        wash_input: getOrderProcessQty(o.id, 'Wash Input'),
        wash_output: getOrderProcessQty(o.id, 'Wash Output')
      }));
    } else if (orderProcessFilter === 'finishing') {
      headers.push(
        { key: 'finishing_input', label: 'Finishing Input' },
        { key: 'line', label: 'Line' },
        { key: 'wip', label: 'WIP' },
        { key: 'finishing_output', label: 'Finishing Output' }
      );
      orders.forEach(o => {
        for (let i = 1; i <= 10; i++) {
          const l = `Line-${i}`;
          const inp = getOrderProcessQty(o.id, 'Finishing Input', l);
          const outp = getOrderProcessQty(o.id, 'Finishing Output', l);
          if (inp > 0 || outp > 0) {
            rows.push({
              ...o,
              timestamp: new Date().toISOString(),
              finishing_input: inp,
              line: l,
              wip: inp - outp,
              finishing_output: outp
            });
          }
        }
      });
    }
    return { headers, rows };
  }, [orderProcessFilter, orders, scans, qrCodes]);

  const handleDownloadExcel = useCallback(() => {
    const { headers, rows } = getTableData();

    // Create CSV content (Excel compatible)
    const csvRows = [];

    // Add header row
    csvRows.push(headers.map(h => `"${h.label}"`).join(','));

    // Add data rows
    rows.forEach(row => {
      const values = headers.map(h => {
        let val = row[h.key];
        if (h.key === 'timestamp') {
          val = new Date(val).toLocaleString();
        }
        // Handle numbers and escape strings
        const escaped = ('' + (val ?? '')).replace(/"/g, '""');
        return `"${escaped}"`;
      });
      csvRows.push(values.join(','));
    });

    const csvString = csvRows.join('\n');
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `PG_Orders_Master_${orderProcessFilter}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, [getTableData, orderProcessFilter]);

  const renderOrdersTable = () => {
    const { headers, rows } = getTableData();

    return (
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left whitespace-nowrap">
            <thead className="bg-gray-50 text-gray-500 uppercase text-[10px] font-bold tracking-wider">
              <tr>{headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {rows.map((row, idx) => (
                <tr key={idx} className="hover:bg-gray-50 transition-colors">
                  {headers.map(h => (
                    <td key={h.key} className="px-6 py-3 text-sm font-medium text-gray-700">
                      {h.key === 'timestamp' ? new Date(row[h.key]).toLocaleString() : row[h.key]}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          {/* Attractive Grouped Dashboard Design */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Cutting Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between hover:shadow-lg transition-all group border-l-4 border-l-blue-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-blue-50 p-3 rounded-xl text-blue-600">✂️</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Cutting Section</h4>
                </div>
                <span className="text-[10px] font-black text-blue-500 bg-blue-50 px-2 py-1 rounded">DEPT-01</span>
              </div>
              <div className="space-y-6">
                <div>
                  <p className="text-xs font-bold text-gray-400 uppercase mb-1">Total Finished Pieces</p>
                  <h5 className="text-4xl font-black text-blue-600">{dashboardStats.cuttingDone} <span className="text-lg font-medium text-gray-400">pcs</span></h5>
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-black text-gray-400 uppercase">
                    <span>Daily Progress</span>
                    <span>92%</span>
                  </div>
                  <div className="w-full bg-gray-100 h-3 rounded-full overflow-hidden">
                    <div className="bg-blue-500 h-full w-[92%] transition-all duration-1000"></div>
                  </div>
                </div>
              </div>
            </div>

            {/* Sewing Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg transition-all group border-l-4 border-l-indigo-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-indigo-50 p-3 rounded-xl text-indigo-600">📥</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Sewing Production</h4>
                </div>
                <span className="text-[10px] font-black text-indigo-500 bg-indigo-50 px-2 py-1 rounded">15 LINES</span>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Total Input</p>
                  <h5 className="text-2xl font-black text-indigo-600">{dashboardStats.sewingInput}</h5>
                </div>
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Total Output</p>
                  <h5 className="text-2xl font-black text-green-600">{dashboardStats.sewingOutput}</h5>
                </div>
              </div>
              <div className="mt-6 flex justify-between items-center bg-indigo-50/50 p-3 rounded-lg border border-indigo-100">
                <p className="text-[10px] font-black text-indigo-800 uppercase tracking-widest">Sewing WIP GAP</p>
                <p className="text-lg font-black text-indigo-600">{dashboardStats.sewingInput - dashboardStats.sewingOutput} pieces</p>
              </div>
            </div>

            {/* Wash Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg transition-all group border-l-4 border-l-cyan-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-cyan-50 p-3 rounded-xl text-cyan-600">🧼</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Washing Department</h4>
                </div>
                <span className="text-[10px] font-black text-cyan-500 bg-cyan-50 px-2 py-1 rounded">CENTRAL</span>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="border-r border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Laundry In</p>
                  <h5 className="text-2xl font-black text-cyan-600">{dashboardStats.washInput}</h5>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Laundry Out</p>
                  <h5 className="text-2xl font-black text-green-600">{dashboardStats.washOutput}</h5>
                </div>
              </div>
              <div className="mt-6 flex justify-between items-center bg-cyan-50/50 p-3 rounded-lg border border-cyan-100">
                <p className="text-[10px] font-black text-cyan-800 uppercase tracking-widest">Wash Queue</p>
                <p className="text-lg font-black text-cyan-600">{dashboardStats.washInput - dashboardStats.washOutput} pieces</p>
              </div>
            </div>

            {/* Finishing Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg transition-all group border-l-4 border-l-emerald-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-emerald-50 p-3 rounded-xl text-emerald-600">🏁</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Finishing & QC</h4>
                </div>
                <span className="text-[10px] font-black text-emerald-500 bg-emerald-50 px-2 py-1 rounded">10 LINES</span>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">QC Input</p>
                  <h5 className="text-2xl font-black text-emerald-600">{dashboardStats.finishingInput}</h5>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Passed (Packed)</p>
                  <h5 className="text-2xl font-black text-green-600">{dashboardStats.finishingOutput}</h5>
                </div>
              </div>
              <div className="mt-6 flex justify-between items-center bg-emerald-50/50 p-3 rounded-lg border border-emerald-100">
                <p className="text-[10px] font-black text-emerald-800 uppercase tracking-widest">Processing WIP</p>
                <p className="text-lg font-black text-emerald-600">{dashboardStats.finishingInput - dashboardStats.finishingOutput} pieces</p>
              </div>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex flex-col xl:flex-row justify-between items-center gap-6">
            <h3 className="text-2xl font-black text-gray-800 tracking-tight">ORDERS MASTER LEDGER</h3>
            <div className="flex flex-wrap items-center justify-center gap-4">
               <div className="flex bg-white p-1 rounded-xl shadow-sm border border-gray-100">
                {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                  <button
                    key={f}
                    onClick={() => setOrderProcessFilter(f)}
                    className={`px-6 py-2.5 text-[10px] font-black uppercase rounded-lg transition-all tracking-wider ${
                      orderProcessFilter === f ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-gray-500 hover:text-gray-800 hover:bg-gray-50'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
              <button 
                onClick={handleDownloadExcel}
                className="flex items-center space-x-2 bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-lg shadow-green-900/10 active:scale-95"
              >
                <span>📥</span>
                <span>DOWNLOAD EXCEL</span>
              </button>
            </div>
          </div>
          {renderOrdersTable()}
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-gray-100 text-center relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -z-0 opacity-50"></div>
            <h3 className="text-3xl font-black text-gray-900 mb-2 relative z-10">Production Gateway</h3>
            <p className="text-gray-500 mb-10 relative z-10">Scan PG- coded bundles or manual ID entry for real-time tracking.</p>

            <div className="flex flex-col md:flex-row space-y-4 md:space-y-0 md:space-x-4 max-w-2xl mx-auto relative z-10">
              <input 
                type="text" 
                value={currentQR}
                onChange={(e) => setCurrentQR(e.target.value)}
                placeholder="Scan / Type PG-..."
                className="flex-1 border-2 border-gray-200 rounded-2xl px-6 py-5 focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none text-2xl font-black tracking-widest transition-all placeholder:font-normal placeholder:tracking-normal placeholder:text-gray-300"
                onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
              />
              <button 
                onClick={handleQRSearch} 
                className="bg-slate-900 text-white px-10 py-5 rounded-2xl font-black text-lg hover:bg-black transition shadow-2xl active:scale-95"
              >
                IDENTIFY
              </button>
            </div>

            {scanStatus.message && (
              <div className={`mt-6 inline-flex items-center space-x-2 px-4 py-2 rounded-full text-sm font-bold ${
                scanStatus.type === 'success' ? 'bg-green-50 text-green-700 border border-green-100' : 'bg-red-50 text-red-700 border border-red-100'
              }`}>
                <span>{scanStatus.type === 'success' ? '✔' : '✘'}</span>
                <span>{scanStatus.message}</span>
              </div>
            )}
          </div>

          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl border border-gray-100 overflow-hidden transform animate-slideUp">
              <div className="bg-slate-950 text-white p-8 flex justify-between items-center border-b border-slate-800">
                <div>
                  <h4 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-2">IDENTIFIED BUNDLE</h4>
                  <p className="text-3xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-4 rounded-2xl text-center shadow-xl shadow-blue-500/20">
                  <p className="text-[10px] text-blue-100 font-black uppercase tracking-widest mb-1">BATCH PIECES</p>
                  <p className="text-3xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>

              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-12">
                <div className="space-y-8">
                  <div className="grid grid-cols-2 gap-8">
                    <DetailItem label="Buyer" value={scanningDetail.buyer} />
                    <DetailItem label="Style" value={scanningDetail.style} />
                    <DetailItem label="PO#" value={scanningDetail.po} />
                    <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  </div>
                  <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start space-x-3">
                    <span className="text-xl">⚠️</span>
                    <p className="text-xs text-amber-800 leading-relaxed font-medium">
                      Verify bundle integrity before posting. This action updates the master ledger for <span className="font-black underline">{scanningDetail.style}</span>.
                    </p>
                  </div>
                </div>

                <div className="bg-slate-50 p-8 rounded-2xl border border-slate-200 space-y-8">
                  <div>
                    <label className="block text-xs font-black text-slate-400 mb-3 uppercase tracking-widest">1. SELECT PROCESS</label>
                    <select 
                      value={selectedProcess}
                      onChange={(e) => {
                        setSelectedProcess(e.target.value);
                        setSelectedLine('Line-1');
                      }}
                      className="w-full bg-white border-2 border-slate-200 rounded-xl px-5 py-4 focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none font-black text-slate-700 transition-all appearance-none cursor-pointer"
                    >
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>

                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="block text-xs font-black text-slate-400 mb-3 uppercase tracking-widest">2. PRODUCTION LINE</label>
                      <select 
                        value={selectedLine}
                        onChange={(e) => setSelectedLine(e.target.value)}
                        className="w-full bg-white border-2 border-slate-200 rounded-xl px-5 py-4 focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none font-black text-slate-700 transition-all appearance-none cursor-pointer"
                      >
                        {Array.from(
                          { length: selectedProcess.includes('Sewing') ? 15 : 10 }, 
                          (_, i) => `Line-${i + 1}`
                        ).map(l => (
                          <option key={l} value={l}>{l}</option>
                        ))}
                      </select>
                    </div>
                  )}

                  <button 
                    onClick={handleScanSubmit}
                    className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black text-xl hover:bg-blue-700 transition shadow-2xl shadow-blue-500/30 flex items-center justify-center space-x-3 active:scale-[0.98]"
                  >
                    <span>POST TRANSACTION</span>
                    <span className="text-2xl">⚡</span>
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden animate-fadeIn">
          <div className="p-8 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
            <h3 className="text-2xl font-black text-gray-800">Transaction Audit Log</h3>
            <button className="text-blue-600 font-black text-xs uppercase tracking-widest hover:underline">Export CSV</button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.1em]">
                <tr>
                  <th className="px-8 py-5">Timestamp</th>
                  <th className="px-8 py-5">QR Identifier</th>
                  <th className="px-8 py-5">Process Step</th>
                  <th className="px-8 py-5 text-right">Qty (pieces)</th>
                  <th className="px-8 py-5">Line Assigned</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {scans.slice(0, 50).map((scan) => (
                  <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                    <td className="px-8 py-5 text-sm font-medium text-slate-500">{new Date(scan.scan_time).toLocaleString()}</td>
                    <td className="px-8 py-5 font-black text-slate-900 tracking-tight">{scan.qr_id}</td>
                    <td className="px-8 py-5">
                      <span className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider shadow-sm border ${
                        scan.process.includes('Input') ? 'bg-blue-50 text-blue-600 border-blue-100' :
                        scan.process.includes('Output') ? 'bg-green-50 text-green-600 border-green-100' :
                        'bg-slate-50 text-slate-600 border-slate-200'
                      }`}>
                        {scan.process}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-slate-900">{scan.qty}</td>
                    <td className="px-8 py-5">
                      <span className="text-xs font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded">{scan.line}</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [scans, setScans] = useState<ScanningData[]>([]);

  // Orders Master Filter
  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');

  // Scanning Form State
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // History Tab Filter & Sort State
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });
  const [historySort, setHistorySort] = useState<{ key: keyof ScanningData; order: 'asc' | 'desc' }>({
    key: 'scan_time',
    order: 'desc'
  });

  // Seed initial scans for realistic dashboard view
  useEffect(() => {
    const initialScans: ScanningData[] = [];
    const nowStr = new Date().toISOString();

    MOCK_ORDERS.forEach(order => {
      // Seed Cutting
      initialScans.push({
        id: crypto.randomUUID(),
        qr_id: `PG-CUT-${order.style}`,
        process: 'Cutting Done',
        qty: 3500,
        status: ProductionStatus.COMPLETED,
        line: 'N/A',
        scanned_by: crypto.randomUUID(),
        scan_time: nowStr
      });

      // Seed Sewing Lines 1-15
      for (let i = 1; i <= 15; i++) {
        const line = `Line-${i}`;
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-SEW-IN-${order.style}-${i}`,
          process: 'Sewing Input',
          qty: 300,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-SEW-OUT-${order.style}-${i}`,
          process: 'Sewing Output',
          qty: 280,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
      }

      // Seed Washing
      initialScans.push({
        id: crypto.randomUUID(),
        qr_id: `PG-WASH-IN-${order.style}`,
        process: 'Wash Input',
        qty: 2000,
        status: ProductionStatus.COMPLETED,
        line: 'N/A',
        scanned_by: crypto.randomUUID(),
        scan_time: nowStr
      });
      initialScans.push({
        id: crypto.randomUUID(),
        qr_id: `PG-WASH-OUT-${order.style}`,
        process: 'Wash Output',
        qty: 1950,
        status: ProductionStatus.COMPLETED,
        line: 'N/A',
        scanned_by: crypto.randomUUID(),
        scan_time: nowStr
      });

      // Seed Finishing Lines 1-10
      for (let i = 1; i <= 10; i++) {
        const line = `Line-${i}`;
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-FIN-IN-${order.style}-${i}`,
          process: 'Finishing Input',
          qty: 180,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-FIN-OUT-${order.style}-${i}`,
          process: 'Finishing Output',
          qty: 170,
          status: ProductionStatus.COMPLETED,
          line: line,
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });
      }
    });

    setScans(initialScans);
  }, []);

  // Aggregated Stats for Dashboard Cards
  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Code Loaded Successfully from Master.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanStatus({ message: 'Dynamic scan code detected. Auto-assigning to default order.', type: 'success' });
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid QR Code. Format must be PG-YYYYMMDDXXXXXX', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;

    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: crypto.randomUUID(),
      scan_time: new Date().toISOString()
    };

    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Recorded ${scanningDetail.bundle_qty} pieces for ${selectedProcess}`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string, line?: string) => {
    return scans.filter(s => {
      const belongs = qrCodes.find(q => q.qr_id === s.qr_id && q.order_id === orderId) || 
                      s.qr_id.includes(orders.find(o => o.id === orderId)?.style || '---');
      const lineMatch = line ? s.line === line : true;
      return belongs && s.process === process && lineMatch;
    }).reduce((a, b) => a + b.qty, 0);
  };

  const getTableData = useCallback(() => {
    const baseCols = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'country', label: 'Country' },
      { key: 'color', label: 'Color' },
      { key: 'size', label: 'Size' },
      { key: 'po_qty', label: 'PO Qty' },
    ];

    let headers = [...baseCols];
    let rows: any[] = [];

    if (orderProcessFilter === 'all') {
      headers.push(
        { key: 'c_qty', label: 'Cutting' },
        { key: 's_in_qty', label: 'Sewing In' },
        { key: 's_out_qty', label: 'Sewing Out' },
        { key: 'w_in_qty', label: 'Wash In' },
        { key: 'w_out_qty', label: 'Wash Out' },
        { key: 'f_in_qty', label: 'Finishing In' },
        { key: 'f_out_qty', label: 'Finishing Out' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
        s_in_qty: getOrderProcessQty(o.id, 'Sewing Input'),
        s_out_qty: getOrderProcessQty(o.id, 'Sewing Output'),
        w_in_qty: getOrderProcessQty(o.id, 'Wash Input'),
        w_out_qty: getOrderProcessQty(o.id, 'Wash Output'),
        f_in_qty: getOrderProcessQty(o.id, 'Finishing Input'),
        f_out_qty: getOrderProcessQty(o.id, 'Finishing Output')
      }));
    } else if (orderProcessFilter === 'cutting') {
      headers.push({ key: 'cutting_done', label: 'Cutting Done Qty' });
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        cutting_done: getOrderProcessQty(o.id, 'Cutting Done')
      }));
    } else if (orderProcessFilter === 'sewing') {
      headers.push(
        { key: 'sewing_input', label: 'Sewing Input' },
        { key: 'line', label: 'Line' },
        { key: 'wip', label: 'WIP' },
        { key: 'sewing_output', label: 'Sewing Output' }
      );
      orders.forEach(o => {
        for (let i = 1; i <= 15; i++) {
          const l = `Line-${i}`;
          const inp = getOrderProcessQty(o.id, 'Sewing Input', l);
          const outp = getOrderProcessQty(o.id, 'Sewing Output', l);
          if (inp > 0 || outp > 0) {
            rows.push({
              ...o,
              timestamp: new Date().toISOString(),
              sewing_input: inp,
              line: l,
              wip: inp - outp,
              sewing_output: outp
            });
          }
        }
      });
    } else if (orderProcessFilter === 'washing') {
      headers.push(
        { key: 'wash_input', label: 'Wash Input' },
        { key: 'wash_output', label: 'Wash Output' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: new Date().toISOString(),
        wash_input: getOrderProcessQty(o.id, 'Wash Input'),
        wash_output: getOrderProcessQty(o.id, 'Wash Output')
      }));
    } else if (orderProcessFilter === 'finishing') {
      headers.push(
        { key: 'finishing_input', label: 'Finishing Input' },
        { key: 'line', label: 'Line' },
        { key: 'wip', label: 'WIP' },
        { key: 'finishing_output', label: 'Finishing Output' }
      );
      orders.forEach(o => {
        for (let i = 1; i <= 10; i++) {
          const l = `Line-${i}`;
          const inp = getOrderProcessQty(o.id, 'Finishing Input', l);
          const outp = getOrderProcessQty(o.id, 'Finishing Output', l);
          if (inp > 0 || outp > 0) {
            rows.push({
              ...o,
              timestamp: new Date().toISOString(),
              finishing_input: inp,
              line: l,
              wip: inp - outp,
              finishing_output: outp
            });
          }
        }
      });
    }
    return { headers, rows };
  }, [orderProcessFilter, orders, scans, qrCodes]);

  const handleDownloadExcel = useCallback(() => {
    const { headers, rows } = getTableData();
    const csvRows = [];
    csvRows.push(headers.map(h => `"${h.label}"`).join(','));
    rows.forEach(row => {
      const values = headers.map(h => {
        let val = row[h.key];
        if (h.key === 'timestamp') val = new Date(val).toLocaleString();
        const escaped = ('' + (val ?? '')).replace(/"/g, '""');
        return `"${escaped}"`;
      });
      csvRows.push(values.join(','));
    });
    const csvString = csvRows.join('\n');
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `PG_Orders_Master_${orderProcessFilter}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, [getTableData, orderProcessFilter]);

  // Filtered and Sorted History Data
  const filteredHistory = useMemo(() => {
    let result = [...scans];

    // Filter by QR ID
    if (historyFilters.qrId) {
      result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    }

    // Filter by Process
    if (historyFilters.process !== 'all') {
      result = result.filter(s => s.process === historyFilters.process);
    }

    // Filter by Line
    if (historyFilters.line !== 'all') {
      result = result.filter(s => s.line === historyFilters.line);
    }

    // Filter by Date Range
    if (historyFilters.startDate) {
      const start = new Date(historyFilters.startDate);
      result = result.filter(s => new Date(s.scan_time) >= start);
    }
    if (historyFilters.endDate) {
      const end = new Date(historyFilters.endDate);
      end.setHours(23, 59, 59, 999);
      result = result.filter(s => new Date(s.scan_time) <= end);
    }

    // Sorting
    result.sort((a, b) => {
      const valA = a[historySort.key];
      const valB = b[historySort.key];

      if (valA < valB) return historySort.order === 'asc' ? -1 : 1;
      if (valA > valB) return historySort.order === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [scans, historyFilters, historySort]);

  const handleSort = (key: keyof ScanningData) => {
    setHistorySort(prev => ({
      key,
      order: prev.key === key && prev.order === 'asc' ? 'desc' : 'asc'
    }));
  };

  const SortIcon = ({ column }: { column: keyof ScanningData }) => {
    if (historySort.key !== column) return <span className="opacity-20 ml-1">⇅</span>;
    return <span className="ml-1">{historySort.order === 'asc' ? '↑' : '↓'}</span>;
  };

  const renderOrdersTable = () => {
    const { headers, rows } = getTableData();
    return (
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left whitespace-nowrap">
            <thead className="bg-gray-50 text-gray-500 uppercase text-[10px] font-bold tracking-wider">
              <tr>{headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {rows.map((row, idx) => (
                <tr key={idx} className="hover:bg-gray-50 transition-colors">
                  {headers.map(h => (
                    <td key={h.key} className="px-6 py-3 text-sm font-medium text-gray-700">
                      {h.key === 'timestamp' ? new Date(row[h.key]).toLocaleString() : row[h.key]}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Cutting Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between hover:shadow-lg transition-all group border-l-4 border-l-blue-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-blue-50 p-3 rounded-xl text-blue-600">✂️</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Cutting Section</h4>
                </div>
                <span className="text-[10px] font-black text-blue-500 bg-blue-50 px-2 py-1 rounded">DEPT-01</span>
              </div>
              <div className="space-y-6">
                <div>
                  <p className="text-xs font-bold text-gray-400 uppercase mb-1">Total Finished Pieces</p>
                  <h5 className="text-4xl font-black text-blue-600">{dashboardStats.cuttingDone} <span className="text-lg font-medium text-gray-400">pcs</span></h5>
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-black text-gray-400 uppercase">
                    <span>Daily Progress</span>
                    <span>92%</span>
                  </div>
                  <div className="w-full bg-gray-100 h-3 rounded-full overflow-hidden">
                    <div className="bg-blue-500 h-full w-[92%] transition-all duration-1000"></div>
                  </div>
                </div>
              </div>
            </div>

            {/* Sewing Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg transition-all group border-l-4 border-l-indigo-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-indigo-50 p-3 rounded-xl text-indigo-600">📥</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Sewing Production</h4>
                </div>
                <span className="text-[10px] font-black text-indigo-500 bg-indigo-50 px-2 py-1 rounded">15 LINES</span>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Total Input</p>
                  <h5 className="text-2xl font-black text-indigo-600">{dashboardStats.sewingInput}</h5>
                </div>
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Total Output</p>
                  <h5 className="text-2xl font-black text-green-600">{dashboardStats.sewingOutput}</h5>
                </div>
              </div>
              <div className="mt-6 flex justify-between items-center bg-indigo-50/50 p-3 rounded-lg border border-indigo-100">
                <p className="text-[10px] font-black text-indigo-800 uppercase tracking-widest">Sewing WIP GAP</p>
                <p className="text-lg font-black text-indigo-600">{dashboardStats.sewingInput - dashboardStats.sewingOutput} pieces</p>
              </div>
            </div>

            {/* Wash Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg transition-all group border-l-4 border-l-cyan-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-3">
                  <div className="bg-cyan-50 p-3 rounded-xl text-cyan-600">🧼</div>
                  <h4 className="text-xl font-black text-gray-800 uppercase tracking-tight">Washing Department</h4>
                </div>
