                >
                  <option value="all">All Processes</option>
                  {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Line</label>
                <select 
                  value={historyFilters.line}
                  onChange={(e) => setHistoryFilters(prev => ({ ...prev, line: e.target.value }))}
                  className="w-full bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none font-medium appearance-none cursor-pointer"
                >
                  <option value="all">All Lines</option>
                  <option value="N/A">N/A</option>
