                 Reset All
               </button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">QR Identifier</label>
                <input 
                  type="text" 
                  value={historyFilters.qrId}
                  onChange={(e) => setHistoryFilters(prev => ({ ...prev, qrId: e.target.value }))}
                  placeholder="Search QR..."
                  className="w-full bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none font-medium"
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Process Step</label>
                <select 
                  value={historyFilters.process}
                  onChange={(e) => setHistoryFilters(prev => ({ ...prev, process: e.target.value }))}
                  className="w-full bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none font-medium appearance-none cursor-pointer"
                >
                  <option value="all">All Processes</option>
                  {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Line</label>
                <select 
                  value={historyFilters.line}
                  onChange={(e) => setHistoryFilters(prev => ({ ...prev, line: e.target.value }))}
                  className="w-full bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none font-medium appearance-none cursor-pointer"
                >
                  <option value="all">All Lines</option>
                  <option value="N/A">N/A</option>
                  {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Start Date</label>
                <input 
                  type="date" 
                  value={historyFilters.startDate}
                  onChange={(e) => setHistoryFilters(prev => ({ ...prev, startDate: e.target.value }))}
                  className="w-full bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none font-medium cursor-pointer"
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">End Date</label>
                <input 
                  type="date" 
                  value={historyFilters.endDate}
                  onChange={(e) => setHistoryFilters(prev => ({ ...prev, endDate: e.target.value }))}
                  className="w-full bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none font-medium cursor-pointer"
                />
              </div>
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-8 border-b border-gray-100 bg-gray-50/50 flex flex-col sm:flex-row justify-between items-center gap-4">
              <div>
                <h3 className="text-2xl font-black text-gray-800">Transaction Audit Log</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Showing {filteredHistory.length} recorded operations</p>
              </div>
              <button 
                onClick={handleDownloadHistoryExcel}
                className="flex items-center space-x-2 bg-green-600 hover:bg-green-700 text-white px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-green-900/10 active:scale-95 transition-all"
              >
                <span>📥</span>
                <span>DOWNLOAD EXCEL</span>
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.1em]">
                  <tr>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600 transition-colors group" onClick={() => handleSort('scan_time')}>
                      Timestamp <SortIcon column="scan_time" />
                    </th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600 transition-colors group" onClick={() => handleSort('qr_id')}>
                      QR Identifier <SortIcon column="qr_id" />
                    </th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600 transition-colors group" onClick={() => handleSort('process')}>
                      Process Step <SortIcon column="process" />
                    </th>
                    <th className="px-8 py-5 text-right cursor-pointer hover:text-blue-600 transition-colors group" onClick={() => handleSort('qty')}>
                      Qty (pieces) <SortIcon column="qty" />
                    </th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600 transition-colors group" onClick={() => handleSort('line')}>
                      Line Assigned <SortIcon column="line" />
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredHistory.length > 0 ? (
                    filteredHistory.map((scan) => (
                      <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                        <td className="px-8 py-5 text-sm font-medium text-slate-500">{new Date(scan.scan_time).toLocaleString()}</td>
                        <td className="px-8 py-5 font-black text-slate-900 tracking-tight">{scan.qr_id}</td>
                        <td className="px-8 py-5">
                          <span className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider shadow-sm border ${
                            scan.process.includes('Input') ? 'bg-blue-50 text-blue-600 border-blue-100' :
                            scan.process.includes('Output') ? 'bg-green-50 text-green-600 border-green-100' :
                            'bg-slate-50 text-slate-600 border-slate-200'
                          }`}>
                            {scan.process}
                          </span>
                        </td>
                        <td className="px-8 py-5 text-right font-black text-slate-900">{scan.qty}</td>
                        <td className="px-8 py-5">
                          <span className="text-xs font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded">{scan.line}</span>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={5} className="px-8 py-20 text-center">
                        <div className="flex flex-col items-center">
                          <span className="text-4xl mb-4">🔍</span>
                          <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">No transactions match your current filters</p>
                        </div>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Initialize scans from localStorage if available, otherwise empty
  const [scans, setScans] = useState<ScanningData[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Orders Master Filter
  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');

  // Scanning Form State
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // History Tab Filter & Sort State
  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });
  const [historySort, setHistorySort] = useState<{ key: keyof ScanningData; order: 'asc' | 'desc' }>({
    key: 'scan_time',
    order: 'desc'
  });

  // Persist scans to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed initial scans only if storage is empty (First run experience)
  useEffect(() => {
    if (scans.length === 0) {
      const initialScans: ScanningData[] = [];
      const nowStr = new Date().toISOString();

      MOCK_ORDERS.forEach(order => {
        // Seed Cutting
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: 3500,
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: crypto.randomUUID(),
          scan_time: nowStr
        });

        // Seed Sewing
        for (let i = 1; i <= 5; i++) {
          const line = `Line-${i}`;
          initialScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-IN-${order.style}-${i}`,
            process: 'Sewing Input',
            qty: 300,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: crypto.randomUUID(),
            scan_time: nowStr
          });
        }
      });
      setScans(initialScans);
    }
  }, []);

  // Aggregated Stats for Dashboard Cards
  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Code Loaded Successfully.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid QR Code.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;

    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: crypto.randomUUID(),
      scan_time: new Date().toISOString()
    };

    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: ${scanningDetail.bundle_qty} pcs posted to ${selectedProcess}`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string, line?: string) => {
    return scans.filter(s => {
      const belongs = qrCodes.find(q => q.qr_id === s.qr_id && q.order_id === orderId) || 
                      s.qr_id.includes(orders.find(o => o.id === orderId)?.style || '---');
      const lineMatch = line ? s.line === line : true;
      return belongs && s.process === process && lineMatch;
    }).reduce((a, b) => a + b.qty, 0);
  };

  const getTableData = useCallback(() => {
    const baseCols = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'country', label: 'Country' },
      { key: 'color', label: 'Color' },
      { key: 'size', label: 'Size' },
      { key: 'po_qty', label: 'PO Qty' },
    ];

    let headers = [...baseCols];
    let rows: any[] = [];

    if (orderProcessFilter === 'all') {
      headers.push(
        { key: 'c_qty', label: 'Cutting' },
        { key: 's_in_qty', label: 'Sewing In' },
        { key: 's_out_qty', label: 'Sewing Out' },
        { key: 'w_in_qty', label: 'Wash In' },
        { key: 'w_out_qty', label: 'Wash Out' },
        { key: 'f_in_qty', label: 'Finishing In' },
        { key: 'f_out_qty', label: 'Finishing Out' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
        s_in_qty: getOrderProcessQty(o.id, 'Sewing Input'),
        s_out_qty: getOrderProcessQty(o.id, 'Sewing Output'),
        w_in_qty: getOrderProcessQty(o.id, 'Wash Input'),
        w_out_qty: getOrderProcessQty(o.id, 'Wash Output'),
        f_in_qty: getOrderProcessQty(o.id, 'Finishing Input'),
        f_out_qty: getOrderProcessQty(o.id, 'Finishing Output')
      }));
    } else if (orderProcessFilter === 'cutting') {
      headers.push({ key: 'cutting_done', label: 'Cutting Done Qty' });
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        cutting_done: getOrderProcessQty(o.id, 'Cutting Done')
      }));
    } else if (orderProcessFilter === 'sewing') {
      headers.push(
        { key: 'sewing_input', label: 'Sewing Input' },
        { key: 'line', label: 'Line' },
        { key: 'wip', label: 'WIP' },
        { key: 'sewing_output', label: 'Sewing Output' }
      );
      orders.forEach(o => {
        for (let i = 1; i <= 15; i++) {
          const l = `Line-${i}`;
          const inp = getOrderProcessQty(o.id, 'Sewing Input', l);
          const outp = getOrderProcessQty(o.id, 'Sewing Output', l);
          if (inp > 0 || outp > 0) {
            rows.push({
              ...o,
              timestamp: new Date().toISOString(),
              sewing_input: inp,
              line: l,
              wip: inp - outp,
              sewing_output: outp
            });
          }
        }
      });
    } else if (orderProcessFilter === 'washing') {
      headers.push(
        { key: 'wash_input', label: 'Wash Input' },
        { key: 'wash_output', label: 'Wash Output' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: new Date().toISOString(),
        wash_input: getOrderProcessQty(o.id, 'Wash Input'),
        wash_output: getOrderProcessQty(o.id, 'Wash Output')
      }));
    } else if (orderProcessFilter === 'finishing') {
      headers.push(
        { key: 'finishing_input', label: 'Finishing Input' },
        { key: 'line', label: 'Line' },
        { key: 'wip', label: 'WIP' },
        { key: 'finishing_output', label: 'Finishing Output' }
      );
      orders.forEach(o => {
        for (let i = 1; i <= 10; i++) {
          const l = `Line-${i}`;
          const inp = getOrderProcessQty(o.id, 'Finishing Input', l);
          const outp = getOrderProcessQty(o.id, 'Finishing Output', l);
          if (inp > 0 || outp > 0) {
            rows.push({
              ...o,
              timestamp: new Date().toISOString(),
              finishing_input: inp,
              line: l,
              wip: inp - outp,
              finishing_output: outp
            });
          }
        }
      });
    }
    return { headers, rows };
  }, [orderProcessFilter, orders, scans, qrCodes]);

  const handleDownloadExcel = useCallback(() => {
    const { headers, rows } = getTableData();
    const csvRows = [];
    csvRows.push(headers.map(h => `"${h.label}"`).join(','));
    rows.forEach(row => {
      const values = headers.map(h => {
        let val = row[h.key];
        if (h.key === 'timestamp') val = new Date(val).toLocaleString();
        const escaped = ('' + (val ?? '')).replace(/"/g, '""');
        return `"${escaped}"`;
      });
      csvRows.push(values.join(','));
    });
    const csvString = csvRows.join('\n');
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `PG_Orders_Master_${orderProcessFilter}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, [getTableData, orderProcessFilter]);

  // Filtered and Sorted History Data
  const filteredHistory = useMemo(() => {
    let result = [...scans];

    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }

    if (historyFilters.qrId) {
      result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    }

    if (historyFilters.process !== 'all') {
      result = result.filter(s => s.process === historyFilters.process);
    }

    if (historyFilters.line !== 'all') {
      result = result.filter(s => s.line === historyFilters.line);
    }

    if (historyFilters.startDate) {
      const start = new Date(historyFilters.startDate);
      result = result.filter(s => new Date(s.scan_time) >= start);
    }
    if (historyFilters.endDate) {
      const end = new Date(historyFilters.endDate);
      end.setHours(23, 59, 59, 999);
      result = result.filter(s => new Date(s.scan_time) <= end);
    }

    result.sort((a, b) => {
      const valA = a[historySort.key];
      const valB = b[historySort.key];
      if (valA < valB) return historySort.order === 'asc' ? -1 : 1;
      if (valA > valB) return historySort.order === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [scans, historyFilters, historySort, historyCategory]);

  const handleDownloadHistoryExcel = useCallback(() => {
    const csvRows = [];
    const headers = ["Timestamp", "QR Identifier", "Process Step", "Qty", "Line"];
    csvRows.push(headers.map(h => `"${h}"`).join(','));

    filteredHistory.forEach(scan => {
      const row = [
        new Date(scan.scan_time).toLocaleString(),
        scan.qr_id,
        scan.process,
        scan.qty.toString(),
        scan.line
      ];
      csvRows.push(row.map(v => `"${v.replace(/"/g, '""')}"`).join(','));
    });

    const csvString = csvRows.join('\n');
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `PG_History_Audit_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, [filteredHistory]);

  const handleSort = (key: keyof ScanningData) => {
    setHistorySort(prev => ({
      key,
      order: prev.key === key && prev.order === 'asc' ? 'desc' : 'asc'
    }));
  };

  const SortIcon = ({ column }: { column: keyof ScanningData }) => {
    if (historySort.key !== column) return <span className="opacity-20 ml-1">⇅</span>;
    return <span className="ml-1">{historySort.order === 'asc' ? '↑' : '↓'}</span>;
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Summary Cards */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 border-l-4 border-l-blue-500">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                  <div className="bg-blue-50 p-2 rounded-lg text-blue-600">✂️</div>
                  <h4 className="font-black text-gray-800 uppercase tracking-tight">Cutting Status</h4>
                </div>
              </div>
              <h5 className="text-4xl font-black text-blue-600">{dashboardStats.cuttingDone} <span className="text-sm font-medium text-gray-400">pcs</span></h5>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 border-l-4 border-l-indigo-500">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                  <div className="bg-indigo-50 p-2 rounded-lg text-indigo-600">📥</div>
                  <h4 className="font-black text-gray-800 uppercase tracking-tight">Sewing Total</h4>
                </div>
              </div>
              <div className="flex space-x-8">
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Input</p>
                  <p className="text-2xl font-black text-indigo-600">{dashboardStats.sewingInput}</p>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Output</p>
                  <p className="text-2xl font-black text-green-600">{dashboardStats.sewingOutput}</p>
                </div>
              </div>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex flex-col xl:flex-row justify-between items-center gap-6">
            <h3 className="text-2xl font-black text-gray-800 tracking-tight">ORDERS MASTER LEDGER</h3>
            <div className="flex flex-wrap items-center gap-4">
               <div className="flex bg-white p-1 rounded-xl border border-gray-100">
                {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                  <button
                    key={f}
                    onClick={() => setOrderProcessFilter(f)}
                    className={`px-4 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${
                      orderProcessFilter === f ? 'bg-blue-600 text-white' : 'text-gray-500 hover:bg-gray-50'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
              <button onClick={handleDownloadExcel} className="bg-green-600 text-white px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10">
                DOWNLOAD EXCEL
              </button>
            </div>
          </div>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left whitespace-nowrap">
                <thead className="bg-gray-50 text-gray-500 uppercase text-[10px] font-bold tracking-wider">
                  <tr>{getTableData().headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {getTableData().rows.map((row, idx) => (
                    <tr key={idx} className="hover:bg-gray-50 transition-colors text-sm font-medium text-gray-700">
                      {getTableData().headers.map(h => (
                        <td key={h.key} className="px-6 py-3">
                          {h.key === 'timestamp' ? new Date(row[h.key]).toLocaleString() : row[h.key]}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-gray-100 text-center relative overflow-hidden">
            <h3 className="text-3xl font-black text-gray-900 mb-2">Production Gateway</h3>
            <p className="text-gray-500 mb-10">Scan PG- coded bundles for real-time tracking.</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="PG-..." className="flex-1 border-2 border-gray-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-bold ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-gray-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-xl text-center">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PCS</p>
                  <p className="text-2xl font-black">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-6">
                  <div className="grid grid-cols-2 gap-4">
                    <DetailItem label="Buyer" value={scanningDetail.buyer} />
                    <DetailItem label="Style" value={scanningDetail.style} />
                    <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                    <DetailItem label="PO" value={scanningDetail.po} />
                  </div>
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Select Process</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">
                    POST TRANSACTION ⚡
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
               <div className="flex flex-col md:flex-row md:items-center gap-4">
                  <h3 className="text-xl font-black text-gray-800">History Filters</h3>
                  <div className="flex bg-gray-50 p-1 rounded-xl border border-gray-100">
                    {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                      <button
                        key={f}
                        onClick={() => setHistoryCategory(f)}
                        className={`px-4 py-1.5 text-[10px] font-black uppercase rounded-lg transition-all tracking-wider ${
                          historyCategory === f ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-800'
                        }`}
                      >
                        {f}
                      </button>
                    ))}
                  </div>
               </div>
               <button 
                onClick={() => { setHistoryFilters({ qrId: '', process: 'all', line: 'all', startDate: '', endDate: '' }); setHistoryCategory('all'); }}
                className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600"
               >
                 Reset
               </button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <input type="text" value={historyFilters.qrId} onChange={(e) => setHistoryFilters(prev => ({ ...prev, qrId: e.target.value }))} placeholder="QR ID" className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase tracking-wider outline-none focus:border-blue-500" />
              <select value={historyFilters.process} onChange={(e) => setHistoryFilters(prev => ({ ...prev, process: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase tracking-wider outline-none focus:border-blue-500">
                <option value="all">PROCESS</option>
                {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <select value={historyFilters.line} onChange={(e) => setHistoryFilters(prev => ({ ...prev, line: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase tracking-wider outline-none focus:border-blue-500">
                <option value="all">LINE</option>
                <option value="N/A">N/A</option>
                {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
              <input type="date" value={historyFilters.startDate} onChange={(e) => setHistoryFilters(prev => ({ ...prev, startDate: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase tracking-wider outline-none focus:border-blue-500" />
              <input type="date" value={historyFilters.endDate} onChange={(e) => setHistoryFilters(prev => ({ ...prev, endDate: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase tracking-wider outline-none focus:border-blue-500" />
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-8 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-gray-800">Transaction Audit Log</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{filteredHistory.length} Transactions</p>
              </div>
              <button 
                onClick={handleDownloadHistoryExcel}
                className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10"
              >
                DOWNLOAD EXCEL
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.1em]">
                  <tr>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('scan_time')}>Timestamp <SortIcon column="scan_time" /></th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('qr_id')}>QR Identifier <SortIcon column="qr_id" /></th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('process')}>Process <SortIcon column="process" /></th>
                    <th className="px-8 py-5 text-right cursor-pointer hover:text-blue-600" onClick={() => handleSort('qty')}>Qty <SortIcon column="qty" /></th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('line')}>Line <SortIcon column="line" /></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredHistory.map((scan) => (
                    <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors text-sm">
                      <td className="px-8 py-4 font-medium text-slate-500">{new Date(scan.scan_time).toLocaleString()}</td>
                      <td className="px-8 py-4 font-black text-slate-900 tracking-tight">{scan.qr_id}</td>
                      <td className="px-8 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ${
                          scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'
                        }`}>
                          {scan.process}
                        </span>
                      </td>
                      <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty}</td>
                      <td className="px-8 py-4 text-xs font-bold text-slate-600">{scan.line}</td>
                    </tr>
                  ))}
                  {filteredHistory.length === 0 && (
                    <tr><td colSpan={5} className="py-20 text-center text-slate-400 font-black uppercase text-[10px]">No records found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Initialize scans from localStorage if available, otherwise empty
  const [scans, setScans] = useState<ScanningData[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Orders Master Filter
  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');

  // Scanning Form State
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // History Tab Filter & Sort State
  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });
  const [historySort, setHistorySort] = useState<{ key: keyof ScanningData; order: 'asc' | 'desc' }>({
    key: 'scan_time',
    order: 'desc'
  });

  // Persist scans to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed initial scans only if storage is empty (First run experience)
  useEffect(() => {
    if (scans.length === 0) {
      const initialScans: ScanningData[] = [];
      const nowStr = new Date().toISOString();

      MOCK_ORDERS.forEach(order => {
        initialScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: 3500,
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'system',
          scan_time: nowStr
        });

        for (let i = 1; i <= 3; i++) {
          const line = `Line-${i}`;
          initialScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-IN-${order.style}-${i}`,
            process: 'Sewing Input',
            qty: 200,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'system',
            scan_time: nowStr
          });
        }
      });
      setScans(initialScans);
    }
  }, []);

  // Aggregated Stats for Dashboard Cards
  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Code Loaded Successfully.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid QR Code.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;

    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };

    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: ${scanningDetail.bundle_qty} pcs posted to ${selectedProcess}`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string, line?: string) => {
    return scans.filter(s => {
      const belongs = qrCodes.find(q => q.qr_id === s.qr_id && q.order_id === orderId) || 
                      s.qr_id.includes(orders.find(o => o.id === orderId)?.style || '---');
      const lineMatch = line ? s.line === line : true;
      return belongs && s.process === process && lineMatch;
    }).reduce((a, b) => a + b.qty, 0);
  };

  const getTableData = useCallback(() => {
    const baseCols = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'country', label: 'Country' },
      { key: 'color', label: 'Color' },
      { key: 'size', label: 'Size' },
      { key: 'po_qty', label: 'PO Qty' },
    ];

    let headers = [...baseCols];
    let rows: any[] = [];

    if (orderProcessFilter === 'all') {
      headers.push(
        { key: 'c_qty', label: 'Cutting' },
        { key: 's_in_qty', label: 'Sewing In' },
        { key: 's_out_qty', label: 'Sewing Out' },
        { key: 'w_in_qty', label: 'Wash In' },
        { key: 'w_out_qty', label: 'Wash Out' },
        { key: 'f_in_qty', label: 'Finishing In' },
        { key: 'f_out_qty', label: 'Finishing Out' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
        s_in_qty: getOrderProcessQty(o.id, 'Sewing Input'),
        s_out_qty: getOrderProcessQty(o.id, 'Sewing Output'),
        w_in_qty: getOrderProcessQty(o.id, 'Wash Input'),
        w_out_qty: getOrderProcessQty(o.id, 'Wash Output'),
        f_in_qty: getOrderProcessQty(o.id, 'Finishing Input'),
        f_out_qty: getOrderProcessQty(o.id, 'Finishing Output')
      }));
    } else {
      // Logic for filtered views
      headers.push({ key: 'current_qty', label: 'Quantity' });
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        current_qty: getOrderProcessQty(o.id, orderProcessFilter === 'cutting' ? 'Cutting Done' : orderProcessFilter === 'sewing' ? 'Sewing Output' : 'Finishing Output')
      }));
    }
    return { headers, rows };
  }, [orderProcessFilter, orders, scans, qrCodes]);

  const handleDownloadExcel = useCallback(() => {
    const { headers, rows } = getTableData();
    const csvRows = [headers.map(h => `"${h.label}"`).join(',')];
    rows.forEach(row => {
      const values = headers.map(h => {
        let val = row[h.key];
        if (h.key === 'timestamp') val = new Date(val).toLocaleString();
        return `"${('' + (val ?? '')).replace(/"/g, '""')}"`;
      });
      csvRows.push(values.join(','));
    });
    const blob = new Blob([csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `PG_Orders_${orderProcessFilter}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, [getTableData, orderProcessFilter]);

  const filteredHistory = useMemo(() => {
    let result = [...scans];
    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }
    if (historyFilters.qrId) result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    if (historyFilters.process !== 'all') result = result.filter(s => s.process === historyFilters.process);
    if (historyFilters.line !== 'all') result = result.filter(s => s.line === historyFilters.line);
    if (historyFilters.startDate) result = result.filter(s => new Date(s.scan_time) >= new Date(historyFilters.startDate));
    if (historyFilters.endDate) result = result.filter(s => new Date(s.scan_time) <= new Date(historyFilters.endDate));

    result.sort((a, b) => {
      const valA = a[historySort.key];
      const valB = b[historySort.key];
      if (valA < valB) return historySort.order === 'asc' ? -1 : 1;
      if (valA > valB) return historySort.order === 'asc' ? 1 : -1;
      return 0;
    });
    return result;
  }, [scans, historyFilters, historySort, historyCategory]);

  const handleDownloadHistoryExcel = useCallback(() => {
    const headers = ["Timestamp", "QR Identifier", "Process Step", "Qty", "Line"];
    const csvRows = [headers.map(h => `"${h}"`).join(',')];
    filteredHistory.forEach(scan => {
      const row = [new Date(scan.scan_time).toLocaleString(), scan.qr_id, scan.process, scan.qty.toString(), scan.line];
      csvRows.push(row.map(v => `"${v.replace(/"/g, '""')}"`).join(','));
    });
    const blob = new Blob([csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `PG_History_Audit_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, [filteredHistory]);

  const handleSort = (key: keyof ScanningData) => {
    setHistorySort(prev => ({ key, order: prev.key === key && prev.order === 'asc' ? 'desc' : 'asc' }));
  };

  const SortIcon = ({ column }: { column: keyof ScanningData }) => {
    if (historySort.key !== column) return <span className="opacity-20 ml-1">⇅</span>;
    return <span className="ml-1">{historySort.order === 'asc' ? '↑' : '↓'}</span>;
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 border-l-4 border-l-blue-500">
              <h4 className="font-black text-gray-800 uppercase tracking-tight mb-2">Cutting Done</h4>
              <h5 className="text-4xl font-black text-blue-600">{dashboardStats.cuttingDone} <span className="text-sm font-medium text-gray-400">pcs</span></h5>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 border-l-4 border-l-indigo-500">
              <h4 className="font-black text-gray-800 uppercase tracking-tight mb-2">Sewing Output</h4>
              <h5 className="text-4xl font-black text-indigo-600">{dashboardStats.sewingOutput} <span className="text-sm font-medium text-gray-400">pcs</span></h5>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex flex-col xl:flex-row justify-between items-center gap-6">
            <h3 className="text-2xl font-black text-gray-800 tracking-tight">ORDERS MASTER LEDGER</h3>
            <div className="flex flex-wrap items-center gap-4">
               <div className="flex bg-white p-1 rounded-xl border border-gray-100 shadow-sm">
                {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                  <button key={f} onClick={() => setOrderProcessFilter(f)} className={`px-4 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${orderProcessFilter === f ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:bg-gray-50'}`}>{f}</button>
                ))}
              </div>
              <button onClick={handleDownloadExcel} className="bg-green-600 text-white px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10">DOWNLOAD EXCEL</button>
            </div>
          </div>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left whitespace-nowrap">
                <thead className="bg-gray-50 text-gray-500 uppercase text-[10px] font-black tracking-wider border-b border-gray-100">
                  <tr>{getTableData().headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-gray-100 text-sm font-medium text-gray-700">
                  {getTableData().rows.map((row, idx) => (
                    <tr key={idx} className="hover:bg-gray-50 transition-colors">
                      {getTableData().headers.map(h => (
                        <td key={h.key} className="px-6 py-3">{h.key === 'timestamp' ? new Date(row[h.key]).toLocaleDateString() : row[h.key]}</td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-gray-100 text-center relative overflow-hidden">
            <h3 className="text-3xl font-black text-gray-900 mb-2">Production Gateway</h3>
            <p className="text-gray-500 mb-8">Identify bundle ID starting with PG-</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="PG-..." className="flex-1 border-2 border-gray-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-bold ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-gray-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-xl text-center">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PCS</p>
                  <p className="text-2xl font-black">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-6">
                  <div className="grid grid-cols-2 gap-4">
                    <DetailItem label="Buyer" value={scanningDetail.buyer} />
                    <DetailItem label="Style" value={scanningDetail.style} />
                    <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                    <DetailItem label="PO" value={scanningDetail.po} />
                  </div>
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
               <div className="flex flex-col md:flex-row md:items-center gap-4">
                  <h3 className="text-xl font-black text-gray-800">History Filters</h3>
                  <div className="flex bg-gray-50 p-1 rounded-xl border border-gray-100">
                    {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                      <button key={f} onClick={() => setHistoryCategory(f)} className={`px-4 py-1.5 text-[10px] font-black uppercase rounded-lg transition-all tracking-wider ${historyCategory === f ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-800'}`}>{f}</button>
                    ))}
                  </div>
               </div>
               <button onClick={() => { setHistoryFilters({ qrId: '', process: 'all', line: 'all', startDate: '', endDate: '' }); setHistoryCategory('all'); }} className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600">Reset</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <input type="text" value={historyFilters.qrId} onChange={(e) => setHistoryFilters(prev => ({ ...prev, qrId: e.target.value }))} placeholder="QR ID" className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none focus:border-blue-500" />
              <select value={historyFilters.process} onChange={(e) => setHistoryFilters(prev => ({ ...prev, process: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none focus:border-blue-500">
                <option value="all">PROCESS</option>
                {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <select value={historyFilters.line} onChange={(e) => setHistoryFilters(prev => ({ ...prev, line: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none focus:border-blue-500">
                <option value="all">LINE</option>
                {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
              <input type="date" value={historyFilters.startDate} onChange={(e) => setHistoryFilters(prev => ({ ...prev, startDate: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none" />
              <input type="date" value={historyFilters.endDate} onChange={(e) => setHistoryFilters(prev => ({ ...prev, endDate: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none" />
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-8 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-gray-800">Transaction Audit Log</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{filteredHistory.length} Records found</p>
              </div>
              <button onClick={handleDownloadHistoryExcel} className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10">DOWNLOAD EXCEL</button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.1em]">
                  <tr>
                    <th className="px-8 py-5 cursor-pointer" onClick={() => handleSort('scan_time')}>Timestamp <SortIcon column="scan_time" /></th>
                    <th className="px-8 py-5 cursor-pointer" onClick={() => handleSort('qr_id')}>QR Identifier <SortIcon column="qr_id" /></th>
                    <th className="px-8 py-5 cursor-pointer" onClick={() => handleSort('process')}>Process <SortIcon column="process" /></th>
                    <th className="px-8 py-5 text-right cursor-pointer" onClick={() => handleSort('qty')}>Qty <SortIcon column="qty" /></th>
                    <th className="px-8 py-5 cursor-pointer" onClick={() => handleSort('line')}>Line <SortIcon column="line" /></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100 text-sm">
                  {filteredHistory.map((scan) => (
                    <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                      <td className="px-8 py-4 font-medium text-slate-500">{new Date(scan.scan_time).toLocaleString()}</td>
                      <td className="px-8 py-4 font-black text-slate-900 tracking-tight">{scan.qr_id}</td>
                      <td className="px-8 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                      </td>
                      <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty}</td>
                      <td className="px-8 py-4 text-xs font-bold text-slate-600">{scan.line}</td>
                    </tr>
                  ))}
                  {filteredHistory.length === 0 && (
                    <tr><td colSpan={5} className="py-20 text-center text-slate-400 font-black uppercase text-[10px]">No matches found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v2';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Persistent storage for scan data - critical for mobile usage
  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  // Orders Master State
  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');

  // Scanning Form State
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // History Tab State
  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });
  const [historySort, setHistorySort] = useState<{ key: keyof ScanningData; order: 'asc' | 'desc' }>({
    key: 'scan_time',
    order: 'desc'
  });

  // Sync with localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed initial demo data if storage is empty
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];
      MOCK_ORDERS.forEach(order => {
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: order.po_qty * 0.7,
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Code Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Loaded.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Posted ${scanningDetail.bundle_qty} pcs to ${selectedProcess}`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string, line?: string) => {
    return scans.filter(s => {
      const style = orders.find(o => o.id === orderId)?.style || '---';
      const belongs = s.qr_id.includes(style);
      const lineMatch = line ? s.line === line : true;
      return belongs && s.process === process && lineMatch;
    }).reduce((a, b) => a + b.qty, 0);
  };

  const getOrdersMasterData = useCallback(() => {
    const baseHeaders = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'country', label: 'Country' },
      { key: 'color', label: 'Color' },
      { key: 'size', label: 'Size' },
      { key: 'po_qty', label: 'PO Qty' },
    ];
    let headers = [...baseHeaders];
    let rows: any[] = [];

    if (orderProcessFilter === 'all') {
      headers.push(
        { key: 'c_qty', label: 'Cutting' },
        { key: 's_out_qty', label: 'Sewing' },
        { key: 'f_out_qty', label: 'Finishing' }
      );
      rows = orders.map(o => ({
        ...o,
        timestamp: o.created_at,
        c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
        s_out_qty: getOrderProcessQty(o.id, 'Sewing Output'),
        f_out_qty: getOrderProcessQty(o.id, 'Finishing Output')
      }));
    } else {
      headers.push({ key: 'current_qty', label: 'Category Qty' });
      rows = orders.map(o => {
        let processName = 'Cutting Done';
        if (orderProcessFilter === 'sewing') processName = 'Sewing Output';
        if (orderProcessFilter === 'washing') processName = 'Wash Output';
        if (orderProcessFilter === 'finishing') processName = 'Finishing Output';
        return {
          ...o,
          timestamp: o.created_at,
          current_qty: getOrderProcessQty(o.id, processName)
        };
      });
    }
    return { headers, rows };
  }, [orderProcessFilter, orders, scans]);

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];

    if (type === 'orders') {
      const data = getOrdersMasterData();
      headers = data.headers.map(h => h.label);
      csvRows = data.rows.map(row => 
        data.headers.map(h => `"${(row[h.key] || '').toString().replace(/"/g, '""')}"`).join(',')
      );
    } else {
      headers = ["Timestamp", "QR Identifier", "Process Step", "Qty", "Line"];
      csvRows = filteredHistory.map(scan => [
        new Date(scan.scan_time).toLocaleString(),
        scan.qr_id,
        scan.process,
        scan.qty.toString(),
        scan.line
      ].map(v => `"${v.replace(/"/g, '""')}"`).join(','));
    }

    const csvContent = [headers.map(h => `"${h}"`).join(','), ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', `PG_${type}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const filteredHistory = useMemo(() => {
    let result = [...scans];
    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }
    if (historyFilters.qrId) result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    if (historyFilters.process !== 'all') result = result.filter(s => s.process === historyFilters.process);
    if (historyFilters.line !== 'all') result = result.filter(s => s.line === historyFilters.line);
    if (historyFilters.startDate) result = result.filter(s => new Date(s.scan_time) >= new Date(historyFilters.startDate));
    if (historyFilters.endDate) {
      const end = new Date(historyFilters.endDate);
      end.setHours(23, 59, 59, 999);
      result = result.filter(s => new Date(s.scan_time) <= end);
    }
    result.sort((a, b) => {
      const valA = a[historySort.key];
      const valB = b[historySort.key];
      if (valA < valB) return historySort.order === 'asc' ? -1 : 1;
      if (valA > valB) return historySort.order === 'asc' ? 1 : -1;
      return 0;
    });
    return result;
  }, [scans, historyFilters, historySort, historyCategory]);

  const handleSort = (key: keyof ScanningData) => {
    setHistorySort(prev => ({ key, order: prev.key === key && prev.order === 'asc' ? 'desc' : 'asc' }));
  };

  const SortIcon = ({ column }: { column: keyof ScanningData }) => {
    if (historySort.key !== column) return <span className="opacity-20 ml-1">⇅</span>;
    return <span className="ml-1">{historySort.order === 'asc' ? '↑' : '↓'}</span>;
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 border-l-4 border-l-blue-500">
              <h4 className="font-black text-gray-800 uppercase tracking-tight mb-2">Cutting Output</h4>
              <h5 className="text-4xl font-black text-blue-600">{dashboardStats.cuttingDone} <span className="text-sm font-medium text-gray-400">pcs</span></h5>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 border-l-4 border-l-indigo-500">
              <h4 className="font-black text-gray-800 uppercase tracking-tight mb-2">Sewing Output</h4>
              <h5 className="text-4xl font-black text-indigo-600">{dashboardStats.sewingOutput} <span className="text-sm font-medium text-gray-400">pcs</span></h5>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex flex-col xl:flex-row justify-between items-center gap-6">
            <h3 className="text-2xl font-black text-gray-800 tracking-tight uppercase">Orders Ledger</h3>
            <div className="flex flex-wrap items-center gap-4">
               <div className="flex bg-white p-1 rounded-xl border border-gray-100 shadow-sm">
                {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                  <button key={f} onClick={() => setOrderProcessFilter(f)} className={`px-4 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${orderProcessFilter === f ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:bg-gray-50'}`}>{f}</button>
                ))}
              </div>
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10">DOWNLOAD EXCEL</button>
            </div>
          </div>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left whitespace-nowrap">
                <thead className="bg-gray-50 text-gray-500 uppercase text-[10px] font-black tracking-wider border-b border-gray-100">
                  <tr>{getOrdersMasterData().headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-gray-100 text-sm font-medium text-gray-700">
                  {getOrdersMasterData().rows.map((row, idx) => (
                    <tr key={idx} className="hover:bg-gray-50 transition-colors">
                      {getOrdersMasterData().headers.map(h => (
                        <td key={h.key} className="px-6 py-3">{h.key === 'timestamp' ? new Date(row[h.key]).toLocaleDateString() : row[h.key]}</td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-gray-100 text-center relative overflow-hidden">
            <h3 className="text-3xl font-black text-gray-900 mb-2">Production Gateway</h3>
            <p className="text-gray-500 mb-8">Scan / Input Bundle ID (e.g., PG-26...)</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="PG-..." className="flex-1 border-2 border-gray-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-bold ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-gray-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PCS</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-4">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Select Process</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
               <div className="flex flex-col md:flex-row md:items-center gap-4">
                  <h3 className="text-xl font-black text-gray-800">History Filters</h3>
                  <div className="flex bg-gray-50 p-1 rounded-xl border border-gray-100">
                    {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                      <button key={f} onClick={() => setHistoryCategory(f)} className={`px-4 py-1.5 text-[10px] font-black uppercase rounded-lg transition-all tracking-wider ${historyCategory === f ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-800'}`}>{f}</button>
                    ))}
                  </div>
               </div>
               <button onClick={() => { setHistoryFilters({ qrId: '', process: 'all', line: 'all', startDate: '', endDate: '' }); setHistoryCategory('all'); }} className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600">Reset</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <input type="text" value={historyFilters.qrId} onChange={(e) => setHistoryFilters(prev => ({ ...prev, qrId: e.target.value }))} placeholder="QR ID" className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none focus:border-blue-500" />
              <select value={historyFilters.process} onChange={(e) => setHistoryFilters(prev => ({ ...prev, process: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none focus:border-blue-500">
                <option value="all">PROCESS</option>
                {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <select value={historyFilters.line} onChange={(e) => setHistoryFilters(prev => ({ ...prev, line: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none focus:border-blue-500">
                <option value="all">LINE</option>
                {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
              <input type="date" value={historyFilters.startDate} onChange={(e) => setHistoryFilters(prev => ({ ...prev, startDate: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none" />
              <input type="date" value={historyFilters.endDate} onChange={(e) => setHistoryFilters(prev => ({ ...prev, endDate: e.target.value }))} className="bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-xs font-bold uppercase outline-none" />
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-8 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-gray-800 uppercase tracking-tight">Audit Log</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{filteredHistory.length} Transactions Found</p>
              </div>
              <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10">DOWNLOAD EXCEL</button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.1em]">
                  <tr>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('scan_time')}>Timestamp <SortIcon column="scan_time" /></th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('qr_id')}>QR Identifier <SortIcon column="qr_id" /></th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('process')}>Process <SortIcon column="process" /></th>
                    <th className="px-8 py-5 text-right cursor-pointer hover:text-blue-600" onClick={() => handleSort('qty')}>Qty <SortIcon column="qty" /></th>
                    <th className="px-8 py-5 cursor-pointer hover:text-blue-600" onClick={() => handleSort('line')}>Line <SortIcon column="line" /></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100 text-sm">
                  {filteredHistory.map((scan) => (
                    <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                      <td className="px-8 py-4 font-medium text-slate-500">{new Date(scan.scan_time).toLocaleString()}</td>
                      <td className="px-8 py-4 font-black text-slate-900 tracking-tight">{scan.qr_id}</td>
                      <td className="px-8 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                      </td>
                      <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty}</td>
                      <td className="px-8 py-4 text-xs font-bold text-slate-600">{scan.line}</td>
                    </tr>
                  ))}
                  {filteredHistory.length === 0 && (
                    <tr><td colSpan={5} className="py-20 text-center text-slate-400 font-black uppercase text-[10px]">No matches found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v3';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Persistent storage for scan data
  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });
  const [historySort, setHistorySort] = useState<{ key: keyof ScanningData; order: 'asc' | 'desc' }>({
    key: 'scan_time',
    order: 'desc'
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];
      MOCK_ORDERS.forEach(order => {
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(order.po_qty * 0.8),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-SEW-IN-${order.style}`,
          process: 'Sewing Input',
          qty: Math.floor(order.po_qty * 0.75),
          status: ProductionStatus.COMPLETED,
          line: 'Line-1',
          scanned_by: 'System',
          scan_time: nowStr
        });
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Successfully posted ${scanningDetail.bundle_qty} pcs`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return 0;
    return scans.filter(s => s.qr_id.includes(order.style) && s.process === process).reduce((a, b) => a + b.qty, 0);
  };

  const getOrdersMasterData = useCallback(() => {
    const headers = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'po_qty', label: 'PO Qty' },
      { key: 'c_qty', label: 'Cutting' },
      { key: 's_qty', label: 'Sewing' },
      { key: 'w_qty', label: 'Wash' },
      { key: 'f_qty', label: 'Finishing' },
    ];
    const rows = orders.map(o => ({
      ...o,
      timestamp: o.created_at,
      c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
      s_qty: getOrderProcessQty(o.id, 'Sewing Output'),
      w_qty: getOrderProcessQty(o.id, 'Wash Output'),
      f_qty: getOrderProcessQty(o.id, 'Finishing Output')
    }));
    return { headers, rows };
  }, [orders, scans]);

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      const data = getOrdersMasterData();
      headers = data.headers.map(h => h.label);
      csvRows = data.rows.map(row => data.headers.map(h => `"${(row[h.key] || '').toString().replace(/"/g, '""')}"`).join(','));
    } else {
      headers = ["Timestamp", "QR", "Process", "Qty", "Line"];
      csvRows = filteredHistory.map(scan => [new Date(scan.scan_time).toLocaleString(), scan.qr_id, scan.process, scan.qty.toString(), scan.line].map(v => `"${v.replace(/"/g, '""')}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  const filteredHistory = useMemo(() => {
    let result = [...scans];
    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }
    if (historyFilters.qrId) result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    if (historyFilters.process !== 'all') result = result.filter(s => s.process === historyFilters.process);
    if (historyFilters.startDate) result = result.filter(s => new Date(s.scan_time) >= new Date(historyFilters.startDate));
    if (historyFilters.endDate) result = result.filter(s => new Date(s.scan_time) <= new Date(historyFilters.endDate));
    result.sort((a, b) => new Date(b.scan_time).getTime() - new Date(a.scan_time).getTime());
    return result;
  }, [scans, historyFilters, historyCategory]);

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          {/* Enhanced Attractive Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* Cutting Section Card */}
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 border-t-blue-500">
               <div className="absolute -right-4 -top-4 text-blue-500 opacity-[0.05] group-hover:opacity-[0.08] transition-opacity">
                 <span className="text-8xl font-black">CUT</span>
               </div>
               <div className="flex items-center space-x-3 mb-6">
                 <div className="bg-blue-50 p-3 rounded-2xl text-blue-600 font-bold">✂️</div>
                 <div>
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section 01</h4>
                    <p className="text-sm font-black text-slate-800 uppercase tracking-tight">Cutting</p>
                 </div>
               </div>
               <div className="space-y-1">
                 <p className="text-4xl font-black text-blue-600 tracking-tighter">{dashboardStats.cuttingDone.toLocaleString()}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Pcs Finished</p>
               </div>
               <div className="mt-6 pt-4 border-t border-slate-50 flex justify-between items-center">
                  <span className="text-[10px] font-bold text-green-500 bg-green-50 px-2 py-0.5 rounded-full">ACTIVE</span>
                  <span className="text-[10px] font-black text-slate-300 uppercase">Pioneer Group</span>
               </div>
            </div>

            {/* Sewing Production Card */}
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 border-t-indigo-500">
               <div className="absolute -right-4 -top-4 text-indigo-500 opacity-[0.05] group-hover:opacity-[0.08] transition-opacity">
                 <span className="text-8xl font-black">SEW</span>
               </div>
               <div className="flex items-center space-x-3 mb-6">
                 <div className="bg-indigo-50 p-3 rounded-2xl text-indigo-600 font-bold">🧵</div>
                 <div>
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section 02</h4>
                    <p className="text-sm font-black text-slate-800 uppercase tracking-tight">Sewing</p>
                 </div>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-2xl font-black text-indigo-600 tracking-tighter">{dashboardStats.sewingInput.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Input</p>
                  </div>
                  <div>
                    <p className="text-2xl font-black text-green-600 tracking-tighter">{dashboardStats.sewingOutput.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Output</p>
                  </div>
               </div>
               <div className="mt-6 pt-4 border-t border-slate-50 flex justify-between items-center">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-indigo-800 uppercase">WIP GAP</span>
                    <span className="text-xs font-black text-indigo-600">{Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString()}</span>
                  </div>
                  <div className="w-12 h-1 bg-slate-100 rounded-full overflow-hidden">
                    <div className="bg-indigo-500 h-full w-[65%]"></div>
                  </div>
               </div>
            </div>

            {/* Wash Production Card */}
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 border-t-cyan-500">
               <div className="absolute -right-4 -top-4 text-cyan-500 opacity-[0.05] group-hover:opacity-[0.08] transition-opacity">
                 <span className="text-8xl font-black">WSH</span>
               </div>
               <div className="flex items-center space-x-3 mb-6">
                 <div className="bg-cyan-50 p-3 rounded-2xl text-cyan-600 font-bold">🧼</div>
                 <div>
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section 03</h4>
                    <p className="text-sm font-black text-slate-800 uppercase tracking-tight">Wash</p>
                 </div>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-2xl font-black text-cyan-600 tracking-tighter">{dashboardStats.washInput.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Laundry In</p>
                  </div>
                  <div>
                    <p className="text-2xl font-black text-green-600 tracking-tighter">{dashboardStats.washOutput.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Laundry Out</p>
                  </div>
               </div>
               <div className="mt-6 pt-4 border-t border-slate-50 flex justify-between items-center">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-cyan-800 uppercase">Queue</span>
                    <span className="text-xs font-black text-cyan-600">{Math.max(0, dashboardStats.washInput - dashboardStats.washOutput).toLocaleString()}</span>
                  </div>
                  <div className="w-12 h-1 bg-slate-100 rounded-full overflow-hidden">
                    <div className="bg-cyan-500 h-full w-[40%]"></div>
                  </div>
               </div>
            </div>

            {/* Finishing Production Card */}
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 border-t-emerald-500">
               <div className="absolute -right-4 -top-4 text-emerald-500 opacity-[0.05] group-hover:opacity-[0.08] transition-opacity">
                 <span className="text-8xl font-black">FIN</span>
               </div>
               <div className="flex items-center space-x-3 mb-6">
                 <div className="bg-emerald-50 p-3 rounded-2xl text-emerald-600 font-bold">🏁</div>
                 <div>
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section 04</h4>
                    <p className="text-sm font-black text-slate-800 uppercase tracking-tight">Finishing</p>
                 </div>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-2xl font-black text-emerald-600 tracking-tighter">{dashboardStats.finishingInput.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Poly In</p>
                  </div>
                  <div>
                    <p className="text-2xl font-black text-green-600 tracking-tighter">{dashboardStats.finishingOutput.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Packed</p>
                  </div>
               </div>
               <div className="mt-6 pt-4 border-t border-slate-50 flex justify-between items-center">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-emerald-800 uppercase">Packing WIP</span>
                    <span className="text-xs font-black text-emerald-600">{Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString()}</span>
                  </div>
                  <div className="w-12 h-1 bg-slate-100 rounded-full overflow-hidden">
                    <div className="bg-emerald-500 h-full w-[80%]"></div>
                  </div>
               </div>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>{getOrdersMasterData().headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {getOrdersMasterData().rows.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      {getOrdersMasterData().headers.map(h => (
                        <td key={h.key} className="px-6 py-4">
                          {h.key === 'timestamp' ? new Date(row[h.key]).toLocaleDateString() : (row as any)[h.key]}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Scan / Input Bundle ID for real-time tracking.</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="PG-..." className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PCS</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <div className="flex justify-between items-center">
               <div className="flex items-center space-x-4">
                  <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">History Filters</h3>
                  <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                    {(['all', 'cutting', 'sewing', 'washing', 'finishing'] as const).map(f => (
                      <button key={f} onClick={() => setHistoryCategory(f)} className={`px-4 py-1.5 text-[10px] font-black uppercase rounded-lg transition-all ${historyCategory === f ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}>{f}</button>
                    ))}
                  </div>
               </div>
               <button onClick={() => { setHistoryFilters({ qrId: '', process: 'all', line: 'all', startDate: '', endDate: '' }); setHistoryCategory('all'); }} className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600">Reset All</button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              <input type="text" value={historyFilters.qrId} onChange={(e) => setHistoryFilters(p => ({ ...p, qrId: e.target.value }))} placeholder="Search QR..." className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none focus:border-blue-500" />
              <select value={historyFilters.process} onChange={(e) => setHistoryFilters(p => ({ ...p, process: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none">
                <option value="all">All Processes</option>
                {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <input type="date" value={historyFilters.startDate} onChange={(e) => setHistoryFilters(p => ({ ...p, startDate: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none" />
              <input type="date" value={historyFilters.endDate} onChange={(e) => setHistoryFilters(p => ({ ...p, endDate: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none" />
            </div>
          </div>

          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Audit Log</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{filteredHistory.length} Records Found</p>
              </div>
              <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 transition-all shadow-lg shadow-green-900/10">Download Excel</button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                  <tr>
                    <th className="px-8 py-5">Timestamp</th>
                    <th className="px-8 py-5">QR ID</th>
                    <th className="px-8 py-5">Process</th>
                    <th className="px-8 py-5 text-right">Qty</th>
                    <th className="px-8 py-5">Line</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                  {filteredHistory.map((scan) => (
                    <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                      <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleString()}</td>
                      <td className="px-8 py-4 text-slate-900 font-black tracking-tight">{scan.qr_id}</td>
                      <td className="px-8 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                      </td>
                      <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty}</td>
                      <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                    </tr>
                  ))}
                  {filteredHistory.length === 0 && (
                    <tr><td colSpan={5} className="py-20 text-center text-slate-400 font-black uppercase text-[10px]">No matches found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v4';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Persistent storage for scan data
  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });
  const [historySort, setHistorySort] = useState<{ key: keyof ScanningData; order: 'asc' | 'desc' }>({
    key: 'scan_time',
    order: 'desc'
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      // Generating some rich demo data for 15 lines
      MOCK_ORDERS.forEach((order, orderIdx) => {
        // Cutting
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: order.po_qty,
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // Seed 15 lines with varied data
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;
          const lineInput = Math.floor(200 + Math.random() * 300);
          const lineOutput = Math.floor(lineInput * (0.7 + Math.random() * 0.25));

          demoScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-IN-${order.style}-L${i}`,
            process: 'Sewing Input',
            qty: lineInput,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'System',
            scan_time: nowStr
          });

          demoScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-OUT-${order.style}-L${i}`,
            process: 'Sewing Output',
            qty: lineOutput,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'System',
            scan_time: nowStr
          });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((a, b) => a + b.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const lineWiseData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    const TARGET_PER_LINE = 450; // Demo target for efficiency calculation

    return lines.map(line => {
      const input = scans.filter(s => s.line === line && s.process === 'Sewing Input').reduce((a, b) => a + b.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === 'Sewing Output').reduce((a, b) => a + b.qty, 0);
      const wip = Math.max(0, input - output);
      const effi = Math.min(100, Math.round((output / TARGET_PER_LINE) * 100));

      let status: 'Good' | 'Fair' | 'Critical' = 'Good';
      if (effi < 40) status = 'Critical';
      else if (effi < 75) status = 'Fair';

      return { line, input, output, wip, effi, status };
    });
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Successfully posted ${scanningDetail.bundle_qty} pcs`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrderProcessQty = (orderId: string, process: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return 0;
    return scans.filter(s => s.qr_id.includes(order.style) && s.process === process).reduce((a, b) => a + b.qty, 0);
  };

  const getOrdersMasterData = useCallback(() => {
    const headers = [
      { key: 'timestamp', label: 'Timestamp' },
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'po_qty', label: 'PO Qty' },
      { key: 'c_qty', label: 'Cutting' },
      { key: 's_qty', label: 'Sewing' },
      { key: 'w_qty', label: 'Wash' },
      { key: 'f_qty', label: 'Finishing' },
    ];
    const rows = orders.map(o => ({
      ...o,
      timestamp: o.created_at,
      c_qty: getOrderProcessQty(o.id, 'Cutting Done'),
      s_qty: getOrderProcessQty(o.id, 'Sewing Output'),
      w_qty: getOrderProcessQty(o.id, 'Wash Output'),
      f_qty: getOrderProcessQty(o.id, 'Finishing Output')
    }));
    return { headers, rows };
  }, [orders, scans]);

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      const data = getOrdersMasterData();
      headers = data.headers.map(h => h.label);
      csvRows = data.rows.map(row => data.headers.map(h => `"${(row[h.key] || '').toString().replace(/"/g, '""')}"`).join(','));
    } else {
      headers = ["Timestamp", "QR", "Process", "Qty", "Line"];
      csvRows = filteredHistory.map(scan => [new Date(scan.scan_time).toLocaleString(), scan.qr_id, scan.process, scan.qty.toString(), scan.line].map(v => `"${v.replace(/"/g, '""')}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  const filteredHistory = useMemo(() => {
    let result = [...scans];
    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }
    if (historyFilters.qrId) result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    if (historyFilters.process !== 'all') result = result.filter(s => s.process === historyFilters.process);
    if (historyFilters.startDate) result = result.filter(s => new Date(s.scan_time) >= new Date(historyFilters.startDate));
    if (historyFilters.endDate) result = result.filter(s => new Date(s.scan_time) <= new Date(historyFilters.endDate));
    result.sort((a, b) => new Date(b.scan_time).getTime() - new Date(a.scan_time).getTime());
    return result;
  }, [scans, historyFilters, historyCategory]);

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* Main Production Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
