  return (
    <div className={`bg-white rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${colorMap[color].split(' ')[1]}`}>
       <div className={`absolute -right-4 -top-4 ${colorMap[color].split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.08] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>
       <div className="flex items-center space-x-3 mb-6">
         <div className={`${colorMap[color].split(' ')[2]} p-3 rounded-2xl ${colorMap[color].split(' ')[0]} font-bold`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section {section}</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title.split(' ')[0]}</p>
         </div>
       </div>
       {details ? (
          <div className="grid grid-cols-2 gap-4">
            <div>
              <p className={`text-2xl font-black ${colorMap[color].split(' ')[0]} tracking-tighter`}>{details.input.toLocaleString()}</p>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Input</p>
            </div>
            <div>
              <p className="text-2xl font-black text-green-600 tracking-tighter">{details.output.toLocaleString()}</p>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Output</p>
            </div>
          </div>
       ) : (
          <div className="space-y-1">
            <p className={`text-4xl font-black ${colorMap[color].split(' ')[0]} tracking-tighter`}>{value.toLocaleString()}</p>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Completed</p>
          </div>
       )}
       <div className="mt-6 pt-4 border-t border-slate-50 flex justify-between items-center">
          {details ? (
            <div className="flex flex-col">
              <span className={`text-[10px] font-black ${colorMap[color].split(' ')[0]} uppercase`}>WIP GAP</span>
              <span className={`text-xs font-black ${colorMap[color].split(' ')[0]}`}>{details.wip.toLocaleString()}</span>
            </div>
          ) : (
            <span className="text-[10px] font-bold text-green-500 bg-green-50 px-2 py-0.5 rounded-full">ACTIVE</span>
          )}
          <div className="w-12 h-1 bg-slate-100 rounded-full overflow-hidden">
            <div className={`h-full ${colorMap[color].replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '60%' }}></div>
          </div>
       </div>
    </div>
  );
};

