import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v5';

// Mock Targets for Dashboard Metrics
const TARGETS = {
  cutting: 6000,
  sewing: 5000,
  wash: 4500,
  finishing: 4000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Persistent storage for scan data
  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(order.po_qty * 0.9),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // 15 Lines
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;
          const lineInput = Math.floor(250 + Math.random() * 200);
          const lineOutput = Math.floor(lineInput * (0.6 + Math.random() * 0.35));

          demoScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-IN-${order.style}-L${i}`,
            process: 'Sewing Input',
            qty: lineInput,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'System',
            scan_time: nowStr
          });

          demoScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-OUT-${order.style}-L${i}`,
            process: 'Sewing Output',
            qty: lineOutput,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'System',
            scan_time: nowStr
          });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const lineWiseData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    const TARGET_PER_LINE = 400;

    return lines.map(line => {
      const input = scans.filter(s => s.line === line && s.process === 'Sewing Input').reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === 'Sewing Output').reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      const effi = Math.min(100, Math.round((output / TARGET_PER_LINE) * 100));

      let status: 'Good' | 'Fair' | 'Critical' = 'Good';
      if (effi < 40) status = 'Critical';
      else if (effi < 75) status = 'Fair';

      return { line, input, output, wip, effi, status };
    });
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Loaded.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: ${scanningDetail.bundle_qty} posted.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrdersMasterData = useCallback(() => {
    const headers = [
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'po_qty', label: 'Qty' },
      { key: 'c_qty', label: 'Cut' },
      { key: 's_qty', label: 'Sew' },
      { key: 'w_qty', label: 'Wash' },
      { key: 'f_qty', label: 'Fin' },
    ];
    const rows = orders.map(o => {
      const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
      return {
        ...o,
        c_qty: scans.filter(s => styleFilter(s) && s.process === 'Cutting Done').reduce((sum, item) => sum + item.qty, 0),
        s_qty: scans.filter(s => styleFilter(s) && s.process === 'Sewing Output').reduce((sum, item) => sum + item.qty, 0),
        w_qty: scans.filter(s => styleFilter(s) && s.process === 'Wash Output').reduce((sum, item) => sum + item.qty, 0),
        f_qty: scans.filter(s => styleFilter(s) && s.process === 'Finishing Output').reduce((sum, item) => sum + item.qty, 0),
      };
    });
    return { headers, rows };
  }, [orders, scans]);

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      const data = getOrdersMasterData();
      headers = data.headers.map(h => h.label);
      csvRows = data.rows.map(row => data.headers.map(h => `"${(row[h.key] || '').toString()}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = filteredHistory.map(scan => [new Date(scan.scan_time).toLocaleString(), scan.qr_id, scan.process, scan.qty.toString(), scan.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  const filteredHistory = useMemo(() => {
    let result = [...scans];
    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }
    if (historyFilters.qrId) result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    if (historyFilters.process !== 'all') result = result.filter(s => s.process === historyFilters.process);
    if (historyFilters.startDate) result = result.filter(s => new Date(s.scan_time) >= new Date(historyFilters.startDate));
    if (historyFilters.endDate) result = result.filter(s => new Date(s.scan_time) <= new Date(historyFilters.endDate));
    result.sort((a, b) => new Date(b.scan_time).getTime() - new Date(a.scan_time).getTime());
    return result;
  }, [scans, historyFilters, historyCategory]);

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* SPECIALIZED ATTRACTIVE CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* Cutting Section */}
            <DashboardCard 
              icon="✂️" 
              title="Cutting Department" 
              value={dashboardStats.cuttingDone} 
              color="blue" 
              label="CUT"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true }
              ]}
            />

            {/* Sewing Production */}
            <DashboardCard 
              icon="🧵" 
              title="Sewing Production" 
              value={dashboardStats.sewingOutput} 
              color="indigo" 
              label="SEW"
              subMetrics={[
                { label: 'WIP', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }
              ]}
            />

            {/* Wash Production */}
            <DashboardCard 
              icon="🧼" 
              title="Wash Production" 
              value={dashboardStats.washOutput} 
              color="cyan" 
              label="WSH"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.wash.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }
              ]}
            />

            {/* Finishing Production */}
            <DashboardCard 
              icon="🏁" 
              title="Finishing Production" 
              value={dashboardStats.finishingOutput} 
              color="emerald" 
              label="FIN"
              subMetrics={[
                { label: 'WIP', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }
              ]}
              footerStatus="Active"
            />
          </div>

          {/* Line-wise Performance Section */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col md:flex-row justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line-wise Performance</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time Sewing Floor Audit (L01 - L15)</p>
              </div>
              <div className="mt-4 md:mt-0 flex items-center space-x-6">
                 <div className="bg-slate-800 px-4 py-2 rounded-xl border border-slate-700">
                    <span className="text-xs font-black text-indigo-400 uppercase tracking-widest">Target: 400 Pcs/Line</span>
                 </div>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5">Line Name</th>
                    <th className="px-8 py-5">Input</th>
                    <th className="px-8 py-5">Output</th>
                    <th className="px-8 py-5">WIP</th>
                    <th className="px-8 py-5">Effi %</th>
                    <th className="px-8 py-5 text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {lineWiseData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-900">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                         <div className="flex items-center space-x-3">
                            <div className="w-20 bg-slate-100 h-1.5 rounded-full overflow-hidden">
                               <div className={`h-full ${item.effi < 40 ? 'bg-rose-500' : item.effi < 75 ? 'bg-amber-500' : 'bg-emerald-500'}`} style={{ width: `${item.effi}%` }}></div>
                            </div>
                            <span className="text-xs tabular-nums">{item.effi}%</span>
                         </div>
                      </td>
                      <td className="px-8 py-4 text-center">
                         <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                           item.status === 'Good' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                           item.status === 'Fair' ? 'bg-amber-50 text-amber-600 border-amber-100' :
                           'bg-rose-50 text-rose-600 border-rose-100'
                         }`}>{item.status}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>{getOrdersMasterData().headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {getOrdersMasterData().rows.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      {getOrdersMasterData().headers.map(h => (
                        <td key={h.key} className="px-6 py-4">{(row as any)[h.key]}</td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Scan / Input Bundle ID (e.g., PG-260225...)</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="PG-..." className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PCS</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <div className="flex justify-between items-center">
               <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">History Audit</h3>
               <button onClick={() => { setActiveTab('scan'); }} className="text-[10px] font-black text-blue-600 uppercase tracking-widest">+ New Entry</button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              <input type="text" value={historyFilters.qrId} onChange={(e) => setHistoryFilters(p => ({ ...p, qrId: e.target.value }))} placeholder="Search QR..." className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none focus:border-blue-500" />
              <select value={historyFilters.process} onChange={(e) => setHistoryFilters(p => ({ ...p, process: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none">
                <option value="all">All Processes</option>
                {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <input type="date" value={historyFilters.startDate} onChange={(e) => setHistoryFilters(p => ({ ...p, startDate: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none" />
              <input type="date" value={historyFilters.endDate} onChange={(e) => setHistoryFilters(p => ({ ...p, endDate: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none" />
            </div>
          </div>

          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Audit Log</h3>
              <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                  <tr>
                    <th className="px-8 py-5">Time</th>
                    <th className="px-8 py-5">QR ID</th>
                    <th className="px-8 py-5">Process</th>
                    <th className="px-8 py-5 text-right">Qty</th>
                    <th className="px-8 py-5">Line</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                  {filteredHistory.map((scan) => (
                    <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                      <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleTimeString()}</td>
                      <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                      <td className="px-8 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                      </td>
                      <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty}</td>
                      <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>

       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Department Log</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>

       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-5xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Units Scanned</p>
       </div>

       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i}>
              <p className={`text-xl font-black tracking-tighter ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{m.label}</p>
           </div>
         ))}
       </div>

       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v5';

// Mock Targets for Dashboard Metrics
const TARGETS = {
  cutting: 6000,
  sewing: 5000,
  wash: 4500,
  finishing: 4000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);

  // Persistent storage for scan data
  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [orderProcessFilter, setOrderProcessFilter] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(order.po_qty * 0.9),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // 15 Lines
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;
          const lineInput = Math.floor(250 + Math.random() * 200);
          const lineOutput = Math.floor(lineInput * (0.6 + Math.random() * 0.35));

          demoScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-IN-${order.style}-L${i}`,
            process: 'Sewing Input',
            qty: lineInput,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'System',
            scan_time: nowStr
          });

          demoScans.push({
            id: crypto.randomUUID(),
            qr_id: `PG-SEW-OUT-${order.style}-L${i}`,
            process: 'Sewing Output',
            qty: lineOutput,
            status: ProductionStatus.COMPLETED,
            line: line,
            scanned_by: 'System',
            scan_time: nowStr
          });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const lineWiseData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    const TARGET_PER_LINE = 400;

    return lines.map(line => {
      const input = scans.filter(s => s.line === line && s.process === 'Sewing Input').reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === 'Sewing Output').reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      const effi = Math.min(100, Math.round((output / TARGET_PER_LINE) * 100));

      let status: 'Good' | 'Fair' | 'Critical' = 'Good';
      if (effi < 40) status = 'Critical';
      else if (effi < 75) status = 'Fair';

      return { line, input, output, wip, effi, status };
    });
  }, [scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Loaded.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: ${scanningDetail.bundle_qty} posted.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const getOrdersMasterData = useCallback(() => {
    const headers = [
      { key: 'buyer', label: 'Buyer' },
      { key: 'style', label: 'Style' },
      { key: 'po', label: 'PO' },
      { key: 'po_qty', label: 'Qty' },
      { key: 'c_qty', label: 'Cut' },
      { key: 's_qty', label: 'Sew' },
      { key: 'w_qty', label: 'Wash' },
      { key: 'f_qty', label: 'Fin' },
    ];
    const rows = orders.map(o => {
      const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
      return {
        ...o,
        c_qty: scans.filter(s => styleFilter(s) && s.process === 'Cutting Done').reduce((sum, item) => sum + item.qty, 0),
        s_qty: scans.filter(s => styleFilter(s) && s.process === 'Sewing Output').reduce((sum, item) => sum + item.qty, 0),
        w_qty: scans.filter(s => styleFilter(s) && s.process === 'Wash Output').reduce((sum, item) => sum + item.qty, 0),
        f_qty: scans.filter(s => styleFilter(s) && s.process === 'Finishing Output').reduce((sum, item) => sum + item.qty, 0),
      };
    });
    return { headers, rows };
  }, [orders, scans]);

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      const data = getOrdersMasterData();
      headers = data.headers.map(h => h.label);
      csvRows = data.rows.map(row => data.headers.map(h => `"${(row[h.key] || '').toString()}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = filteredHistory.map(scan => [new Date(scan.scan_time).toLocaleString(), scan.qr_id, scan.process, scan.qty.toString(), scan.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  const filteredHistory = useMemo(() => {
    let result = [...scans];
    if (historyCategory !== 'all') {
      result = result.filter(s => {
        const p = s.process.toLowerCase();
        if (historyCategory === 'cutting') return p.includes('cutting');
        if (historyCategory === 'sewing') return p.includes('sewing');
        if (historyCategory === 'washing') return p.includes('wash');
        if (historyCategory === 'finishing') return p.includes('finishing');
        return true;
      });
    }
    if (historyFilters.qrId) result = result.filter(s => s.qr_id.toLowerCase().includes(historyFilters.qrId.toLowerCase()));
    if (historyFilters.process !== 'all') result = result.filter(s => s.process === historyFilters.process);
    if (historyFilters.startDate) result = result.filter(s => new Date(s.scan_time) >= new Date(historyFilters.startDate));
    if (historyFilters.endDate) result = result.filter(s => new Date(s.scan_time) <= new Date(historyFilters.endDate));
    result.sort((a, b) => new Date(b.scan_time).getTime() - new Date(a.scan_time).getTime());
    return result;
  }, [scans, historyFilters, historyCategory]);

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* SPECIALIZED ATTRACTIVE CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* Cutting Section */}
            <DashboardCard 
              icon="✂️" 
              title="Cutting Department" 
              value={dashboardStats.cuttingDone} 
              color="blue" 
              label="CUT"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true }
              ]}
            />

            {/* Sewing Production */}
            <DashboardCard 
              icon="🧵" 
              title="Sewing Production" 
              value={dashboardStats.sewingOutput} 
              color="indigo" 
              label="SEW"
              subMetrics={[
                { label: 'WIP', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }
              ]}
            />

            {/* Wash Production */}
            <DashboardCard 
              icon="🧼" 
              title="Wash Production" 
              value={dashboardStats.washOutput} 
              color="cyan" 
              label="WSH"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.wash.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }
              ]}
            />

            {/* Finishing Production */}
            <DashboardCard 
              icon="🏁" 
              title="Finishing Production" 
              value={dashboardStats.finishingOutput} 
              color="emerald" 
              label="FIN"
              subMetrics={[
                { label: 'WIP', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }
              ]}
              footerStatus="Active"
            />
          </div>

          {/* Line-wise Performance Section */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col md:flex-row justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line-wise Performance</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time Sewing Floor Audit (L01 - L15)</p>
              </div>
              <div className="mt-4 md:mt-0 flex items-center space-x-6">
                 <div className="bg-slate-800 px-4 py-2 rounded-xl border border-slate-700">
                    <span className="text-xs font-black text-indigo-400 uppercase tracking-widest">Target: 400 Pcs/Line</span>
                 </div>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5">Line Name</th>
                    <th className="px-8 py-5">Input</th>
                    <th className="px-8 py-5">Output</th>
                    <th className="px-8 py-5">WIP</th>
                    <th className="px-8 py-5">Effi %</th>
                    <th className="px-8 py-5 text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {lineWiseData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-900">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                         <div className="flex items-center space-x-3">
                            <div className="w-20 bg-slate-100 h-1.5 rounded-full overflow-hidden">
                               <div className={`h-full ${item.effi < 40 ? 'bg-rose-500' : item.effi < 75 ? 'bg-amber-500' : 'bg-emerald-500'}`} style={{ width: `${item.effi}%` }}></div>
                            </div>
                            <span className="text-xs tabular-nums">{item.effi}%</span>
                         </div>
                      </td>
                      <td className="px-8 py-4 text-center">
                         <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                           item.status === 'Good' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                           item.status === 'Fair' ? 'bg-amber-50 text-amber-600 border-amber-100' :
                           'bg-rose-50 text-rose-600 border-rose-100'
                         }`}>{item.status}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>{getOrdersMasterData().headers.map(h => <th key={h.key} className="px-6 py-4">{h.label}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {getOrdersMasterData().rows.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      {getOrdersMasterData().headers.map(h => (
                        <td key={h.key} className="px-6 py-4">{(row as any)[h.key]}</td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Scan / Input Bundle ID (e.g., PG-260225...)</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="PG-..." className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PCS</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <div className="flex justify-between items-center">
               <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">History Audit</h3>
               <button onClick={() => { setActiveTab('scan'); }} className="text-[10px] font-black text-blue-600 uppercase tracking-widest">+ New Entry</button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              <input type="text" value={historyFilters.qrId} onChange={(e) => setHistoryFilters(p => ({ ...p, qrId: e.target.value }))} placeholder="Search QR..." className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none focus:border-blue-500" />
              <select value={historyFilters.process} onChange={(e) => setHistoryFilters(p => ({ ...p, process: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none">
                <option value="all">All Processes</option>
                {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <input type="date" value={historyFilters.startDate} onChange={(e) => setHistoryFilters(p => ({ ...p, startDate: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none" />
              <input type="date" value={historyFilters.endDate} onChange={(e) => setHistoryFilters(p => ({ ...p, endDate: e.target.value }))} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs font-bold uppercase outline-none" />
            </div>
          </div>

          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Audit Log</h3>
              <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                  <tr>
                    <th className="px-8 py-5">Time</th>
                    <th className="px-8 py-5">QR ID</th>
                    <th className="px-8 py-5">Process</th>
                    <th className="px-8 py-5 text-right">Qty</th>
                    <th className="px-8 py-5">Line</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                  {filteredHistory.map((scan) => (
                    <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                      <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleTimeString()}</td>
                      <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                      <td className="px-8 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                      </td>
                      <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty}</td>
                      <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>

       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Department Log</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>

       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-5xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Units Scanned</p>
       </div>

       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i}>
              <p className={`text-xl font-black tracking-tighter ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{m.label}</p>
           </div>
         ))}
       </div>

       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v6';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 8000,
  sewing: 6000,
  wash: 5500,
  finishing: 5000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Wash' | 'Finishing'>('Sewing');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed data for 15 lines across all departments
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting Total
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(TARGETS.cutting * 0.85),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // 15 Lines data generation
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;

          // Sewing
          const sIn = Math.floor(300 + Math.random() * 150);
          const sOut = Math.floor(sIn * (0.7 + Math.random() * 0.25));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-IN-L${i}`, process: 'Sewing Input', qty: sIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-OUT-L${i}`, process: 'Sewing Output', qty: sOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Wash
          const wIn = Math.floor(250 + Math.random() * 150);
          const wOut = Math.floor(wIn * (0.8 + Math.random() * 0.15));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `W-IN-L${i}`, process: 'Wash Input', qty: wIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `W-OUT-L${i}`, process: 'Wash Output', qty: wOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Finishing
          const fIn = Math.floor(200 + Math.random() * 100);
          const fOut = Math.floor(fIn * (0.9 + Math.random() * 0.08));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-IN-L${i}`, process: 'Finishing Input', qty: fIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-OUT-L${i}`, process: 'Finishing Output', qty: fOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    const targets = { Sewing: 400, Wash: 350, Finishing: 300 };
    const currentTarget = targets[performanceView];

    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      const effi = Math.min(100, Math.round((output / currentTarget) * 100));

      let status: 'Good' | 'Fair' | 'Critical' = 'Good';
      if (effi < 45) status = 'Critical';
      else if (effi < 80) status = 'Fair';

      return { line, input, output, wip, effi, status };
    });
  }, [scans, performanceView]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing') || selectedProcess.includes('Wash');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Posted ${scanningDetail.bundle_qty} pieces.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["Buyer", "Style", "PO", "PO Qty", "Cut", "Sew", "Wash", "Fin"];
      csvRows = orders.map(o => {
        const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
        const cut = scans.filter(s => styleFilter(s) && s.process === 'Cutting Done').reduce((a, b) => a + b.qty, 0);
        const sew = scans.filter(s => styleFilter(s) && s.process === 'Sewing Output').reduce((a, b) => a + b.qty, 0);
        const wash = scans.filter(s => styleFilter(s) && s.process === 'Wash Output').reduce((a, b) => a + b.qty, 0);
        const fin = scans.filter(s => styleFilter(s) && s.process === 'Finishing Output').reduce((a, b) => a + b.qty, 0);
        return [o.buyer, o.style, o.po, o.po_qty, cut, sew, wash, fin].map(v => `"${v}"`).join(',');
      });
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* HEADER SUMMARY CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* 1. Cutting Department */}
            <DashboardCard 
              icon="✂️" 
              title="Cutting Department" 
              value={dashboardStats.cuttingDone} 
              color="blue" 
              label="CUT"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true, showProgress: true }
              ]}
            />

            {/* 2. Sewing Production */}
            <DashboardCard 
              icon="🧵" 
              title="Sewing Production" 
              value={dashboardStats.sewingOutput} 
              color="indigo" 
              label="SEW"
              subMetrics={[
                { label: 'WIP', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }
              ]}
            />

            {/* 3. Wash Production */}
            <DashboardCard 
              icon="🧼" 
              title="Wash Production" 
              value={dashboardStats.washOutput} 
              color="cyan" 
              label="WSH"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.wash.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }
              ]}
            />

            {/* 4. Finishing Production */}
            <DashboardCard 
              icon="🏁" 
              title="Finishing Production" 
              value={dashboardStats.finishingOutput} 
              color="emerald" 
              label="FIN"
              subMetrics={[
                { label: 'WIP', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }
              ]}
              footerStatus="Stable"
            />
          </div>

          {/* LINE-WISE PERFORMANCE LEDGER */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div className="mb-4 lg:mb-0">
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Performance (1-15)</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Select Department to view performance</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
                {(['Sewing', 'Wash', 'Finishing'] as const).map(view => (
                  <button 
                    key={view} 
                    onClick={() => setPerformanceView(view)}
                    className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                  >
                    {view}
                  </button>
                ))}
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5">Line</th>
                    <th className="px-8 py-5">Input (pcs)</th>
                    <th className="px-8 py-5">Output (pcs)</th>
                    <th className="px-8 py-5">WIP</th>
                    <th className="px-8 py-5">Efficiency</th>
                    <th className="px-8 py-5 text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                         <div className="flex items-center space-x-3 min-w-[140px]">
                            <div className="flex-1 bg-slate-100 h-1.5 rounded-full overflow-hidden">
                               <div 
                                  className={`h-full transition-all duration-700 ${item.effi < 45 ? 'bg-rose-500' : item.effi < 80 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                                  style={{ width: `${item.effi}%` }}
                               ></div>
                            </div>
                            <span className="text-xs tabular-nums w-8">{item.effi}%</span>
                         </div>
                      </td>
                      <td className="px-8 py-4 text-center">
                         <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                           item.status === 'Good' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                           item.status === 'Fair' ? 'bg-amber-50 text-amber-600 border-amber-100' :
                           'bg-rose-50 text-rose-600 border-rose-100'
                         }`}>{item.status}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>
                    <th className="px-6 py-4">Buyer</th>
                    <th className="px-6 py-4">Style</th>
                    <th className="px-6 py-4">PO</th>
                    <th className="px-6 py-4 text-right">PO Qty</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {orders.map((o) => (
                    <tr key={o.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4">{o.buyer}</td>
                      <td className="px-6 py-4 font-black">{o.style}</td>
                      <td className="px-6 py-4">{o.po}</td>
                      <td className="px-6 py-4 text-right">{o.po_qty.toLocaleString()} pieces</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Input Bundle ID for real-time tracking (pieces).</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input 
                type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} 
                placeholder="PG-..." 
                className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" 
                onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} 
              />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PIECES</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing') || selectedProcess.includes('Wash')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
             <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Audit Trail</h3>
             <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 shadow-lg shadow-green-900/10">Download CSV</button>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                    <tr>
                      <th className="px-8 py-5">Timestamp</th>
                      <th className="px-8 py-5">QR Identifier</th>
                      <th className="px-8 py-5">Department Step</th>
                      <th className="px-8 py-5 text-right">Quantity</th>
                      <th className="px-8 py-5">Line</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                    {scans.slice().reverse().map((scan) => (
                      <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                        <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleString()}</td>
                        <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                        <td className="px-8 py-4">
                          <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                        </td>
                        <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty} pieces</td>
                        <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
  showProgress?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>

       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section Overview</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>

       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-5xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Pieces Scanned</p>
       </div>

       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i} className="flex flex-col">
              <p className={`text-xl font-black tracking-tighter ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">{m.label}</p>
              {m.showProgress && (
                <div className="w-10 h-1 bg-slate-200/50 rounded-full overflow-hidden">
                   <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: m.value }}></div>
                </div>
              )}
           </div>
         ))}
       </div>

       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell,
  LineChart, Line
} from 'recharts';
import { ScanningData } from '../types';
import { PROCESS_FLOW } from '../constants';

interface ProductionChartProps {
  data: ScanningData[];
}

const ProductionChart: React.FC<ProductionChartProps> = ({ data }) => {
  // Group data by process based on the requested order
  const chartData = PROCESS_FLOW.map(processName => {
    const total = data
      .filter(item => item.process === processName)
      .reduce((sum, curr) => sum + curr.qty, 0);
    return {
      name: processName,
      total: total
    };
  });

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#ec4899'];

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-semibold mb-6 text-gray-800">Production Graph (pieces)</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 10}} interval={0} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                formatter={(value) => [`${value} pieces`, 'Quantity']}
              />
              <Bar dataKey="total" radius={[4, 4, 0, 0]}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-semibold mb-6 text-gray-800">Scanning Trends</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={data.slice(-15).reverse()}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="scan_time" 
                tickFormatter={(val) => new Date(val).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#64748b', fontSize: 10}}
              />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                formatter={(value) => [`${value} pieces`, 'Quantity']}
              />
              <Line type="monotone" dataKey="qty" stroke="#3b82f6" strokeWidth={3} dot={{r: 4, fill: '#3b82f6'}} activeDot={{r: 6}} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default ProductionChart;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v7';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 8000,
  sewing: 6000,
  wash: 5500,
  finishing: 5000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Wash' | 'Finishing'>('Sewing');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed data for 15 lines across all departments
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting Total
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(TARGETS.cutting * 0.85),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // 15 Lines data generation
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;

          // Sewing
          const sIn = Math.floor(300 + Math.random() * 150);
          const sOut = Math.floor(sIn * (0.7 + Math.random() * 0.25));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-IN-L${i}`, process: 'Sewing Input', qty: sIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-OUT-L${i}`, process: 'Sewing Output', qty: sOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Wash
          const wIn = Math.floor(250 + Math.random() * 150);
          const wOut = Math.floor(wIn * (0.8 + Math.random() * 0.15));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `W-IN-L${i}`, process: 'Wash Input', qty: wIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `W-OUT-L${i}`, process: 'Wash Output', qty: wOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Finishing
          const fIn = Math.floor(200 + Math.random() * 100);
          const fOut = Math.floor(fIn * (0.9 + Math.random() * 0.08));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-IN-L${i}`, process: 'Finishing Input', qty: fIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-OUT-L${i}`, process: 'Finishing Output', qty: fOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    const targets = { Sewing: 400, Wash: 350, Finishing: 300 };
    const currentTarget = targets[performanceView];

    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      const effi = Math.min(100, Math.round((output / currentTarget) * 100));

      let status: 'Good' | 'Fair' | 'Critical' = 'Good';
      if (effi < 45) status = 'Critical';
      else if (effi < 80) status = 'Fair';

      return { line, input, output, wip, effi, status };
    });
  }, [scans, performanceView]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing') || selectedProcess.includes('Wash');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Posted ${scanningDetail.bundle_qty} pieces.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["Buyer", "Style", "PO", "PO Qty", "Cut", "Sew", "Wash", "Fin"];
      csvRows = orders.map(o => {
        const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
        const cut = scans.filter(s => styleFilter(s) && s.process === 'Cutting Done').reduce((a, b) => a + b.qty, 0);
        const sew = scans.filter(s => styleFilter(s) && s.process === 'Sewing Output').reduce((a, b) => a + b.qty, 0);
        const wash = scans.filter(s => styleFilter(s) && s.process === 'Wash Output').reduce((a, b) => a + b.qty, 0);
        const fin = scans.filter(s => styleFilter(s) && s.process === 'Finishing Output').reduce((a, b) => a + b.qty, 0);
        return [o.buyer, o.style, o.po, o.po_qty, cut, sew, wash, fin].map(v => `"${v}"`).join(',');
      });
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* HEADER SUMMARY CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* 1. Cutting Department */}
            <DashboardCard 
              icon="✂️" 
              title="Cutting Department" 
              value={dashboardStats.cuttingDone} 
              color="blue" 
              label="CUT"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true, showProgress: true }
              ]}
            />

            {/* 2. Sewing Production */}
            <DashboardCard 
              icon="🧵" 
              title="Sewing Production" 
              value={dashboardStats.sewingOutput} 
              color="indigo" 
              label="SEW"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.sewingInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.sewingOutput.toLocaleString() },
                { label: 'WIP pieces', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }
              ]}
            />

            {/* 3. Wash Production */}
            <DashboardCard 
              icon="🧼" 
              title="Wash Production" 
              value={dashboardStats.washOutput} 
              color="cyan" 
              label="WSH"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.washInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.washOutput.toLocaleString() },
                { label: 'Daily Target', value: TARGETS.wash.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }
              ]}
            />

            {/* 4. Finishing Production */}
            <DashboardCard 
              icon="🏁" 
              title="Finishing Production" 
              value={dashboardStats.finishingOutput} 
              color="emerald" 
              label="FIN"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.finishingInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.finishingOutput.toLocaleString() },
                { label: 'WIP pieces', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }
              ]}
              footerStatus="Stable"
            />
          </div>

          {/* LINE-WISE PERFORMANCE LEDGER */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div className="mb-4 lg:mb-0">
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Performance (1-15)</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Select Department to view performance</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
                {(['Sewing', 'Wash', 'Finishing'] as const).map(view => (
                  <button 
                    key={view} 
                    onClick={() => setPerformanceView(view)}
                    className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                  >
                    {view}
                  </button>
                ))}
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5">Line</th>
                    <th className="px-8 py-5">Input (pcs)</th>
                    <th className="px-8 py-5">Output (pcs)</th>
                    <th className="px-8 py-5">WIP</th>
                    <th className="px-8 py-5">Efficiency</th>
                    <th className="px-8 py-5 text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                         <div className="flex items-center space-x-3 min-w-[140px]">
                            <div className="flex-1 bg-slate-100 h-1.5 rounded-full overflow-hidden">
                               <div 
                                  className={`h-full transition-all duration-700 ${item.effi < 45 ? 'bg-rose-500' : item.effi < 80 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                                  style={{ width: `${item.effi}%` }}
                               ></div>
                            </div>
                            <span className="text-xs tabular-nums w-8">{item.effi}%</span>
                         </div>
                      </td>
                      <td className="px-8 py-4 text-center">
                         <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                           item.status === 'Good' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                           item.status === 'Fair' ? 'bg-amber-50 text-amber-600 border-amber-100' :
                           'bg-rose-50 text-rose-600 border-rose-100'
                         }`}>{item.status}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>
                    <th className="px-6 py-4">Buyer</th>
                    <th className="px-6 py-4">Style</th>
                    <th className="px-6 py-4">PO</th>
                    <th className="px-6 py-4 text-right">PO Qty</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {orders.map((o) => (
                    <tr key={o.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4">{o.buyer}</td>
                      <td className="px-6 py-4 font-black">{o.style}</td>
                      <td className="px-6 py-4">{o.po}</td>
                      <td className="px-6 py-4 text-right">{o.po_qty.toLocaleString()} pieces</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Input Bundle ID for real-time tracking (pieces).</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input 
                type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} 
                placeholder="PG-..." 
                className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" 
                onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} 
              />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PIECES</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing') || selectedProcess.includes('Wash')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
             <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Audit Trail</h3>
             <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 shadow-lg shadow-green-900/10">Download CSV</button>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                    <tr>
                      <th className="px-8 py-5">Timestamp</th>
                      <th className="px-8 py-5">QR Identifier</th>
                      <th className="px-8 py-5">Department Step</th>
                      <th className="px-8 py-5 text-right">Quantity</th>
                      <th className="px-8 py-5">Line</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                    {scans.slice().reverse().map((scan) => (
                      <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                        <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleString()}</td>
                        <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                        <td className="px-8 py-4">
                          <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                        </td>
                        <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty} pieces</td>
                        <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
  showProgress?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>

       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section Overview</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>

       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-4xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Output (pcs)</p>
       </div>

       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i} className="flex flex-col">
              <p className={`text-base font-black tracking-tight ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mb-1">{m.label}</p>
              {m.showProgress && (
                <div className="w-10 h-1 bg-slate-200/50 rounded-full overflow-hidden mt-0.5">
                   <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: m.value }}></div>
                </div>
              )}
           </div>
         ))}
       </div>

       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v8';

// Enterprise Daily Targets (15 lines * 1000 pieces = 15,000)
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Wash' | 'Finishing'>('Sewing');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyCategory, setHistoryCategory] = useState<'all' | 'cutting' | 'sewing' | 'washing' | 'finishing'>('all');
  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed data for 15 lines across all departments
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting Total
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(TARGETS.cutting * 0.82),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // 15 Lines data generation reflecting 1000pcs target
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;

          // Sewing
          const sIn = Math.floor(800 + Math.random() * 250);
          const sOut = Math.floor(sIn * (0.75 + Math.random() * 0.2));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-IN-L${i}`, process: 'Sewing Input', qty: sIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-OUT-L${i}`, process: 'Sewing Output', qty: sOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Wash
          const wIn = Math.floor(750 + Math.random() * 200);
          const wOut = Math.floor(wIn * (0.8 + Math.random() * 0.15));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `W-IN-L${i}`, process: 'Wash Input', qty: wIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `W-OUT-L${i}`, process: 'Wash Output', qty: wOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Finishing
          const fIn = Math.floor(700 + Math.random() * 200);
          const fOut = Math.floor(fIn * (0.85 + Math.random() * 0.12));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-IN-L${i}`, process: 'Finishing Input', qty: fIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-OUT-L${i}`, process: 'Finishing Output', qty: fOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    const currentTarget = 1000; // 1000 pieces per line target

    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      const effi = Math.min(100, Math.round((output / currentTarget) * 100));

      let status: 'Good' | 'Fair' | 'Critical' = 'Good';
      if (effi < 45) status = 'Critical';
      else if (effi < 80) status = 'Fair';

      return { line, input, output, wip, effi, status };
    });
  }, [scans, performanceView]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing') || selectedProcess.includes('Wash');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Posted ${scanningDetail.bundle_qty} pieces.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["Buyer", "Style", "PO", "PO Qty", "Cut", "Sew", "Wash", "Fin"];
      csvRows = orders.map(o => {
        const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
        const cut = scans.filter(s => styleFilter(s) && s.process === 'Cutting Done').reduce((a, b) => a + b.qty, 0);
        const sew = scans.filter(s => styleFilter(s) && s.process === 'Sewing Output').reduce((a, b) => a + b.qty, 0);
        const wash = scans.filter(s => styleFilter(s) && s.process === 'Wash Output').reduce((a, b) => a + b.qty, 0);
        const fin = scans.filter(s => styleFilter(s) && s.process === 'Finishing Output').reduce((a, b) => a + b.qty, 0);
        return [o.buyer, o.style, o.po, o.po_qty, cut, sew, wash, fin].map(v => `"${v}"`).join(',');
      });
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* HEADER SUMMARY CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* 1. Cutting Department */}
            <DashboardCard 
              icon="✂️" 
              title="Cutting Department" 
              value={dashboardStats.cuttingDone} 
              color="blue" 
              label="CUT"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true, showProgress: true }
              ]}
            />

            {/* 2. Sewing Production */}
            <DashboardCard 
              icon="🧵" 
              title="Sewing Production" 
              value={dashboardStats.sewingOutput} 
              color="indigo" 
              label="SEW"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.sewingInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.sewingOutput.toLocaleString() },
                { label: 'WIP pieces', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }
              ]}
            />

            {/* 3. Wash Production */}
            <DashboardCard 
              icon="🧼" 
              title="Wash Production" 
              value={dashboardStats.washOutput} 
              color="cyan" 
              label="WSH"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.washInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.washOutput.toLocaleString() },
                { label: 'Daily Target', value: TARGETS.wash.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }
              ]}
            />

            {/* 4. Finishing Production */}
            <DashboardCard 
              icon="🏁" 
              title="Finishing Production" 
              value={dashboardStats.finishingOutput} 
              color="emerald" 
              label="FIN"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.finishingInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.finishingOutput.toLocaleString() },
                { label: 'WIP pieces', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }
              ]}
              footerStatus="Stable"
            />
          </div>

          {/* LINE-WISE PERFORMANCE LEDGER */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div className="mb-4 lg:mb-0">
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Performance (1-15)</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Select Department to view performance</p>
              </div>
              <div className="flex items-center space-x-4">
                 <div className="bg-slate-800 px-4 py-2 rounded-xl border border-slate-700 mr-4">
                    <span className="text-xs font-black text-indigo-400 uppercase tracking-widest">Target: 1000 Pcs/Line</span>
                 </div>
                 <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
                    {(['Sewing', 'Wash', 'Finishing'] as const).map(view => (
                      <button 
                        key={view} 
                        onClick={() => setPerformanceView(view)}
                        className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                      >
                        {view}
                      </button>
                    ))}
                 </div>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5">Line</th>
                    <th className="px-8 py-5">Input (pcs)</th>
                    <th className="px-8 py-5">Output (pcs)</th>
                    <th className="px-8 py-5">WIP</th>
                    <th className="px-8 py-5">Efficiency</th>
                    <th className="px-8 py-5 text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                         <div className="flex items-center space-x-3 min-w-[140px]">
                            <div className="flex-1 bg-slate-100 h-1.5 rounded-full overflow-hidden">
                               <div 
                                  className={`h-full transition-all duration-700 ${item.effi < 45 ? 'bg-rose-500' : item.effi < 80 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                                  style={{ width: `${item.effi}%` }}
                               ></div>
                            </div>
                            <span className="text-xs tabular-nums w-8">{item.effi}%</span>
                         </div>
                      </td>
                      <td className="px-8 py-4 text-center">
                         <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                           item.status === 'Good' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                           item.status === 'Fair' ? 'bg-amber-50 text-amber-600 border-amber-100' :
                           'bg-rose-50 text-rose-600 border-rose-100'
                         }`}>{item.status}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>
                    <th className="px-6 py-4">Buyer</th>
                    <th className="px-6 py-4">Style</th>
                    <th className="px-6 py-4">PO</th>
                    <th className="px-6 py-4 text-right">PO Qty</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {orders.map((o) => (
                    <tr key={o.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4">{o.buyer}</td>
                      <td className="px-6 py-4 font-black">{o.style}</td>
                      <td className="px-6 py-4">{o.po}</td>
                      <td className="px-6 py-4 text-right">{o.po_qty.toLocaleString()} pieces</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Input Bundle ID for real-time tracking (pieces).</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input 
                type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} 
                placeholder="PG-..." 
                className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" 
                onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} 
              />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PIECES</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing') || selectedProcess.includes('Wash')) && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
             <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Audit Trail</h3>
             <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 shadow-lg shadow-green-900/10">Download CSV</button>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                    <tr>
                      <th className="px-8 py-5">Timestamp</th>
                      <th className="px-8 py-5">QR Identifier</th>
                      <th className="px-8 py-5">Department Step</th>
                      <th className="px-8 py-5 text-right">Quantity</th>
                      <th className="px-8 py-5">Line</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                    {scans.slice().reverse().map((scan) => (
                      <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                        <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleString()}</td>
                        <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                        <td className="px-8 py-4">
                          <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                        </td>
                        <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty} pieces</td>
                        <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
  showProgress?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>

       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section Overview</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>

       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-4xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Output (pcs)</p>
       </div>

       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i} className="flex flex-col">
              <p className={`text-base font-black tracking-tight ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mb-1">{m.label}</p>
              {m.showProgress && (
                <div className="w-10 h-1 bg-slate-200/50 rounded-full overflow-hidden mt-0.5">
                   <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: m.value }}></div>
                </div>
              )}
           </div>
         ))}
       </div>

       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v9';

// Enterprise Daily Targets (Total Department Goals)
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [historyFilters, setHistoryFilters] = useState({
    qrId: '',
    process: 'all',
    line: 'all',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed data reflecting 15 lines for Sewing/Finishing and N/A for Wash
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting Total
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(TARGETS.cutting * 0.82),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // Wash Total (No lines)
        const wIn = Math.floor(TARGETS.wash * 0.9);
        const wOut = Math.floor(wIn * 0.95);
        demoScans.push({ id: crypto.randomUUID(), qr_id: `W-IN-${order.style}`, process: 'Wash Input', qty: wIn, status: 'C', line: 'N/A', scanned_by: 'Sys', scan_time: nowStr });
        demoScans.push({ id: crypto.randomUUID(), qr_id: `W-OUT-${order.style}`, process: 'Wash Output', qty: wOut, status: 'C', line: 'N/A', scanned_by: 'Sys', scan_time: nowStr });

        // 15 Lines data generation for Sewing and Finishing
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;

          // Sewing
          const sIn = Math.floor(800 + Math.random() * 250);
          const sOut = Math.floor(sIn * (0.8 + Math.random() * 0.15));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-IN-L${i}`, process: 'Sewing Input', qty: sIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-OUT-L${i}`, process: 'Sewing Output', qty: sOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Finishing
          const fIn = Math.floor(700 + Math.random() * 200);
          const fOut = Math.floor(fIn * (0.85 + Math.random() * 0.1));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-IN-L${i}`, process: 'Finishing Input', qty: fIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-OUT-L${i}`, process: 'Finishing Output', qty: fOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      return { line, input, output, wip };
    });
  }, [scans, performanceView]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    // Wash does not have lines
    const isLineProcess = (selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && !selectedProcess.includes('Wash');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Posted ${scanningDetail.bundle_qty} pieces.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["Buyer", "Style", "PO", "PO Qty", "Cut", "Sew", "Wash", "Fin"];
      csvRows = orders.map(o => {
        const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
        const cut = scans.filter(s => styleFilter(s) && s.process === 'Cutting Done').reduce((a, b) => a + b.qty, 0);
        const sew = scans.filter(s => styleFilter(s) && s.process === 'Sewing Output').reduce((a, b) => a + b.qty, 0);
        const wash = scans.filter(s => styleFilter(s) && s.process === 'Wash Output').reduce((a, b) => a + b.qty, 0);
        const fin = scans.filter(s => styleFilter(s) && s.process === 'Finishing Output').reduce((a, b) => a + b.qty, 0);
        return [o.buyer, o.style, o.po, o.po_qty, cut, sew, wash, fin].map(v => `"${v}"`).join(',');
      });
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* HEADER SUMMARY CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            <DashboardCard 
              icon="✂️" 
              title="Cutting Department" 
              value={dashboardStats.cuttingDone} 
              color="blue" 
              label="CUT"
              subMetrics={[
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true, showProgress: true }
              ]}
            />

            <DashboardCard 
              icon="🧵" 
              title="Sewing Production" 
              value={dashboardStats.sewingOutput} 
              color="indigo" 
              label="SEW"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.sewingInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.sewingOutput.toLocaleString() },
                { label: 'WIP pieces', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }
              ]}
            />

            <DashboardCard 
              icon="🧼" 
              title="Wash Production" 
              value={dashboardStats.washOutput} 
              color="cyan" 
              label="WSH"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.washInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.washOutput.toLocaleString() },
                { label: 'Daily Target', value: TARGETS.wash.toLocaleString() },
                { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }
              ]}
            />

            <DashboardCard 
              icon="🏁" 
              title="Finishing Production" 
              value={dashboardStats.finishingOutput} 
              color="emerald" 
              label="FIN"
              subMetrics={[
                { label: 'Total Input', value: dashboardStats.finishingInput.toLocaleString() },
                { label: 'Total Output', value: dashboardStats.finishingOutput.toLocaleString() },
                { label: 'WIP pieces', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() },
                { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }
              ]}
              footerStatus="Stable"
            />
          </div>

          {/* LINE-WISE PERFORMANCE LEDGER (Excluding Wash) */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div className="mb-4 lg:mb-0">
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Performance (1-15)</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time throughput analysis</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button 
                    key={view} 
                    onClick={() => setPerformanceView(view)}
                    className={`px-8 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                  >
                    {view}
                  </button>
                ))}
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5">Line</th>
                    <th className="px-8 py-5">Input (pcs)</th>
                    <th className="px-8 py-5">Output (pcs)</th>
                    <th className="px-8 py-5">WIP</th>
                    <th className="px-8 py-5">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                         <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                           item.output > 0 ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'
                         }`}>
                           {item.output > 0 ? 'Active' : 'Idle'}
                         </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Orders Master</h3>
            <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest border-b border-slate-100">
                  <tr>
                    <th className="px-6 py-4">Buyer</th>
                    <th className="px-6 py-4">Style</th>
                    <th className="px-6 py-4">PO</th>
                    <th className="px-6 py-4 text-right">PO Qty</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {orders.map((o) => (
                    <tr key={o.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4">{o.buyer}</td>
                      <td className="px-6 py-4 font-black">{o.style}</td>
                      <td className="px-6 py-4">{o.po}</td>
                      <td className="px-6 py-4 text-right">{o.po_qty.toLocaleString()} pieces</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8">Input Bundle ID for real-time tracking (pieces).</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input 
                type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} 
                placeholder="PG-..." 
                className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest" 
                onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} 
              />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition active:scale-95">IDENTIFY</button>
            </div>
            {scanStatus.message && (
              <div className={`mt-4 inline-block px-4 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {scanStatus.message}
              </div>
            )}
          </div>
          {scanningDetail && (
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden animate-slideUp border border-slate-100">
              <div className="bg-slate-950 text-white p-6 flex justify-between items-center">
                <div>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BUNDLE ID</p>
                  <p className="text-2xl font-black tracking-tighter">{scanningDetail.qr_id}</p>
                </div>
                <div className="bg-blue-600 px-6 py-3 rounded-2xl text-center shadow-lg shadow-blue-500/20">
                  <p className="text-[10px] font-black uppercase tracking-widest text-blue-100">PIECES</p>
                  <p className="text-2xl font-black leading-none">{scanningDetail.bundle_qty}</p>
                </div>
              </div>
              <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="grid grid-cols-2 gap-6">
                  <DetailItem label="Buyer" value={scanningDetail.buyer} />
                  <DetailItem label="Style" value={scanningDetail.style} />
                  <DetailItem label="Spec" value={`${scanningDetail.color} / ${scanningDetail.size}`} />
                  <DetailItem label="PO#" value={scanningDetail.po} />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Process Step</label>
                    <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                      {PROCESS_FLOW.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  {/* Line selection only for Sewing and Finishing, NOT Wash */}
                  {(selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && !selectedProcess.includes('Wash') && (
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Production Line</label>
                      <select value={selectedLine} onChange={(e) => setSelectedLine(e.target.value)} className="w-full bg-white border-2 border-slate-200 rounded-xl p-3 font-black text-slate-700 outline-none">
                        {Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`).map(l => <option key={l} value={l}>{l}</option>)}
                      </select>
                    </div>
                  )}
                  <button onClick={handleScanSubmit} className="w-full bg-blue-600 text-white py-4 rounded-xl font-black hover:bg-blue-700 transition active:scale-95 shadow-xl shadow-blue-500/20">POST TRANSACTION ⚡</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
             <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Audit Trail</h3>
             <button onClick={() => handleDownloadExcel('history')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest active:scale-95 shadow-lg shadow-green-900/10">Download CSV</button>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                    <tr>
                      <th className="px-8 py-5">Timestamp</th>
                      <th className="px-8 py-5">QR Identifier</th>
                      <th className="px-8 py-5">Department Step</th>
                      <th className="px-8 py-5 text-right">Quantity</th>
                      <th className="px-8 py-5">Line</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                    {scans.slice().reverse().map((scan) => (
                      <tr key={scan.id} className="hover:bg-blue-50/20 transition-colors">
                        <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleString()}</td>
                        <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                        <td className="px-8 py-4">
                          <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${scan.process.includes('Input') ? 'bg-blue-50 text-blue-600' : 'bg-green-50 text-green-600'}`}>{scan.process}</span>
                        </td>
                        <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty} pieces</td>
                        <td className="px-8 py-4 text-xs font-bold text-slate-500">{scan.line}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
  showProgress?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>

       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section Overview</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>

       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-4xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Output (pcs)</p>
       </div>

       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i} className="flex flex-col">
              <p className={`text-base font-black tracking-tight ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mb-1">{m.label}</p>
              {m.showProgress && (
                <div className="w-10 h-1 bg-slate-200/50 rounded-full overflow-hidden mt-0.5">
                   <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: m.value }}></div>
                </div>
              )}
           </div>
         ))}
       </div>

       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

const DetailItem: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-lg font-black text-slate-800 tracking-tight">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v10';

// Enterprise Daily Targets (Total Department Goals)
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string>(PROCESS_FLOW[0]);
  const [selectedLine, setSelectedLine] = useState<string>('Line-1');
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // Filters for Orders Tab
  const [orderFilters, setOrderFilters] = useState({
    buyer: '',
    style: '',
    po: '',
    color: ''
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Seed data reflecting 15 lines for Sewing/Finishing and N/A for Wash
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        // Cutting Total
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(TARGETS.cutting * 0.82),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        // Wash Total (No lines)
        const wIn = Math.floor(TARGETS.wash * 0.9);
        const wOut = Math.floor(wIn * 0.95);
        demoScans.push({ id: crypto.randomUUID(), qr_id: `W-IN-${order.style}`, process: 'Wash Input', qty: wIn, status: 'C', line: 'N/A', scanned_by: 'Sys', scan_time: nowStr });
        demoScans.push({ id: crypto.randomUUID(), qr_id: `W-OUT-${order.style}`, process: 'Wash Output', qty: wOut, status: 'C', line: 'N/A', scanned_by: 'Sys', scan_time: nowStr });

        // 15 Lines data generation for Sewing and Finishing
        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;

          // Sewing
          const sIn = Math.floor(800 + Math.random() * 250);
          const sOut = Math.floor(sIn * (0.8 + Math.random() * 0.15));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-IN-L${i}-${order.style}`, process: 'Sewing Input', qty: sIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-OUT-L${i}-${order.style}`, process: 'Sewing Output', qty: sOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });

          // Finishing
          const fIn = Math.floor(700 + Math.random() * 200);
          const fOut = Math.floor(fIn * (0.85 + Math.random() * 0.1));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-IN-L${i}-${order.style}`, process: 'Finishing Input', qty: fIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `F-OUT-L${i}-${order.style}`, process: 'Finishing Output', qty: fOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      return { line, input, output, wip };
    });
  }, [scans, performanceView]);

  const filteredOrders = useMemo(() => {
    return orders.filter(o => {
      const matchBuyer = !orderFilters.buyer || o.buyer.toLowerCase().includes(orderFilters.buyer.toLowerCase());
      const matchStyle = !orderFilters.style || o.style.toLowerCase().includes(orderFilters.style.toLowerCase());
      const matchPO = !orderFilters.po || o.po.toLowerCase().includes(orderFilters.po.toLowerCase());
      const matchColor = !orderFilters.color || o.color.toLowerCase().includes(orderFilters.color.toLowerCase());
      return matchBuyer && matchStyle && matchPO && matchColor;
    });
  }, [orders, orderFilters]);

  const aggregatedOrdersData = useMemo(() => {
    return filteredOrders.map(o => {
      const styleFilter = (s: ScanningData) => s.qr_id.includes(o.style);
      const getP = (p: string) => scans.filter(s => styleFilter(s) && s.process === p).reduce((sum, item) => sum + item.qty, 0);

      return {
        ...o,
        cut: getP('Cutting Done'),
        sewIn: getP('Sewing Input'),
        sewOut: getP('Sewing Output'),
        washIn: getP('Wash Input'),
        washOut: getP('Wash Output'),
        finIn: getP('Finishing Input'),
        finOut: getP('Finishing Output')
      };
    });
  }, [filteredOrders, scans]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;
    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }
    if (normalizedQR.startsWith('PG-')) {
       const defaultOrder = orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: defaultOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...defaultOrder
       });
       setScanStatus({ message: 'Dynamic QR Initialized.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'QR not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleScanSubmit = () => {
    if (!scanningDetail) return;
    const isLineProcess = (selectedProcess.includes('Sewing') || selectedProcess.includes('Finishing')) && !selectedProcess.includes('Wash');
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: selectedProcess,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: isLineProcess ? selectedLine : 'N/A',
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Success: Posted ${scanningDetail.bundle_qty} pieces.`, type: 'success' });
    setCurrentQR('');
    setScanningDetail(null);
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty", "Cut", "Sew In", "Sew Out", "Wash In", "Wash Out", "Fin In", "Fin Out"];
      csvRows = aggregatedOrdersData.map(o => [
        o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty,
        o.cut, o.sewIn, o.sewOut, o.washIn, o.washOut, o.finIn, o.finOut
      ].map(v => `"${v}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

