interface Metric {
  label: string;
  value: string;
  highlight?: boolean;
  showProgress?: boolean;
}

const DashboardCard: React.FC<{ 
  icon: string, 
  title: string, 
  value: number, 
  color: 'blue' | 'indigo' | 'cyan' | 'emerald', 
  label: string, 
  subMetrics: Metric[],
  footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = {
    blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40',
    indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40',
    cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40',
    emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40'
  };

  const currentTheme = themes[color];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}>
         <span className="text-8xl font-black">{label}</span>
       </div>
       <div className="flex items-center space-x-4 mb-6 relative z-10">
         <div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div>
         <div>
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section Overview</h4>
            <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
         </div>
       </div>
       <div className="space-y-1 mb-6 relative z-10">
         <p className={`text-4xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p>
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Output (pcs)</p>
       </div>
       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i} className="flex flex-col">
              <p className={`text-base font-black tracking-tight ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mb-1">{m.label}</p>
              {m.showProgress && (
                <div className="w-10 h-1 bg-slate-200/50 rounded-full overflow-hidden mt-0.5">
                   <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: m.value }}></div>
                </div>
              )}
           </div>
         ))}
       </div>
       <div className="mt-6 flex justify-between items-center relative z-10">
          <span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>
            {footerStatus ? '● ' + footerStatus : 'Pioneer Group'}
          </span>
          <div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden">
             <div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div>
          </div>
       </div>
    </div>
  );
};

