const DashboardCard: React.FC<{ 
  icon: string, title: string, value: number, color: 'blue' | 'indigo' | 'cyan' | 'emerald', label: string, subMetrics: any[], footerStatus?: string
}> = ({ icon, title, value, color, label, subMetrics, footerStatus }) => {
  const themes = { blue: 'text-blue-600 border-t-blue-500 bg-blue-50/40', indigo: 'text-indigo-600 border-t-indigo-500 bg-indigo-50/40', cyan: 'text-cyan-600 border-t-cyan-500 bg-cyan-50/40', emerald: 'text-emerald-600 border-t-emerald-500 bg-emerald-50/40' };
  const currentTheme = themes[color];
  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300 group overflow-hidden relative border-t-4 ${currentTheme}`}>
       <div className={`absolute -right-4 -top-4 ${currentTheme.split(' ')[0]} opacity-[0.05] group-hover:opacity-[0.1] transition-opacity`}><span className="text-8xl font-black">{label}</span></div>
       <div className="flex items-center space-x-4 mb-6 relative z-10"><div className={`w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl`}>{icon}</div><div><h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section Overview</h4><p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p></div></div>
       <div className="space-y-1 mb-6 relative z-10"><p className={`text-4xl font-black tracking-tighter ${currentTheme.split(' ')[0]}`}>{value.toLocaleString()}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Output (pcs)</p></div>
       <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
         {subMetrics.map((m, i) => (
           <div key={i} className="flex flex-col"><p className={`text-base font-black tracking-tight ${m.highlight ? currentTheme.split(' ')[0] : 'text-slate-800'}`}>{m.value}</p><p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mb-1">{m.label}</p>
              {m.showProgress && (<div className="w-10 h-1 bg-slate-200/50 rounded-full overflow-hidden mt-0.5"><div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: m.value }}></div></div>)}
           </div>
         ))}
       </div>
       <div className="mt-6 flex justify-between items-center relative z-10"><span className={`text-[10px] font-black uppercase tracking-widest ${footerStatus ? 'text-emerald-500' : 'text-slate-300'}`}>{footerStatus ? '● ' + footerStatus : 'Pioneer Group'}</span><div className="w-16 h-1.5 bg-slate-200/50 rounded-full overflow-hidden"><div className={`h-full ${currentTheme.replace('text-', 'bg-').split(' ')[0]}`} style={{ width: '70%' }}></div></div></div>
    </div>
  );
};

const FilterButton: React.FC<{ label: string, active: boolean, onClick: () => void, color: string }> = ({ label, active, onClick, color }) => {
  const colorMap: any = {
    blue: active ? 'bg-blue-600 text-white shadow-md' : 'text-blue-600 hover:bg-blue-50',
    indigo: active ? 'bg-indigo-600 text-white shadow-md' : 'text-indigo-600 hover:bg-indigo-50',
    cyan: active ? 'bg-cyan-600 text-white shadow-md' : 'text-cyan-600 hover:bg-cyan-50',
    emerald: active ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600 hover:bg-emerald-50',
    slate: active ? 'bg-slate-800 text-white shadow-md' : 'text-slate-600 hover:bg-slate-200',
  };
  return (
    <button onClick={onClick} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${colorMap[color] || colorMap.slate}`}>
      {label}
    </button>
  );
};

const SearchInput: React.FC<{ label: string, icon?: string, value: string, onChange: (v: string) => void }> = ({ label, icon, value, onChange }) => (
  <div className="flex flex-col">
    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">{label}</label>
    <div className="relative">
      {icon && <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs grayscale opacity-50">{icon}</span>}
      <input 
        type="text" 
        value={value} 
        onChange={(e) => onChange(e.target.value)}
        placeholder={`Search...`}
        className={`w-full bg-white border border-slate-200 rounded-xl ${icon ? 'pl-9' : 'px-4'} py-2 text-xs font-bold text-black outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 transition-all`}
      />
    </div>
  </div>
);

const DetailItemDark: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div>
    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-sm font-black text-white tracking-tight break-words">{value}</p>
  </div>
);

export default App;

export interface OrderMaster {
  id: string;
  buyer: string;
  style: string;
  po: string;
  color: string;
  country: string;
  size: string;
  po_qty: number;
  created_at: string;
}

export interface QRMaster {
  qr_id: string;
  order_id: string;
  bundle_qty: number;
  created_at: string;
}

export interface ScanningData {
  id: string;
  qr_id: string;
  process: string;
  qty: number;
  status: string;
  line: string;
  scanned_by: string;
  scan_time: string;
}

// Fixed: QRDetail now includes po_qty to match the joined data structure in App.tsx
export interface QRDetail extends QRMaster {
  buyer: string;
  style: string;
  po: string;
  color: string;
  country: string;
  size: string;
  po_qty: number;
}

export enum ProductionProcess {
  CUTTING_DONE = 'Cutting Done',
  SEWING_INPUT = 'Sewing Input',
  SEWING_OUTPUT = 'Sewing Output',
  WASH_INPUT = 'Wash Input',
  WASH_OUTPUT = 'Wash Output',
  FINISHING_INPUT = 'Finishing Input',
  FINISHING_OUTPUT = 'Finishing Output'
}

export enum ProductionStatus {
  COMPLETED = 'Completed',
  PENDING = 'Pending',
  REJECTED = 'Rejected'
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v11';

// Enterprise Daily Targets (Total Department Goals)
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  // Search Filters for Orders Tab
  const [orderSearch, setOrderSearch] = useState({
    buyer: '',
    style: '',
    po: '',
    qr: ''
  });

  // Search Filter for History Tab
  const [historySearch, setHistorySearch] = useState('');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Initial demo data generation
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];

      MOCK_ORDERS.forEach((order) => {
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-CUT-${order.style}`,
          process: 'Cutting Done',
          qty: Math.floor(TARGETS.cutting * 0.82),
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });

        const wIn = Math.floor(TARGETS.wash * 0.9);
        const wOut = Math.floor(wIn * 0.95);
        demoScans.push({ id: crypto.randomUUID(), qr_id: `W-IN-${order.style}`, process: 'Wash Input', qty: wIn, status: 'C', line: 'N/A', scanned_by: 'Sys', scan_time: nowStr });
        demoScans.push({ id: crypto.randomUUID(), qr_id: `W-OUT-${order.style}`, process: 'Wash Output', qty: wOut, status: 'C', line: 'N/A', scanned_by: 'Sys', scan_time: nowStr });

        for (let i = 1; i <= 15; i++) {
          const line = `Line-${i}`;
          const sIn = Math.floor(800 + Math.random() * 250);
          const sOut = Math.floor(sIn * (0.8 + Math.random() * 0.15));
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-IN-L${i}-${order.style}`, process: 'Sewing Input', qty: sIn, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
          demoScans.push({ id: crypto.randomUUID(), qr_id: `S-OUT-L${i}-${order.style}`, process: 'Sewing Output', qty: sOut, status: 'C', line, scanned_by: 'Sys', scan_time: nowStr });
        }
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    return {
      cuttingDone: getSum('Cutting Done'),
      sewingInput: getSum('Sewing Input'),
      sewingOutput: getSum('Sewing Output'),
      washInput: getSum('Wash Input'),
      washOutput: getSum('Wash Output'),
      finishingInput: getSum('Finishing Input'),
      finishingOutput: getSum('Finishing Output'),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      return { line, input, output, wip };
    });
  }, [scans, performanceView]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([
      ...qrCodes.map(q => q.qr_id),
      ...scans.map(s => s.qr_id)
    ]));

    return allUniqueQRs
      .map(qrId => {
        const masterQR = qrCodes.find(q => q.qr_id === qrId);
        const masterOrder = masterQR 
          ? orders.find(o => o.id === masterQR.order_id)
          : orders.find(o => qrId.includes(o.style)); 

        if (!masterOrder) return null;

        const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);

        return {
          qr_unique_id: qrId,
          timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
          buyer: masterOrder.buyer,
          style: masterOrder.style,
          po: masterOrder.po,
          country: masterOrder.country,
          color: masterOrder.color,
          size: masterOrder.size,
          po_qty: masterOrder.po_qty, // PO Total Qty
          bundle_qty: masterQR?.bundle_qty || 100, // Specific Bundle Qty
          cut: getP('Cutting Done'),
          sewIn: getP('Sewing Input'),
          sewOut: getP('Sewing Output'),
          washIn: getP('Wash Input'),
          washOut: getP('Wash Output'),
          finIn: getP('Finishing Input'),
          finOut: getP('Finishing Output')
        };
      })
      .filter((item): item is NonNullable<typeof item> => item !== null)
      .filter(item => {
        const matchBuyer = !orderSearch.buyer || item.buyer.toLowerCase().includes(orderSearch.buyer.toLowerCase());
        const matchStyle = !orderSearch.style || item.style.toLowerCase().includes(orderSearch.style.toLowerCase());
        const matchPO = !orderSearch.po || item.po.toLowerCase().includes(orderSearch.po.toLowerCase());
        const matchQR = !orderSearch.qr || item.qr_unique_id.toLowerCase().includes(orderSearch.qr.toLowerCase());
        return matchBuyer && matchStyle && matchPO && matchQR;
      });
  }, [orders, qrCodes, scans, orderSearch]);

  const filteredHistory = useMemo(() => {
    if (!historySearch) return scans;
    const term = historySearch.toLowerCase();
    return scans.filter(s => 
      s.qr_id.toLowerCase().includes(term) || 
      s.process.toLowerCase().includes(term) || 
      s.line.toLowerCase().includes(term)
    );
  }, [scans, historySearch]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style)) || orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...matchingOrder
       });
       setScanStatus({ message: 'Tracking New Bundle.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Unique Bundle ID not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleQuickPost = (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;
    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Successfully posted ${scanningDetail.bundle_qty} pcs to ${process} ${line !== 'N/A' ? '(' + line + ')' : ''}`, type: 'success' });

    // Auto clear after short delay or keep for continuous scanning
    // setCurrentQR('');
    // setScanningDetail(null);
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      const isAll = activeOrderFilter === 'all';
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty"];
      if (isAll || activeOrderFilter === 'cutting') headers.push("Cut");
      if (isAll || activeOrderFilter === 'sewing') { headers.push("Sew In"); headers.push("Sew Out"); }
      if (isAll || activeOrderFilter === 'wash') { headers.push("Wash In"); headers.push("Wash Out"); }
      if (isAll || activeOrderFilter === 'finishing') { headers.push("Fin In"); headers.push("Fin Out"); }

      csvRows = aggregatedOrdersData.map(o => {
        const row = [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty];
        if (isAll || activeOrderFilter === 'cutting') row.push(o.cut);
        if (isAll || activeOrderFilter === 'sewing') { row.push(o.sewIn); row.push(o.sewOut); }
        if (isAll || activeOrderFilter === 'wash') { row.push(o.washIn); row.push(o.washOut); }
        if (isAll || activeOrderFilter === 'finishing') { row.push(o.finIn); row.push(o.finOut); }
        return row.map(v => `"${v}"`).join(',');
      });
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = filteredHistory.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${activeOrderFilter}_${type}_${Date.now()}.csv`;
    link.click();
  };

  const showCut = activeOrderFilter === 'all' || activeOrderFilter === 'cutting';
  const showSew = activeOrderFilter === 'all' || activeOrderFilter === 'sewing';
  const showWash = activeOrderFilter === 'all' || activeOrderFilter === 'wash';
  const showFin = activeOrderFilter === 'all' || activeOrderFilter === 'finishing';

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Department" value={dashboardStats.cuttingDone} color="blue" label="CUT" subMetrics={[{ label: 'Daily Target', value: TARGETS.cutting.toLocaleString() }, { label: 'Status %', value: `${Math.round((dashboardStats.cuttingDone / TARGETS.cutting) * 100)}%`, highlight: true, showProgress: true }]} />
            <DashboardCard icon="🧵" title="Sewing Production" value={dashboardStats.sewingOutput} color="indigo" label="SEW" subMetrics={[{ label: 'Total Input', value: dashboardStats.sewingInput.toLocaleString() }, { label: 'Total Output', value: dashboardStats.sewingOutput.toLocaleString() }, { label: 'WIP pieces', value: Math.max(0, dashboardStats.sewingInput - dashboardStats.sewingOutput).toLocaleString() }, { label: 'Efficiency', value: `${Math.round((dashboardStats.sewingOutput / TARGETS.sewing) * 100)}%`, highlight: true }]} />
            <DashboardCard icon="🧼" title="Wash Production" value={dashboardStats.washOutput} color="cyan" label="WSH" subMetrics={[{ label: 'Total Input', value: dashboardStats.washInput.toLocaleString() }, { label: 'Total Output', value: dashboardStats.washOutput.toLocaleString() }, { label: 'Daily Target', value: TARGETS.wash.toLocaleString() }, { label: 'Status %', value: `${Math.round((dashboardStats.washOutput / TARGETS.wash) * 100)}%`, highlight: true }]} />
            <DashboardCard icon="🏁" title="Finishing Production" value={dashboardStats.finishingOutput} color="emerald" label="FIN" subMetrics={[{ label: 'Total Input', value: dashboardStats.finishingInput.toLocaleString() }, { label: 'Total Output', value: dashboardStats.finishingOutput.toLocaleString() }, { label: 'WIP pieces', value: Math.max(0, dashboardStats.finishingInput - dashboardStats.finishingOutput).toLocaleString() }, { label: 'Efficiency', value: `${Math.round((dashboardStats.finishingOutput / TARGETS.finishing) * 100)}%`, highlight: true }]} footerStatus="Stable" />
          </div>

          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div className="mb-4 lg:mb-0">
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Performance (1-15)</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time throughput analysis</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-8 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line</th><th className="px-8 py-5">Input (pcs)</th><th className="px-8 py-5">Output (pcs)</th><th className="px-8 py-5">WIP</th><th className="px-8 py-5">Status</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4"><span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${item.output > 0 ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>{item.output > 0 ? 'Active' : 'Idle'}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          {/* FILTERS & SEARCH */}
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
              <div>
                <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Production Master</h3>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-1">Unified records for every bundle and style</p>
              </div>
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 transition active:scale-95 shadow-lg shadow-green-900/10">Download Excel</button>
            </div>

            <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-6 pt-4 border-t border-slate-100">
              <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 rounded-2xl w-fit border border-slate-100">
                <FilterButton label="All" active={activeOrderFilter === 'all'} onClick={() => setActiveOrderFilter('all')} color="slate" />
                <FilterButton label="Cutting" active={activeOrderFilter === 'cutting'} onClick={() => setActiveOrderFilter('cutting')} color="blue" />
                <FilterButton label="Sewing" active={activeOrderFilter === 'sewing'} onClick={() => setActiveOrderFilter('sewing')} color="indigo" />
                <FilterButton label="Wash" active={activeOrderFilter === 'wash'} onClick={() => setActiveOrderFilter('wash')} color="cyan" />
                <FilterButton label="Finishing" active={activeOrderFilter === 'finishing'} onClick={() => setActiveOrderFilter('finishing')} color="emerald" />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 flex-1">
                <SearchInput label="Bundle ID" icon="🔍" value={orderSearch.qr} onChange={(v) => setOrderSearch(prev => ({...prev, qr: v}))} />
                <SearchInput label="Buyer" value={orderSearch.buyer} onChange={(v) => setOrderSearch(prev => ({...prev, buyer: v}))} />
                <SearchInput label="Style" value={orderSearch.style} onChange={(v) => setOrderSearch(prev => ({...prev, style: v}))} />
                <SearchInput label="PO#" value={orderSearch.po} onChange={(v) => setOrderSearch(prev => ({...prev, po: v}))} />
              </div>
            </div>
          </div>

          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest border-b border-slate-800">
                  <tr>
                    <th className="px-4 py-5 sticky left-0 bg-slate-900 z-10">QR Code</th>
                    <th className="px-4 py-5">Updated</th>
                    <th className="px-4 py-5">Buyer</th>
                    <th className="px-4 py-5">Style</th>
                    <th className="px-4 py-5">PO</th>
                    <th className="px-4 py-5">Color/Size</th>
                    <th className="px-4 py-5 text-right">Qty</th>
                    {showCut && <th className="px-4 py-5 text-center bg-blue-900/30">Cut</th>}
                    {showSew && <><th className="px-4 py-5 text-center bg-indigo-900/30">Sew In</th><th className="px-4 py-5 text-center bg-indigo-900/30">Sew Out</th></>}
                    {showWash && <><th className="px-4 py-5 text-center bg-cyan-900/30">Wash In</th><th className="px-4 py-5 text-center bg-cyan-900/30">Wash Out</th></>}
                    {showFin && <><th className="px-4 py-5 text-center bg-emerald-900/30">Fin In</th><th className="px-4 py-5 text-center bg-emerald-900/30">Fin Out</th></>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[11px] font-bold text-slate-700">
                  {aggregatedOrdersData.map((o) => (
                    <tr key={o.qr_unique_id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-4 py-4 font-black text-slate-900 sticky left-0 bg-white group-hover:bg-slate-50 transition-colors">
                        <span className="bg-slate-100 px-2 py-1 rounded text-[10px] tabular-nums border border-slate-200">{o.qr_unique_id}</span>
                      </td>
                      <td className="px-4 py-4 text-slate-400 whitespace-nowrap">
                        {new Date(o.timestamp).toLocaleDateString()} <span className="text-[10px] opacity-60 ml-1">{new Date(o.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                      </td>
                      <td className="px-4 py-4">{o.buyer}</td>
                      <td className="px-4 py-4 font-black text-blue-600">{o.style}</td>
                      <td className="px-4 py-4">{o.po}</td>
                      <td className="px-4 py-4"><span className="px-2 py-0.5 bg-slate-100 rounded text-slate-600">{o.color} / {o.size}</span></td>
