                </div>
              </div>

              {/* Functional Controls Grid */}
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                <div className="space-y-6">
                  {/* Step 1: Cutting */}
                  <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-5 text-4xl group-hover:opacity-10 transition-opacity">✂️</div>
                    <h4 className="text-xs font-black uppercase text-slate-400 mb-6 tracking-[0.2em] flex items-center">SECTION 01: CUTTING</h4>
                    <button 
                      onClick={() => handleQuickPost('Cutting Done')} 
                      className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-sm transition-all shadow-md active:scale-95 ${!lastCompletedProcess ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-slate-50 text-slate-300 cursor-not-allowed border border-slate-100'}`}
                    >
                      Post Cutting Done
