export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v11';

// Enterprise Daily Targets (Total Department Goals)
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  // Fix: Define visibility flags based on active filter to resolve missing variable errors in the table header and body
  const showCut = activeOrderFilter === 'all' || activeOrderFilter === 'cutting';
  const showSew = activeOrderFilter === 'all' || activeOrderFilter === 'sewing';
  const showWash = activeOrderFilter === 'all' || activeOrderFilter === 'wash';
  const showFin = activeOrderFilter === 'all' || activeOrderFilter === 'finishing';

  const [orderSearch, setOrderSearch] = useState({
    buyer: '',
    style: '',
    po: '',
    qr: ''
  });

  const [historySearch, setHistorySearch] = useState('');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Initial demo data generation
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];
      MOCK_ORDERS.forEach((order) => {
        // Mock some starting data for the dashboard
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-DEMO-${order.style}`,
          process: 'Cutting Done',
          qty: 2500,
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cut = getSum('Cutting Done');
    const sewIn = getSum('Sewing Input');
    const sewOut = getSum('Sewing Output');
    const washIn = getSum('Wash Input');
    const washOut = getSum('Wash Output');
    const finIn = getSum('Finishing Input');
    const finOut = getSum('Finishing Output');

    return {
      cutting: cut,
      sewingIn: sewIn,
      sewingOut: sewOut,
      washIn: washIn,
      washOut: washOut,
      finIn: finIn,
      finOut: finOut,
      // Sequential WIP Calculations
      sewingWIP: cut - sewIn,
      washWIP: sewOut - washIn,
      finishingWIP: washOut - finIn,
      // Efficiencies
      cutEff: Math.min(100, Math.round((cut / TARGETS.cutting) * 100)),
      sewEff: Math.min(100, Math.round((sewOut / TARGETS.sewing) * 100)),
      washEff: Math.min(100, Math.round((washOut / TARGETS.wash) * 100)),
      finEff: Math.min(100, Math.round((finOut / TARGETS.finishing) * 100)),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      return { line, input, output, wip };
    });
  }, [scans, performanceView]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([
      ...qrCodes.map(q => q.qr_id),
      ...scans.map(s => s.qr_id)
    ]));

    return allUniqueQRs
      .map(qrId => {
        const masterQR = qrCodes.find(q => q.qr_id === qrId);
        const masterOrder = masterQR 
          ? orders.find(o => o.id === masterQR.order_id)
          : orders.find(o => qrId.includes(o.style)); 

        if (!masterOrder) return null;
        const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);

        return {
          qr_unique_id: qrId,
          timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
          buyer: masterOrder.buyer,
          style: masterOrder.style,
          po: masterOrder.po,
          country: masterOrder.country,
          color: masterOrder.color,
          size: masterOrder.size,
          po_qty: masterOrder.po_qty,
          bundle_qty: masterQR?.bundle_qty || 100,
          cut: getP('Cutting Done'),
          sewIn: getP('Sewing Input'),
          sewOut: getP('Sewing Output'),
          washIn: getP('Wash Input'),
          washOut: getP('Wash Output'),
          finIn: getP('Finishing Input'),
          finOut: getP('Finishing Output')
        };
      })
      .filter((item): item is NonNullable<typeof item> => item !== null)
      .filter(item => {
        const matchBuyer = !orderSearch.buyer || item.buyer.toLowerCase().includes(orderSearch.buyer.toLowerCase());
        const matchStyle = !orderSearch.style || item.style.toLowerCase().includes(orderSearch.style.toLowerCase());
        const matchPO = !orderSearch.po || item.po.toLowerCase().includes(orderSearch.po.toLowerCase());
        const matchQR = !orderSearch.qr || item.qr_unique_id.toLowerCase().includes(orderSearch.qr.toLowerCase());
        return matchBuyer && matchStyle && matchPO && matchQR;
      });
  }, [orders, qrCodes, scans, orderSearch]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans
      .filter(s => s.qr_id === scanningDetail.qr_id)
      .sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => {
    if (qrProductionHistory.length === 0) return null;
    return qrProductionHistory[qrProductionHistory.length - 1].process;
  }, [qrProductionHistory]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style)) || orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...matchingOrder
       });
       setScanStatus({ message: 'Tracking New Bundle.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Unique Bundle ID not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleQuickPost = (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;

    const sequence = [
      'Cutting Done',
      'Sewing Input',
      'Sewing Output',
      'Wash Input',
      'Wash Output',
      'Finishing Input',
      'Finishing Output'
    ];

    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    // Sequential Check
    if (currentIndex !== lastIndex + 1) {
      if (currentIndex <= lastIndex) {
        setScanStatus({ message: `Already completed ${process}.`, type: 'error' });
        return;
      }
      setScanStatus({ message: `Missing intermediate steps. Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Successfully posted ${process}!`, type: 'success' });
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      const isAll = activeOrderFilter === 'all';
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty"];
      if (isAll || activeOrderFilter === 'cutting') headers.push("Cut");
      if (isAll || activeOrderFilter === 'sewing') { headers.push("Sew In"); headers.push("Sew Out"); }
      if (isAll || activeOrderFilter === 'wash') { headers.push("Wash In"); headers.push("Wash Out"); }
      if (isAll || activeOrderFilter === 'finishing') { headers.push("Fin In"); headers.push("Fin Out"); }

      csvRows = aggregatedOrdersData.map(o => {
        const row = [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty];
        if (isAll || activeOrderFilter === 'cutting') row.push(o.cut);
        if (isAll || activeOrderFilter === 'sewing') { row.push(o.sewIn); row.push(o.sewOut); }
        if (isAll || activeOrderFilter === 'wash') { row.push(o.washIn); row.push(o.washOut); }
        if (isAll || activeOrderFilter === 'finishing') { row.push(o.finIn); row.push(o.finOut); }
        return row.map(v => `"${v}"`).join(',');
      });
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.filter(s => !historySearch || s.qr_id.toLowerCase().includes(historySearch.toLowerCase())).map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* Main Department KPIs */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard 
              icon="✂️" title="Cutting Dept" value={dashboardStats.cutting} color="blue" label="CUT" 
              subMetrics={[
                { label: 'Efficiency %', value: `${dashboardStats.cutEff}%`, highlight: true, showProgress: true },
                { label: 'Daily Target', value: TARGETS.cutting.toLocaleString() }
              ]} 
            />
            <DashboardCard 
              icon="🧵" title="Sewing Floor" value={dashboardStats.sewingOut} color="indigo" label="SEW" 
              subMetrics={[
                { label: 'Efficiency %', value: `${dashboardStats.sewEff}%`, highlight: true, showProgress: true },
                { label: 'WIP from Cut', value: Math.max(0, dashboardStats.sewingWIP).toLocaleString() }
              ]} 
            />
            <DashboardCard 
              icon="🧼" title="Wash Plant" value={dashboardStats.washOut} color="cyan" label="WSH" 
              subMetrics={[
                { label: 'Efficiency %', value: `${dashboardStats.washEff}%`, highlight: true, showProgress: true },
                { label: 'WIP from Sew', value: Math.max(0, dashboardStats.washWIP).toLocaleString() }
              ]} 
            />
            <DashboardCard 
              icon="🏁" title="Finishing/Pack" value={dashboardStats.finOut} color="emerald" label="FIN" 
              subMetrics={[
                { label: 'Efficiency %', value: `${dashboardStats.finEff}%`, highlight: true, showProgress: true },
                { label: 'WIP from Wash', value: Math.max(0, dashboardStats.finishingWIP).toLocaleString() }
              ]} 
            />
          </div>

          {/* Line Performance Table */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div>
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Throughput Analysis</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time status of production lines</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700 mt-4 lg:mt-0">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-8 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line ID</th><th className="px-8 py-5">Input (pcs)</th><th className="px-8 py-5">Output (pcs)</th><th className="px-8 py-5">Active WIP</th><th className="px-8 py-5">Status</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${item.output > 0 ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                          {item.output > 0 ? 'Active' : 'Idle'}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Order Master Matrix</h3>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-1">Bundle-level tracking through the entire plant</p>
              </div>
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase shadow-lg hover:bg-green-700 transition active:scale-95">Export CSV</button>
            </div>
            <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-6 pt-4 border-t border-slate-100">
              <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 rounded-2xl w-fit border border-slate-100">
                {(['all', 'cutting', 'sewing', 'wash', 'finishing'] as OrderFilterType[]).map(f => (
                  <FilterButton key={f} label={f} active={activeOrderFilter === f} onClick={() => setActiveOrderFilter(f)} color="slate" />
                ))}
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 flex-1">
                <SearchInput label="Bundle ID" icon="🔍" value={orderSearch.qr} onChange={(v) => setOrderSearch(prev => ({...prev, qr: v}))} />
                <SearchInput label="Buyer" value={orderSearch.buyer} onChange={(v) => setOrderSearch(prev => ({...prev, buyer: v}))} />
                <SearchInput label="Style" value={orderSearch.style} onChange={(v) => setOrderSearch(prev => ({...prev, style: v}))} />
                <SearchInput label="PO" value={orderSearch.po} onChange={(v) => setOrderSearch(prev => ({...prev, po: v}))} />
              </div>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest border-b border-slate-800">
                  <tr>
                    <th className="px-4 py-5 sticky left-0 bg-slate-900 z-10">Unit ID</th>
                    <th className="px-4 py-5">Buyer/Style</th>
                    <th className="px-4 py-5">PO Number</th>
                    <th className="px-4 py-5">Metadata</th>
                    <th className="px-4 py-5 text-right">PO Total</th>
                    {showCut && <th className="px-4 py-5 text-center bg-blue-900/40">Cut</th>}
                    {showSew && <><th className="px-4 py-5 text-center bg-indigo-900/40">Sew In</th><th className="px-4 py-5 text-center bg-indigo-900/40">Sew Out</th></>}
                    {showWash && <><th className="px-4 py-5 text-center bg-cyan-900/40">Wash In</th><th className="px-4 py-5 text-center bg-cyan-900/40">Wash Out</th></>}
                    {showFin && <><th className="px-4 py-5 text-center bg-emerald-900/40">Fin In</th><th className="px-4 py-5 text-center bg-emerald-900/40">Fin Out</th></>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[11px] font-bold text-slate-700">
                  {aggregatedOrdersData.map((o) => (
                    <tr key={o.qr_unique_id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 font-black text-slate-900 sticky left-0 bg-white"><span className="bg-slate-100 px-2 py-1 rounded border border-slate-200">{o.qr_unique_id}</span></td>
                      <td className="px-4 py-4">{o.buyer} <br/><span className="text-blue-600 font-black">{o.style}</span></td>
                      <td className="px-4 py-4">{o.po}</td>
                      <td className="px-4 py-4 text-slate-400">{o.color}/{o.size}</td>
                      <td className="px-4 py-4 text-right font-black">{o.po_qty.toLocaleString()}</td>
                      {showCut && <td className="px-4 py-4 text-center bg-blue-50/30 text-blue-700">{o.cut || '-'}</td>}
                      {showSew && <><td className="px-4 py-4 text-center bg-indigo-50/30">{o.sewIn || '-'}</td><td className="px-4 py-4 text-center bg-indigo-50/30 text-indigo-700">{o.sewOut || '-'}</td></>}
                      {showWash && <><td className="px-4 py-4 text-center bg-cyan-50/30">{o.washIn || '-'}</td><td className="px-4 py-4 text-center bg-cyan-50/30 text-cyan-700">{o.washOut || '-'}</td></>}
                      {showFin && <><td className="px-4 py-4 text-center bg-emerald-50/30">{o.finIn || '-'}</td><td className="px-4 py-4 text-center bg-emerald-50/30 text-emerald-700">{o.finOut || '-'}</td></>}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-6xl mx-auto space-y-8 animate-fadeIn">
          <div className="bg-white p-10 rounded-3xl shadow-xl border border-slate-100 text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Production Gateway</h3>
            <p className="text-slate-500 mb-8 font-medium">Input Bundle ID to post sequential updates</p>
            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="ENTER UNIT ID..." className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest uppercase text-black" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
              <button onClick={handleQRSearch} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black shadow-lg transform active:scale-95 transition-all">IDENTIFY</button>
            </div>
            {scanStatus.message && <div className={`mt-4 inline-block px-6 py-2 rounded-full text-xs font-black ${scanStatus.type === 'success' ? 'bg-green-50 text-green-700 border border-green-100' : 'bg-red-50 text-red-700 border border-red-100'}`}>{scanStatus.message}</div>}
          </div>

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              {/* Sequential Progress Visualizer */}
              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm overflow-x-auto">
                 <div className="flex justify-between items-center min-w-[900px]">
                    {['Cutting Done', 'Sewing Input', 'Sewing Output', 'Wash Input', 'Wash Output', 'Finishing Input', 'Finishing Output'].map((step, i) => {
                      const isDone = qrProductionHistory.some(s => s.process === step);
                      const sequence = ['Cutting Done', 'Sewing Input', 'Sewing Output', 'Wash Input', 'Wash Output', 'Finishing Input', 'Finishing Output'];
                      const isNext = (lastCompletedProcess === null && step === 'Cutting Done') || 
                                     (lastCompletedProcess && sequence[sequence.indexOf(lastCompletedProcess) + 1] === step);

                      return (
                        <div key={step} className="flex flex-col items-center relative flex-1 group">
                          <div className={`w-10 h-10 rounded-full flex items-center justify-center text-[10px] font-black z-10 transition-all duration-300 border-4 ${isDone ? 'bg-emerald-500 text-white border-emerald-100' : isNext ? 'bg-blue-600 text-white border-blue-100 scale-110 shadow-lg' : 'bg-slate-100 text-slate-400 border-slate-50'}`}>
                            {isDone ? '✓' : i + 1}
                          </div>
                          <p className={`mt-3 text-[9px] font-black uppercase tracking-tighter text-center max-w-[80px] ${isNext ? 'text-blue-600' : 'text-slate-400'}`}>{step}</p>
                          {i < 6 && <div className={`absolute left-1/2 top-5 w-full h-[2px] -z-0 ${isDone ? 'bg-emerald-500' : 'bg-slate-200'}`}></div>}
                        </div>
                      );
                    })}
                 </div>
              </div>

              {/* Data Summary Card */}
              <div className="bg-slate-950 text-white rounded-[2.5rem] shadow-2xl p-8 grid grid-cols-1 lg:grid-cols-4 gap-12">
                <div className="lg:border-r lg:border-slate-800 pr-8">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">CURRENT BUNDLE</p>
                  <p className="text-3xl font-black text-blue-400 break-all leading-tight mb-4">{scanningDetail.qr_id}</p>
                  <div className="p-4 bg-blue-600 rounded-2xl shadow-lg shadow-blue-500/20">
                    <p className="text-[10px] font-black text-blue-100 uppercase">BUNDLE PCS</p>
                    <p className="text-4xl font-black">{scanningDetail.bundle_qty}</p>
                  </div>
                </div>
                <div className="lg:col-span-3 grid grid-cols-2 md:grid-cols-4 gap-8">
                  <DetailItemDark label="Buyer" value={scanningDetail.buyer} />
                  <DetailItemDark label="Style" value={scanningDetail.style} />
                  <DetailItemDark label="PO No" value={scanningDetail.po} />
                  <DetailItemDark label="Country" value={scanningDetail.country} />
                  <DetailItemDark label="Color" value={scanningDetail.color} />
                  <DetailItemDark label="Size" value={scanningDetail.size} />
                  <DetailItemDark label="Total PO Qty" value={scanningDetail.po_qty.toLocaleString()} />
                  <DetailItemDark label="Last Progress" value={lastCompletedProcess || 'Pending Start'} />
                </div>
              </div>

              {/* Functional Controls Grid */}
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                <div className="space-y-6">
                  {/* Step 1: Cutting */}
                  <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-5 text-4xl group-hover:opacity-10 transition-opacity">✂️</div>
                    <h4 className="text-xs font-black uppercase text-slate-400 mb-6 tracking-[0.2em] flex items-center">SECTION 01: CUTTING</h4>
                    <button 
                      onClick={() => handleQuickPost('Cutting Done')} 
                      className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-sm transition-all shadow-md active:scale-95 ${!lastCompletedProcess ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-slate-50 text-slate-300 cursor-not-allowed border border-slate-100'}`}
                    >
                      Post Cutting Done
                    </button>
                  </div>
                  {/* Step 2: Sewing */}
                  <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm group relative">
                    <div className="absolute top-0 right-0 p-4 opacity-5 text-4xl group-hover:opacity-10 transition-opacity">🧵</div>
                    <h4 className="text-xs font-black uppercase text-slate-400 mb-6 tracking-[0.2em]">SECTION 02: SEWING FLOOR</h4>
                    <div className="grid grid-cols-2 gap-6">
                      <div className="bg-slate-50/50 p-4 rounded-3xl border border-slate-100">
                        <p className="text-[9px] font-black uppercase text-indigo-600 mb-4 text-center tracking-widest">Input (Lines 1-15)</p>
                        <div className="grid grid-cols-3 gap-2">
                          {Array.from({ length: 15 }).map((_, i) => (
                            <button key={i} onClick={() => handleQuickPost('Sewing Input', `Line-${i+1}`)} className="py-2.5 bg-white border border-slate-200 rounded-xl text-[11px] font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all shadow-sm active:scale-90">{i+1}</button>
                          ))}
                        </div>
                      </div>
                      <div className="bg-slate-50/50 p-4 rounded-3xl border border-slate-100">
                        <p className="text-[9px] font-black uppercase text-emerald-600 mb-4 text-center tracking-widest">Output (Lines 1-15)</p>
                        <div className="grid grid-cols-3 gap-2">
                          {Array.from({ length: 15 }).map((_, i) => (
                            <button key={i} onClick={() => handleQuickPost('Sewing Output', `Line-${i+1}`)} className="py-2.5 bg-white border border-slate-200 rounded-xl text-[11px] font-black text-slate-700 hover:bg-emerald-600 hover:text-white transition-all shadow-sm active:scale-90">{i+1}</button>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="space-y-6">
                  {/* Step 3: Wash */}
                  <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-5 text-4xl group-hover:opacity-10 transition-opacity">🧼</div>
                    <h4 className="text-xs font-black uppercase text-slate-400 mb-6 tracking-[0.2em]">SECTION 03: WASH PLANT</h4>
                    <div className="grid grid-cols-2 gap-4">
                      <button onClick={() => handleQuickPost('Wash Input')} className="py-5 bg-cyan-50 text-cyan-700 border-2 border-cyan-100 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-cyan-600 hover:text-white transition-all active:scale-95">Post Wash In</button>
                      <button onClick={() => handleQuickPost('Wash Output')} className="py-5 bg-cyan-50 text-cyan-700 border-2 border-cyan-100 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-cyan-600 hover:text-white transition-all active:scale-95">Post Wash Out</button>
                    </div>
                  </div>
                  {/* Step 4: Finishing */}
                  <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm group relative">
                    <div className="absolute top-0 right-0 p-4 opacity-5 text-4xl group-hover:opacity-10 transition-opacity">🏁</div>
                    <h4 className="text-xs font-black uppercase text-slate-400 mb-6 tracking-[0.2em]">SECTION 04: FINISHING FLOOR</h4>
                    <div className="grid grid-cols-2 gap-6">
                      <div className="bg-slate-50/50 p-4 rounded-3xl border border-slate-100">
                        <p className="text-[9px] font-black uppercase text-violet-600 mb-4 text-center tracking-widest">Input (Lines 1-10)</p>
                        <div className="grid grid-cols-5 gap-2">
                          {Array.from({ length: 10 }).map((_, i) => (
                            <button key={i} onClick={() => handleQuickPost('Finishing Input', `Line-${i+1}`)} className="py-2.5 bg-white border border-slate-200 rounded-xl text-[10px] font-black text-slate-700 hover:bg-violet-600 hover:text-white transition-all shadow-sm active:scale-90">{i+1}</button>
                          ))}
                        </div>
                      </div>
                      <div className="bg-slate-50/50 p-4 rounded-3xl border border-slate-100">
                        <p className="text-[9px] font-black uppercase text-pink-600 mb-4 text-center tracking-widest">Output (Lines 1-10)</p>
                        <div className="grid grid-cols-5 gap-2">
                          {Array.from({ length: 10 }).map((_, i) => (
                            <button key={i} onClick={() => handleQuickPost('Finishing Output', `Line-${i+1}`)} className="py-2.5 bg-white border border-slate-200 rounded-xl text-[10px] font-black text-slate-700 hover:bg-pink-600 hover:text-white transition-all shadow-sm active:scale-90">{i+1}</button>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
             <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">System Audit Log</h3>
             <div className="flex gap-4 w-full md:w-auto">
                <input type="text" value={historySearch} onChange={(e) => setHistorySearch(e.target.value)} placeholder="Filter by Unit ID..." className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-xs font-bold text-black focus:border-blue-500 outline-none" />
                <button onClick={() => handleDownloadExcel('history')} className="bg-slate-900 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase shadow-lg active:scale-95">Download CSV</button>
             </div>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <div className="overflow-x-auto">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest"><tr><th className="px-8 py-5">Scan Timestamp</th><th className="px-8 py-5">Unit ID</th><th className="px-8 py-5">Process Stage</th><th className="px-8 py-5 text-right">Qty</th><th className="px-8 py-5">Line</th></tr></thead>
                 <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                   {scans.filter(s => !historySearch || s.qr_id.includes(historySearch)).slice().reverse().map((scan) => (
                     <tr key={scan.id} className="hover:bg-slate-50 transition-colors">
                       <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleString()}</td>
                       <td className="px-8 py-4 text-slate-900 font-black tracking-tighter">{scan.qr_id}</td>
                       <td className="px-8 py-4">
                        <span className={`px-3 py-1 rounded-full text-[10px] uppercase font-black tracking-tight ${scan.process.includes('Input') ? 'bg-indigo-50 text-indigo-600' : 'bg-emerald-50 text-emerald-600'}`}>{scan.process}</span>
                       </td>
                       <td className="px-8 py-4 text-right font-black text-slate-900">{scan.qty.toLocaleString()} pcs</td>
                       <td className="px-8 py-4 text-xs text-slate-400 font-medium">{scan.line}</td>
                     </tr>
                   ))}
                   {scans.length === 0 && (
                     <tr><td colSpan={5} className="py-20 text-center text-slate-300 font-black uppercase tracking-widest">No Logs Available</td></tr>
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DashboardCard: React.FC<{ 
  icon: string, title: string, value: number, color: string, label: string, subMetrics: any[]
}> = ({ icon, title, value, color, label, subMetrics }) => {
  const theme = color === 'blue' ? 'text-blue-600 border-t-blue-500 bg-blue-50/30' : 
                color === 'indigo' ? 'text-indigo-600 border-t-indigo-500 bg-indigo-50/30' : 
                color === 'cyan' ? 'text-cyan-600 border-t-cyan-500 bg-cyan-50/30' : 'text-emerald-600 border-t-emerald-500 bg-emerald-50/30';

  const textTheme = theme.split(' ')[0];
  const borderTheme = theme.split(' ')[1];
  const bgTheme = theme.split(' ')[2];

  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 border-t-4 ${borderTheme} ${bgTheme} hover:shadow-xl transition-all relative overflow-hidden group`}>
      <div className={`absolute -right-4 -top-4 ${textTheme} opacity-5 group-hover:opacity-10 transition-opacity`}>
        <span className="text-8xl font-black">{label}</span>
      </div>
      <div className="flex items-center space-x-4 mb-4 relative z-10">
        <div className="w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-xl">{icon}</div>
        <div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Section</p>
          <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{title}</p>
        </div>
      </div>
      <div className="mb-6 relative z-10">
        <p className={`text-4xl font-black tracking-tighter ${textTheme}`}>{value.toLocaleString()}</p>
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Current Output (pcs)</p>
      </div>
      <div className="grid grid-cols-1 gap-4 pt-4 border-t border-slate-200/50 relative z-10">
        {subMetrics.map((m, i) => (
          <div key={i} className="flex flex-col">
            <div className="flex justify-between items-end mb-1">
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{m.label}</p>
              <p className={`text-sm font-black tracking-tight ${m.highlight ? textTheme : 'text-slate-800'}`}>{m.value}</p>
            </div>
            {m.showProgress && (
              <div className="w-full h-1.5 bg-white/50 rounded-full overflow-hidden">
                <div 
                  className={`h-full ${textTheme.replace('text-', 'bg-')}`} 
                  style={{ width: m.value }}
                ></div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

const FilterButton: React.FC<{ label: string, active: boolean, onClick: () => void, color: string }> = ({ label, active, onClick, color }) => {
  const activeClass = active ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100';
  return <button onClick={onClick} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeClass}`}>{label}</button>;
};

const SearchInput: React.FC<{ label: string, icon?: string, value: string, onChange: (v: string) => void }> = ({ label, icon, value, onChange }) => (
  <div className="flex flex-col">
    <label className="text-[9px] font-black text-slate-400 uppercase mb-1 ml-1 tracking-widest">{label}</label>
    <div className="relative">
      {icon && <span className="absolute left-3 top-1/2 -translate-y-1/2 opacity-30">{icon}</span>}
      <input type="text" value={value} onChange={(e) => onChange(e.target.value)} placeholder="Search..." className={`w-full bg-white border border-slate-200 rounded-xl ${icon ? 'pl-9' : 'px-4'} py-2 text-xs font-bold text-black outline-none focus:border-blue-500 transition-all`} />
    </div>
  </div>
);

const DetailItemDark: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div className="group">
    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-blue-400 transition-colors">{label}</p>
    <p className="text-sm font-black text-white tracking-tight break-words uppercase">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { MOCK_ORDERS, MOCK_QR_DATA, PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';

const STORAGE_KEY = 'pg_production_scans_v11';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders] = useState<OrderMaster[]>(MOCK_ORDERS);
  const [qrCodes] = useState<QRMaster[]>(MOCK_QR_DATA);
  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  const [orderSearch, setOrderSearch] = useState({
    buyer: '',
    style: '',
    po: '',
    qr: ''
  });

  const [historySearch, setHistorySearch] = useState('');

  const [scans, setScans] = useState<ScanningData[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scans from storage", e);
      return [];
    }
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(scans));
  }, [scans]);

  // Initial demo data generation
  useEffect(() => {
    if (scans.length === 0) {
      const nowStr = new Date().toISOString();
      const demoScans: ScanningData[] = [];
      MOCK_ORDERS.forEach((order) => {
        // Create initial cutting input to simulate cutting WIP
        demoScans.push({
          id: crypto.randomUUID(),
          qr_id: `PG-START-${order.style}`,
          process: 'Cutting Done',
          qty: 4500,
          status: ProductionStatus.COMPLETED,
          line: 'N/A',
          scanned_by: 'System',
          scan_time: nowStr
        });
      });
      setScans(demoScans);
    }
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);

    // We treat 'Cutting Done' as Output of cutting. Input for cutting is implied/mocked as Target for WIP visualization.
    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      // Cutting metrics (Input is mocked as Daily Target for the first stage)
      cutInput: TARGETS.cutting,
      cutOutput: cutOutput,
      cutWIP: Math.max(0, TARGETS.cutting - cutOutput),
      cutEff: Math.round((cutOutput / TARGETS.cutting) * 100),

      // Sewing metrics
      sewInput: sewInput,
      sewOutput: sewOutput,
      sewWIP: Math.max(0, sewInput - sewOutput),
      sewEff: Math.round((sewOutput / TARGETS.sewing) * 100),

      // Wash metrics
      washInput: washInput,
      washOutput: washOutput,
      washWIP: Math.max(0, washInput - washOutput),
      washEff: Math.round((washOutput / TARGETS.wash) * 100),

      // Finishing metrics
      finInput: finInput,
      finOutput: finOutput,
      finWIP: Math.max(0, finInput - finOutput),
      finEff: Math.round((finOutput / TARGETS.finishing) * 100),
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lines = Array.from({ length: 15 }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      return { line, input, output, wip };
    });
  }, [scans, performanceView]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([
      ...qrCodes.map(q => q.qr_id),
      ...scans.map(s => s.qr_id)
    ]));

    return allUniqueQRs
      .map(qrId => {
        const masterQR = qrCodes.find(q => q.qr_id === qrId);
        const masterOrder = masterQR 
          ? orders.find(o => o.id === masterQR.order_id)
          : orders.find(o => qrId.includes(o.style)); 

        if (!masterOrder) return null;
        const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);

        return {
          qr_unique_id: qrId,
          timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
          buyer: masterOrder.buyer,
          style: masterOrder.style,
          po: masterOrder.po,
          country: masterOrder.country,
          color: masterOrder.color,
          size: masterOrder.size,
          po_qty: masterOrder.po_qty,
          bundle_qty: masterQR?.bundle_qty || 100,
          cut: getP('Cutting Done'),
          sewIn: getP('Sewing Input'),
          sewOut: getP('Sewing Output'),
          washIn: getP('Wash Input'),
          washOut: getP('Wash Output'),
          finIn: getP('Finishing Input'),
          finOut: getP('Finishing Output')
        };
      })
      .filter((item): item is NonNullable<typeof item> => item !== null);
  }, [orders, qrCodes, scans]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans
      .filter(s => s.qr_id === scanningDetail.qr_id)
      .sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => {
    if (qrProductionHistory.length === 0) return null;
    return qrProductionHistory[qrProductionHistory.length - 1].process;
  }, [qrProductionHistory]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style)) || orders[0];
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder.id,
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         ...matchingOrder
       });
       setScanStatus({ message: 'Tracking New Bundle.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Unique Bundle ID not found.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleQuickPost = (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;

    const sequence = [
      'Cutting Done',
      'Sewing Input',
      'Sewing Output',
      'Wash Input',
      'Wash Output',
      'Finishing Input',
      'Finishing Output'
    ];

    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    if (currentIndex !== lastIndex + 1) {
      if (currentIndex <= lastIndex) {
        setScanStatus({ message: `Already completed ${process}.`, type: 'error' });
        return;
      }
      setScanStatus({ message: `Sequence Error. Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };
    setScans(prev => [newScan, ...prev]);
    setScanStatus({ message: `Successfully posted ${process}!`, type: 'success' });
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty", "Cut", "Sew In", "Sew Out", "Wash In", "Wash Out", "Fin In", "Fin Out"];
      csvRows = aggregatedOrdersData.map(o => [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty, o.cut, o.sewIn, o.sewOut, o.washIn, o.washOut, o.finIn, o.finOut].map(v => `"${v}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  const showCut = activeOrderFilter === 'all' || activeOrderFilter === 'cutting';
  const showSew = activeOrderFilter === 'all' || activeOrderFilter === 'sewing';
  const showWash = activeOrderFilter === 'all' || activeOrderFilter === 'wash';
  const showFin = activeOrderFilter === 'all' || activeOrderFilter === 'finishing';

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* Main Department KPI Grid: Input, WIP, Efficiency */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard 
              icon="✂️" title="Cutting Section" value={dashboardStats.cutOutput} color="blue" label="CUT" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.cutInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.cutWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.cutEff}%`, highlight: true, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🧵" title="Sewing Floor" value={dashboardStats.sewOutput} color="indigo" label="SEW" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.sewInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.sewWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.sewEff}%`, highlight: true, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🧼" title="Wash Plant" value={dashboardStats.washOutput} color="cyan" label="WSH" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.washInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.washWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.washEff}%`, highlight: true, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🏁" title="Finishing Floor" value={dashboardStats.finOutput} color="emerald" label="FIN" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.finInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.finWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.finEff}%`, highlight: true, showProgress: true }
              ]} 
            />
          </div>

          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div>
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">Line Throughput Analysis</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time status of production lines</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700 mt-4 lg:mt-0">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-8 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line ID</th><th className="px-8 py-5">Input (pcs)</th><th className="px-8 py-5">Output (pcs)</th><th className="px-8 py-5">Active WIP</th><th className="px-8 py-5">Status</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-slate-400">{item.wip.toLocaleString()}</td>
                      <td className="px-8 py-4">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${item.output > 0 ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                          {item.output > 0 ? 'Active' : 'Idle'}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
              <div>
                <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Order Tracking Matrix</h3>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-1">Global visibility of every production unit</p>
              </div>
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-green-700 shadow-lg active:scale-95">Export CSV</button>
            </div>
            <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-6 pt-4 border-t border-slate-100">
              <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 rounded-2xl w-fit border border-slate-100">
                <FilterButton label="All" active={activeOrderFilter === 'all'} onClick={() => setActiveOrderFilter('all')} color="slate" />
                <FilterButton label="Cutting" active={activeOrderFilter === 'cutting'} onClick={() => setActiveOrderFilter('cutting')} color="blue" />
                <FilterButton label="Sewing" active={activeOrderFilter === 'sewing'} onClick={() => setActiveOrderFilter('sewing')} color="indigo" />
                <FilterButton label="Wash" active={activeOrderFilter === 'wash'} onClick={() => setActiveOrderFilter('wash')} color="cyan" />
                <FilterButton label="Finishing" active={activeOrderFilter === 'finishing'} onClick={() => setActiveOrderFilter('finishing')} color="emerald" />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 flex-1">
