  'Cutting Done',
  'Sewing Input',
  'Sewing Output',
  'Wash Input',
  'Wash Output',
  'Finishing Input',
  'Finishing Output'
];

// QR Format: PG-YYMMDDXXXXXX (e.g., PG-260122000001)
