export const MOCK_ORDERS = []; // Empty demo data
export const MOCK_QR_DATA = []; // Empty demo data

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'https://wkxoyxxucbbkwqunknfg.supabase.co';
const supabaseAnonKey = 'sb_publishable_PLz0LrswCkK6Uhdfv1qHQw_AZtLiJa4';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  const [orderSearch, setOrderSearch] = useState({
    buyer: '',
    style: '',
    po: '',
    qr: ''
  });

  const [historyFilters, setHistoryFilters] = useState({
    qr: '',
    date: '',
    process: ''
  });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  // Fetch initial data from Supabase
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleResetAll = async () => {
    if (window.confirm("CRITICAL ACTION: Are you sure you want to permanently delete ALL data (Orders, QR Codes, and Scans) from the DATABASE? This cannot be undone.")) {
      try {
        await supabase.from('scans').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        await supabase.from('qr_codes').delete().neq('qr_id', 'none');
        await supabase.from('orders').delete().neq('id', '00000000-0000-0000-0000-000000000000');

        setScans([]);
        setOrders([]);
        setQrCodes([]);
        setScanStatus({ message: 'Database has been completely wiped.', type: 'success' });
      } catch (error) {
        console.error("Reset error:", error);
        setScanStatus({ message: 'Failed to clear database.', type: 'error' });
      }
    }
  };

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);

    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      cutInput: TARGETS.cutting,
      cutOutput: cutOutput,
      cutWIP: Math.max(0, TARGETS.cutting - cutOutput),
      cutEff: Math.round((cutOutput / TARGETS.cutting) * 100) || 0,

      sewInput: sewInput,
      sewOutput: sewOutput,
      sewWIP: Math.max(0, sewInput - sewOutput),
      sewEff: Math.round((sewOutput / TARGETS.sewing) * 100) || 0,

      washInput: washInput,
      washOutput: washOutput,
      washWIP: Math.max(0, washInput - washOutput),
      washEff: Math.round((washOutput / TARGETS.wash) * 100) || 0,

      finInput: finInput,
      finOutput: finOutput,
      finWIP: Math.max(0, finInput - finOutput),
      finEff: Math.round((finOutput / TARGETS.finishing) * 100) || 0,
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lineCount = performanceView === 'Sewing' ? 15 : 10;
    const lines = Array.from({ length: lineCount }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const inputProc = `${performanceView} Input`;
      const outputProc = `${performanceView} Output`;
      const input = scans.filter(s => s.line === line && s.process === inputProc).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === outputProc).reduce((sum, item) => sum + item.qty, 0);
      const wip = Math.max(0, input - output);
      return { line, input, output, wip };
    });
  }, [scans, performanceView]);

  const filteredHistory = useMemo(() => {
    return scans.filter(s => {
      const matchQR = !historyFilters.qr || s.qr_id.toLowerCase().includes(historyFilters.qr.toLowerCase());
      const matchProcess = !historyFilters.process || s.process === historyFilters.process;
      const matchDate = !historyFilters.date || s.scan_time.startsWith(historyFilters.date);
      return matchQR && matchProcess && matchDate;
    });
  }, [scans, historyFilters]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([
      ...qrCodes.map(q => q.qr_id),
      ...scans.map(s => s.qr_id)
    ]));

    return allUniqueQRs
      .map(qrId => {
        const masterQR = qrCodes.find(q => q.qr_id === qrId);
        const masterOrder = masterQR 
          ? orders.find(o => o.id === masterQR.order_id)
          : orders.find(o => qrId.includes(o.style)); 

        if (!masterOrder) return null;
        const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);

        return {
          qr_unique_id: qrId,
          timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
          buyer: masterOrder.buyer,
          style: masterOrder.style,
          po: masterOrder.po,
          country: masterOrder.country,
          color: masterOrder.color,
          size: masterOrder.size,
          po_qty: masterOrder.po_qty,
          bundle_qty: masterQR?.bundle_qty || 100,
          cut: getP('Cutting Done'),
          sewIn: getP('Sewing Input'),
          sewOut: getP('Sewing Output'),
          washIn: getP('Wash Input'),
          washOut: getP('Wash Output'),
          finIn: getP('Finishing Input'),
          finOut: getP('Finishing Output')
        };
      })
      .filter((item): item is NonNullable<typeof item> => item !== null);
  }, [orders, qrCodes, scans]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans
      .filter(s => s.qr_id === scanningDetail.qr_id)
      .sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => {
    if (qrProductionHistory.length === 0) return null;
    return qrProductionHistory[qrProductionHistory.length - 1].process;
  }, [qrProductionHistory]);

  const handleQRSearch = useCallback(() => {
    const normalizedQR = currentQR.trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style));
       if (matchingOrder) {
          setScanningDetail({
            qr_id: normalizedQR,
            order_id: matchingOrder.id,
            bundle_qty: 100,
            created_at: new Date().toISOString(),
            ...matchingOrder
          });
          setScanStatus({ message: 'Bundle Link Found.', type: 'success' });
       } else {
          setScanningDetail({
            qr_id: normalizedQR,
            order_id: 'unknown',
            bundle_qty: 100,
            created_at: new Date().toISOString(),
            buyer: 'New Entry',
            style: 'New Style',
            po: 'N/A',
            color: 'N/A',
            country: 'N/A',
            size: 'N/A',
            po_qty: 0
          });
          setScanStatus({ message: 'Starting New Bundle Track.', type: 'success' });
       }
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid Bundle ID Format.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const handleQuickPost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;

    const sequence = PROCESS_FLOW;
    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    if (currentIndex !== lastIndex + 1) {
      if (currentIndex <= lastIndex) {
        setScanStatus({ message: `Already completed ${process}.`, type: 'error' });
        return;
      }
      setScanStatus({ message: `Sequence Error. Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process: process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line: line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;

      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Successfully posted ${process}!`, type: 'success' });
    } catch (error) {
      console.error("Post error:", error);
      setScanStatus({ message: 'Database sync failed.', type: 'error' });
    }
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = [];
    let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty", "Cut", "Sew In", "Sew Out", "Wash In", "Wash Out", "Fin In", "Fin Out"];
      csvRows = aggregatedOrdersData.map(o => [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty, o.cut, o.sewIn, o.sewOut, o.washIn, o.washOut, o.finIn, o.finOut].map(v => `"${v}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = filteredHistory.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  const showCut = activeOrderFilter === 'all' || activeOrderFilter === 'cutting';
  const showSew = activeOrderFilter === 'all' || activeOrderFilter === 'sewing';
  const showWash = activeOrderFilter === 'all' || activeOrderFilter === 'wash';
  const showFin = activeOrderFilter === 'all' || activeOrderFilter === 'finishing';

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm font-black uppercase tracking-widest text-slate-400">Connecting to Supabase...</p>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard 
              icon="✂️" title="Cutting Section" value={dashboardStats.cutOutput} color="blue" label="CUT" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.cutInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.cutWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.cutEff}%`, highlight: true, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🧵" title="Sewing Floor" value={dashboardStats.sewOutput} color="indigo" label="SEW" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.sewInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.sewWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.sewEff}%`, highlight: true, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🧼" title="Wash Plant" value={dashboardStats.washOutput} color="cyan" label="WSH" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.washInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.washWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.washEff}%`, highlight: true, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🏁" title="Finishing Floor" value={dashboardStats.finOutput} color="emerald" label="FIN" 
              subMetrics={[
                { label: 'Input', value: dashboardStats.finInput.toLocaleString() },
                { label: 'WIP', value: dashboardStats.finWIP.toLocaleString() },
                { label: 'Efficiency', value: `${dashboardStats.finEff}%`, highlight: true, showProgress: true }
              ]} 
            />
          </div>

          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center border-b border-slate-800">
              <div>
                <h3 className="text-2xl font-black text-white uppercase tracking-tight">LINE WISE PERFORMANCE</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Real-time status of production lines</p>
              </div>
              <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700 mt-4 lg:mt-0">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-8 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line ID</th><th className="px-8 py-5">Input (pcs)</th><th className="px-8 py-5">Output (pcs)</th><th className="px-8 py-5">Active WIP</th><th className="px-8 py-5">Status</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/80 transition-all duration-200">
                      <td className="px-8 py-4 font-black text-slate-950">{item.line}</td>
                      <td className="px-8 py-4 tabular-nums">{item.input.toLocaleString()}</td>
                      <td className="px-8 py-4 tabular-nums text-indigo-600">{item.output.toLocaleString()}</td>
