            <div className="flex space-x-4 max-w-2xl mx-auto">
              <input type="text" value={currentQR} onChange={(e) => setCurrentQR(e.target.value)} placeholder="ENTER BUNDLE ID (e.g. PG-STYLE-001)" className="flex-1 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-blue-500 outline-none text-xl font-black tracking-widest uppercase text-black" onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()} />
