          </div>

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm overflow-x-auto">
                 <div className="flex justify-between items-center min-w-[900px]">
                    {PROCESS_FLOW.map((step, i) => {
                      const isDone = qrProductionHistory.some(s => s.process === step);
                      const sequence = PROCESS_FLOW;
                      const isNext = (lastCompletedProcess === null && step === sequence[0]) || 
                                     (lastCompletedProcess && sequence[sequence.indexOf(lastCompletedProcess) + 1] === step);

                      return (
                        <div key={step} className="flex flex-col items-center relative flex-1 group">
                          <div className={`w-10 h-10 rounded-full flex items-center justify-center text-[10px] font-black z-10 transition-all duration-300 border-4 ${isDone ? 'bg-emerald-500 text-white border-emerald-100' : isNext ? 'bg-blue-600 text-white border-blue-100 scale-110 shadow-lg' : 'bg-slate-100 text-slate-400 border-slate-50'}`}>
