import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  const [orderSearch, setOrderSearch] = useState({ buyer: '', style: '', po: '', qr: '' });
  const [historyFilters, setHistoryFilters] = useState({ qr: '', date: '', process: '' });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Fetch initial data from Supabase
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleResetAll = async () => {
    if (window.confirm("CRITICAL ACTION: Are you sure you want to permanently delete ALL data? This cannot be undone.")) {
      try {
        await supabase.from('scans').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        await supabase.from('qr_codes').delete().neq('qr_id', 'none');
        await supabase.from('orders').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        setScans([]); setOrders([]); setQrCodes([]);
        setScanStatus({ message: 'Database cleared.', type: 'success' });
      } catch (error) {
        setScanStatus({ message: 'Reset failed.', type: 'error' });
      }
    }
  };

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      cutInput: TARGETS.cutting, cutOutput, cutWIP: Math.max(0, TARGETS.cutting - cutOutput), cutEff: Math.round((cutOutput / TARGETS.cutting) * 100) || 0,
      sewInput, sewOutput, sewWIP: Math.max(0, sewInput - sewOutput), sewEff: Math.round((sewOutput / TARGETS.sewing) * 100) || 0,
      washInput, washOutput, washWIP: Math.max(0, washInput - washOutput), washEff: Math.round((washOutput / TARGETS.wash) * 100) || 0,
      finInput, finOutput, finWIP: Math.max(0, finInput - finOutput), finEff: Math.round((finOutput / TARGETS.finishing) * 100) || 0,
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lineCount = performanceView === 'Sewing' ? 15 : 10;
    const lines = Array.from({ length: lineCount }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const input = scans.filter(s => s.line === line && s.process === `${performanceView} Input`).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === `${performanceView} Output`).reduce((sum, item) => sum + item.qty, 0);
      return { line, input, output, wip: Math.max(0, input - output) };
    });
  }, [scans, performanceView]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([...qrCodes.map(q => q.qr_id), ...scans.map(s => s.qr_id)]));
    return allUniqueQRs.map(qrId => {
      const masterQR = qrCodes.find(q => q.qr_id === qrId);
      const masterOrder = masterQR ? orders.find(o => o.id === masterQR.order_id) : orders.find(o => qrId.includes(o.style)); 
      if (!masterOrder) return null;
      const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);
      return {
        qr_unique_id: qrId, timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
        buyer: masterOrder.buyer, style: masterOrder.style, po: masterOrder.po, country: masterOrder.country, color: masterOrder.color,
        size: masterOrder.size, po_qty: masterOrder.po_qty, bundle_qty: masterQR?.bundle_qty || 100,
        cut: getP('Cutting Done'), sewIn: getP('Sewing Input'), sewOut: getP('Sewing Output'),
        washIn: getP('Wash Input'), washOut: getP('Wash Output'), finIn: getP('Finishing Input'), finOut: getP('Finishing Output')
      };
    }).filter((item): item is NonNullable<typeof item> => item !== null);
  }, [orders, qrCodes, scans]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans.filter(s => s.qr_id === scanningDetail.qr_id).sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => qrProductionHistory.length > 0 ? qrProductionHistory[qrProductionHistory.length - 1].process : null, [qrProductionHistory]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const normalizedQR = (qrVal || currentQR).trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style));
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder?.id || 'unknown',
         bundle_qty: 100,
         created_at: new Date().toISOString(),
         buyer: matchingOrder?.buyer || 'New Entry',
         style: matchingOrder?.style || 'New Style',
         po: matchingOrder?.po || 'N/A',
         color: matchingOrder?.color || 'N/A',
         country: matchingOrder?.country || 'N/A',
         size: matchingOrder?.size || 'N/A',
         po_qty: matchingOrder?.po_qty || 0
       });
       setScanStatus({ message: 'Unit Ready for Tracking.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid Bundle ID.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.play();
        requestAnimationFrame(tick);
      }
    } catch (err) {
      console.error(err);
      setScanStatus({ message: 'Camera access denied.', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const tick = () => {
    if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      if (context) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        context.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'dontInvert' });
        if (code) {
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) requestAnimationFrame(tick);
  };

  const handleQuickPost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;
    const sequence = PROCESS_FLOW;
    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    if (currentIndex !== lastIndex + 1) {
      setScanStatus({ message: currentIndex <= lastIndex ? `Already at ${process}` : `Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(), qr_id: scanningDetail.qr_id, process, qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED, line, scanned_by: 'Rakibul', scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Posted ${process} successfully!`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Database sync failed.', type: 'error' });
    }
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = []; let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty", "Cut", "Sew In", "Sew Out", "Wash In", "Wash Out", "Fin In", "Fin Out"];
      csvRows = aggregatedOrdersData.map(o => [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty, o.cut, o.sewIn, o.sewOut, o.washIn, o.washOut, o.finIn, o.finOut].map(v => `"${v}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm font-black uppercase tracking-widest text-slate-400">Syncing Cloud Database...</p>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Section" value={dashboardStats.cutOutput} color="blue" label="CUT" subMetrics={[{ label: 'WIP', value: dashboardStats.cutWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.cutEff}%`, showProgress: true }]} />
            <DashboardCard icon="🧵" title="Sewing Floor" value={dashboardStats.sewOutput} color="indigo" label="SEW" subMetrics={[{ label: 'WIP', value: dashboardStats.sewWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.sewEff}%`, showProgress: true }]} />
            <DashboardCard icon="🧼" title="Wash Plant" value={dashboardStats.washOutput} color="cyan" label="WSH" subMetrics={[{ label: 'WIP', value: dashboardStats.washWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.washEff}%`, showProgress: true }]} />
            <DashboardCard icon="🏁" title="Finishing Floor" value={dashboardStats.finOutput} color="emerald" label="FIN" subMetrics={[{ label: 'WIP', value: dashboardStats.finWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.finEff}%`, showProgress: true }]} />
          </div>
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center">
              <div><h3 className="text-2xl font-black text-white uppercase tracking-tight">LINE WISE PERFORMANCE</h3></div>
              <div className="flex bg-slate-800 p-1 rounded-xl mt-4 lg:mt-0">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-6 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line ID</th><th className="px-8 py-5 text-right">Input</th><th className="px-8 py-5 text-right">Output</th><th className="px-8 py-5 text-right">WIP</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-all"><td className="px-8 py-4 font-black">{item.line}</td><td className="px-8 py-4 text-right">{item.input.toLocaleString()}</td><td className="px-8 py-4 text-right text-indigo-600">{item.output.toLocaleString()}</td><td className="px-8 py-4 text-right text-slate-400">{item.wip.toLocaleString()}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
            <div><h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Order Matrix</h3></div>
            <div className="flex flex-wrap gap-2">
              <FilterButton label="All" active={activeOrderFilter === 'all'} onClick={() => setActiveOrderFilter('all')} color="slate" />
              <FilterButton label="Cutting" active={activeOrderFilter === 'cutting'} onClick={() => setActiveOrderFilter('cutting')} color="blue" />
              <FilterButton label="Sewing" active={activeOrderFilter === 'sewing'} onClick={() => setActiveOrderFilter('sewing')} color="indigo" />
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase shadow-lg">Export</button>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest">
                  <tr><th className="px-4 py-5">Unit ID</th><th className="px-4 py-5">Style</th><th className="px-4 py-5 text-right">PO Qty</th><th className="px-4 py-5 text-center">Cut</th><th className="px-4 py-5 text-center">Sew In</th><th className="px-4 py-5 text-center">Sew Out</th><th className="px-4 py-5 text-center">Wash In</th><th className="px-4 py-5 text-center">Wash Out</th><th className="px-4 py-5 text-center">Fin Out</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[11px] font-bold text-slate-700">
                  {aggregatedOrdersData.map(o => (
                    <tr key={o.qr_unique_id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 font-black">{o.qr_unique_id}</td><td className="px-4 py-4 text-blue-600">{o.style}</td><td className="px-4 py-4 text-right">{o.po_qty.toLocaleString()}</td><td className="px-4 py-4 text-center">{o.cut || '-'}</td><td className="px-4 py-4 text-center">{o.sewIn || '-'}</td><td className="px-4 py-4 text-center text-indigo-700">{o.sewOut || '-'}</td><td className="px-4 py-4 text-center">{o.washIn || '-'}</td><td className="px-4 py-4 text-center text-cyan-700">{o.washOut || '-'}</td><td className="px-4 py-4 text-center text-emerald-700">{o.finOut || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-6 animate-fadeIn pb-12">
          {/* Compact Scan Bar */}
          <div className="bg-white p-6 rounded-3xl shadow-lg border border-slate-100 relative group">
            <div className="flex items-center space-x-3">
              <div className="relative flex-1 group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-lg text-slate-400">🔍</span>
                <input 
                  type="text" 
                  value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Enter or Scan Bundle ID" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl pl-12 pr-4 py-4 font-black uppercase tracking-widest text-lg focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all outline-none"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button 
                onClick={startScanner} 
                className="bg-blue-600 text-white w-14 h-14 rounded-2xl flex items-center justify-center text-xl hover:bg-blue-700 shadow-xl shadow-blue-200 transition-transform active:scale-90"
                title="Open Camera"
              >
                📷
              </button>
              <button 
                onClick={() => handleQRSearch()} 
                className="bg-slate-900 text-white px-8 h-14 rounded-2xl font-black uppercase text-sm hover:bg-black shadow-xl transition-all"
              >
                Identify
              </button>
            </div>
            {scanStatus.message && <p className={`mt-3 text-[10px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}
          </div>

          {/* Camera Modal Overlay */}
          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 animate-fadeIn">
              <div className="relative w-full max-w-md aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-64 h-64 border-2 border-blue-500/50 rounded-3xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-8 text-white font-black uppercase tracking-[0.3em] text-[10px]">Scanning for QR Code...</p>
                </div>
                <button onClick={stopScanner} className="absolute top-6 right-6 w-10 h-10 bg-white/10 hover:bg-white/20 rounded-full text-white flex items-center justify-center font-bold">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-4 shadow-2xl">
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1">UNIT IDENTIFIER</p>
                  <p className="text-xl font-black text-blue-400 break-all">{scanningDetail.qr_id}</p>
                </div>
                <DetailItemDark label="Bundle Pcs" value={scanningDetail.bundle_qty.toString()} />
                <DetailItemDark label="Style" value={scanningDetail.style} />
              </div>

              {/* Action Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <ActionSection title="01. Cutting" icon="✂️" color="blue">
                  <button onClick={() => handleQuickPost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-lg active:scale-95 transition-all">Post Cutting Done</button>
                </ActionSection>
                <ActionSection title="02. Sewing" icon="🧵" color="indigo">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={15} onPost={(line) => handleQuickPost('Sewing Input', `Line-${line}`)} color="indigo" />
                    <ProcessGrid title="Output" lines={15} onPost={(line) => handleQuickPost('Sewing Output', `Line-${line}`)} color="emerald" />
                  </div>
                </ActionSection>
                <ActionSection title="03. Wash" icon="🧼" color="cyan">
                   <div className="grid grid-cols-2 gap-3">
                     <button onClick={() => handleQuickPost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash In</button>
                     <button onClick={() => handleQuickPost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash Out</button>
                   </div>
                </ActionSection>
                <ActionSection title="04. Finishing" icon="🏁" color="emerald">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={10} onPost={(line) => handleQuickPost('Finishing Input', `Line-${line}`)} color="violet" />
                    <ProcessGrid title="Output" lines={10} onPost={(line) => handleQuickPost('Finishing Output', `Line-${line}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 uppercase">Scan History</h3>
            <div className="flex space-x-3">
              <button onClick={handleResetAll} className="bg-red-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Reset</button>
              <button onClick={() => handleDownloadExcel('history')} className="bg-slate-900 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Export</button>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                 <tr><th className="px-8 py-5">Time</th><th className="px-8 py-5">Unit</th><th className="px-8 py-5">Process</th><th className="px-8 py-5 text-right">Qty</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                 {scans.slice().reverse().map(scan => (
                   <tr key={scan.id} className="hover:bg-slate-50 transition-colors">
                     <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleTimeString()}</td>
                     <td className="px-8 py-4 text-slate-900">{scan.qr_id}</td>
                     <td className="px-8 py-4"><span className="px-3 py-1 bg-slate-100 rounded-full text-[10px] uppercase">{scan.process}</span></td>
                     <td className="px-8 py-4 text-right">{scan.qty}</td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode, color: string }> = ({ title, icon, children }) => (
  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
    <div className="absolute top-2 right-2 opacity-5 text-3xl group-hover:scale-125 transition-transform">{icon}</div>
    <h4 className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">{title}</h4>
    {children}
  </div>
);

const ProcessGrid: React.FC<{ title: string, lines: number, onPost: (l: number) => void, color: string }> = ({ title, lines, onPost, color }) => (
  <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-100">
    <p className={`text-[9px] font-black uppercase text-center mb-3 text-${color}-600 tracking-widest`}>{title}</p>
    <div className="grid grid-cols-3 gap-1.5">
      {Array.from({ length: lines }).map((_, i) => (
        <button key={i} onClick={() => onPost(i + 1)} className="py-2 bg-white border border-slate-200 rounded-lg text-[10px] font-black hover:bg-slate-900 hover:text-white transition-all">{i + 1}</button>
      ))}
    </div>
  </div>
);

const DashboardCard: React.FC<{ icon: string, title: string, value: number, color: string, label: string, subMetrics: any[] }> = ({ icon, title, value, color, label, subMetrics }) => {
  const theme = color === 'blue' ? 'text-blue-600 border-t-blue-500 bg-blue-50/30' : color === 'indigo' ? 'text-indigo-600 border-t-indigo-500 bg-indigo-50/30' : color === 'cyan' ? 'text-cyan-600 border-t-cyan-500 bg-cyan-50/30' : 'text-emerald-600 border-t-emerald-500 bg-emerald-50/30';
  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 border-t-4 ${theme.split(' ')[1]} ${theme.split(' ')[2]} hover:shadow-xl transition-all relative overflow-hidden group`}>
      <div className={`absolute -right-4 -top-4 ${theme.split(' ')[0]} opacity-5 group-hover:opacity-10 transition-opacity`}><span className="text-7xl font-black">{label}</span></div>
      <div className="flex items-center space-x-3 mb-4"><div className="w-10 h-10 rounded-xl bg-white shadow-sm flex items-center justify-center text-lg">{icon}</div><p className="text-xs font-black uppercase tracking-tight">{title}</p></div>
      <div className="mb-4"><p className={`text-4xl font-black tracking-tighter ${theme.split(' ')[0]}`}>{value.toLocaleString()}</p></div>
      <div className="space-y-3 pt-4 border-t border-slate-200/50">
        {subMetrics.map((m, i) => (
          <div key={i} className="flex flex-col">
            <div className="flex justify-between items-end mb-1"><p className="text-[9px] font-bold text-slate-400 uppercase">{m.label}</p><p className="text-xs font-black">{m.value}</p></div>
            {m.showProgress && <div className="w-full h-1 bg-white/50 rounded-full overflow-hidden"><div className={`h-full ${theme.split(' ')[0].replace('text-', 'bg-')}`} style={{ width: `${m.value}` }}></div></div>}
          </div>
        ))}
      </div>
    </div>
  );
};

const FilterButton: React.FC<{ label: string, active: boolean, onClick: () => void, color: string }> = ({ label, active, onClick }) => (
  <button onClick={onClick} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'}`}>{label}</button>
);

const DetailItemDark: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div className="group">
    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5 group-hover:text-blue-400">{label}</p>
    <p className="text-sm font-black text-white tracking-tight break-words uppercase">{value}</p>
  </div>
);

export default App;

import { GoogleGenAI } from "@google/genai";
import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  const [orderSearch, setOrderSearch] = useState({ buyer: '', style: '', po: '', qr: '' });
  const [historyFilters, setHistoryFilters] = useState({ qr: '', date: '', process: '' });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Fetch initial data from Supabase
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleResetAll = async () => {
    if (window.confirm("CRITICAL ACTION: Are you sure you want to permanently delete ALL data? This cannot be undone.")) {
      try {
        await supabase.from('scans').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        await supabase.from('qr_codes').delete().neq('qr_id', 'none');
        await supabase.from('orders').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        setScans([]); setOrders([]); setQrCodes([]);
        setScanStatus({ message: 'Database cleared.', type: 'success' });
      } catch (error) {
        setScanStatus({ message: 'Reset failed.', type: 'error' });
      }
    }
  };

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      cutInput: TARGETS.cutting, cutOutput, cutWIP: Math.max(0, TARGETS.cutting - cutOutput), cutEff: Math.round((cutOutput / TARGETS.cutting) * 100) || 0,
      sewInput, sewOutput, sewWIP: Math.max(0, sewInput - sewOutput), sewEff: Math.round((sewOutput / TARGETS.sewing) * 100) || 0,
      washInput, washOutput, washWIP: Math.max(0, washInput - washOutput), washEff: Math.round((washOutput / TARGETS.wash) * 100) || 0,
      finInput, finOutput, finWIP: Math.max(0, finInput - finOutput), finEff: Math.round((finOutput / TARGETS.finishing) * 100) || 0,
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lineCount = performanceView === 'Sewing' ? 15 : 10;
    const lines = Array.from({ length: lineCount }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const input = scans.filter(s => s.line === line && s.process === `${performanceView} Input`).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === `${performanceView} Output`).reduce((sum, item) => sum + item.qty, 0);
      return { line, input, output, wip: Math.max(0, input - output) };
    });
  }, [scans, performanceView]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([...qrCodes.map(q => q.qr_id), ...scans.map(s => s.qr_id)]));
    return allUniqueQRs.map(qrId => {
      const masterQR = qrCodes.find(q => q.qr_id === qrId);
      const masterOrder = masterQR ? orders.find(o => o.id === masterQR.order_id) : orders.find(o => qrId.includes(o.style)); 
      if (!masterOrder) return null;
      const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);
      return {
        qr_unique_id: qrId, timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
        buyer: masterOrder.buyer, style: masterOrder.style, po: masterOrder.po, country: masterOrder.country, color: masterOrder.color,
        size: masterOrder.size, po_qty: masterOrder.po_qty, bundle_qty: masterQR?.bundle_qty || 20,
        cut: getP('Cutting Done'), sewIn: getP('Sewing Input'), sewOut: getP('Sewing Output'),
        washIn: getP('Wash Input'), washOut: getP('Wash Output'), finIn: getP('Finishing Input'), finOut: getP('Finishing Output')
      };
    }).filter((item): item is NonNullable<typeof item> => item !== null);
  }, [orders, qrCodes, scans]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans.filter(s => s.qr_id === scanningDetail.qr_id).sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => qrProductionHistory.length > 0 ? qrProductionHistory[qrProductionHistory.length - 1].process : null, [qrProductionHistory]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const normalizedQR = (qrVal || currentQR).trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style));
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder?.id || 'unknown',
         bundle_qty: 20,
         created_at: new Date().toISOString(),
         buyer: matchingOrder?.buyer || 'New Entry',
         style: matchingOrder?.style || 'New Style',
         po: matchingOrder?.po || 'N/A',
         color: matchingOrder?.color || 'N/A',
         country: matchingOrder?.country || 'N/A',
         size: matchingOrder?.size || 'N/A',
         po_qty: matchingOrder?.po_qty || 0
       });
       setScanStatus({ message: 'Unit Ready for Tracking.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid Bundle ID.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.play();
        requestAnimationFrame(tick);
      }
    } catch (err) {
      console.error(err);
      setScanStatus({ message: 'Camera access denied.', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const tick = () => {
    if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      if (context) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        context.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'dontInvert' });
        if (code) {
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) requestAnimationFrame(tick);
  };

  const handleQuickPost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;
    const sequence = PROCESS_FLOW;
    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    if (currentIndex !== lastIndex + 1) {
      setScanStatus({ message: currentIndex <= lastIndex ? `Already at ${process}` : `Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(), qr_id: scanningDetail.qr_id, process, qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED, line, scanned_by: 'Rakibul', scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Posted ${process} successfully!`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Database sync failed.', type: 'error' });
    }
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = []; let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty", "Cut", "Sew In", "Sew Out", "Wash In", "Wash Out", "Fin In", "Fin Out"];
      csvRows = aggregatedOrdersData.map(o => [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty, o.cut, o.sewIn, o.sewOut, o.washIn, o.washOut, o.finIn, o.finOut].map(v => `"${v}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm font-black uppercase tracking-widest text-slate-400">Syncing Cloud Database...</p>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Section" value={dashboardStats.cutOutput} color="blue" label="CUT" subMetrics={[{ label: 'WIP', value: dashboardStats.cutWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.cutEff}%`, showProgress: true }]} />
            <DashboardCard icon="🧵" title="Sewing Floor" value={dashboardStats.sewOutput} color="indigo" label="SEW" subMetrics={[{ label: 'WIP', value: dashboardStats.sewWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.sewEff}%`, showProgress: true }]} />
            <DashboardCard icon="🧼" title="Wash Plant" value={dashboardStats.washOutput} color="cyan" label="WSH" subMetrics={[{ label: 'WIP', value: dashboardStats.washWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.washEff}%`, showProgress: true }]} />
            <DashboardCard icon="🏁" title="Finishing Floor" value={dashboardStats.finOutput} color="emerald" label="FIN" subMetrics={[{ label: 'WIP', value: dashboardStats.finWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.finEff}%`, showProgress: true }]} />
          </div>
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center">
              <div><h3 className="text-2xl font-black text-white uppercase tracking-tight">LINE WISE PERFORMANCE</h3></div>
              <div className="flex bg-slate-800 p-1 rounded-xl mt-4 lg:mt-0">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-6 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line ID</th><th className="px-8 py-5 text-right">Input</th><th className="px-8 py-5 text-right">Output</th><th className="px-8 py-5 text-right">WIP</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-all"><td className="px-8 py-4 font-black">{item.line}</td><td className="px-8 py-4 text-right">{item.input.toLocaleString()}</td><td className="px-8 py-4 text-right text-indigo-600">{item.output.toLocaleString()}</td><td className="px-8 py-4 text-right text-slate-400">{item.wip.toLocaleString()}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
            <div><h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Order Matrix</h3></div>
            <div className="flex flex-wrap gap-2">
              <FilterButton label="All" active={activeOrderFilter === 'all'} onClick={() => setActiveOrderFilter('all')} color="slate" />
              <FilterButton label="Cutting" active={activeOrderFilter === 'cutting'} onClick={() => setActiveOrderFilter('cutting')} color="blue" />
              <FilterButton label="Sewing" active={activeOrderFilter === 'sewing'} onClick={() => setActiveOrderFilter('sewing')} color="indigo" />
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase shadow-lg">Export</button>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest">
                  <tr><th className="px-4 py-5">Unit ID</th><th className="px-4 py-5">Style</th><th className="px-4 py-5 text-right">PO Qty</th><th className="px-4 py-5 text-center">Cut</th><th className="px-4 py-5 text-center">Sew In</th><th className="px-4 py-5 text-center">Sew Out</th><th className="px-4 py-5 text-center">Wash In</th><th className="px-4 py-5 text-center">Wash Out</th><th className="px-4 py-5 text-center">Fin Out</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[11px] font-bold text-slate-700">
                  {aggregatedOrdersData.map(o => (
                    <tr key={o.qr_unique_id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 font-black">{o.qr_unique_id}</td><td className="px-4 py-4 text-blue-600">{o.style}</td><td className="px-4 py-4 text-right">{o.po_qty.toLocaleString()}</td><td className="px-4 py-4 text-center">{o.cut || '-'}</td><td className="px-4 py-4 text-center">{o.sewIn || '-'}</td><td className="px-4 py-4 text-center text-indigo-700">{o.sewOut || '-'}</td><td className="px-4 py-4 text-center">{o.washIn || '-'}</td><td className="px-4 py-4 text-center text-cyan-700">{o.washOut || '-'}</td><td className="px-4 py-4 text-center text-emerald-700">{o.finOut || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-12">
          {/* Compact Scan Bar */}
          <div className="bg-white p-4 rounded-2xl shadow-md border border-slate-100 relative group">
            <div className="flex items-center space-x-2">
              <div className="relative flex-1 group">
                <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-base text-slate-400">🔍</span>
                <input 
                  type="text" 
                  value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Enter or Scan Bundle ID" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-10 pr-3 py-2.5 font-bold uppercase tracking-wider text-sm focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all outline-none"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button 
                onClick={startScanner} 
                className="bg-blue-600 text-white w-10 h-10 rounded-xl flex items-center justify-center text-lg hover:bg-blue-700 shadow-lg shadow-blue-100 transition-transform active:scale-90"
                title="Open Camera"
              >
                📷
              </button>
              <button 
                onClick={() => handleQRSearch()} 
                className="bg-slate-900 text-white px-6 h-10 rounded-xl font-black uppercase text-[11px] hover:bg-black shadow-lg transition-all"
              >
                Identify
              </button>
            </div>
            {scanStatus.message && <p className={`mt-2 text-[9px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}
          </div>

          {/* Camera Modal Overlay */}
          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 animate-fadeIn">
              <div className="relative w-full max-w-md aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-64 h-64 border-2 border-blue-500/50 rounded-3xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-8 text-white font-black uppercase tracking-[0.3em] text-[10px]">Scanning for QR Code...</p>
                </div>
                <button onClick={stopScanner} className="absolute top-6 right-6 w-10 h-10 bg-white/10 hover:bg-white/20 rounded-full text-white flex items-center justify-center font-bold">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-4 shadow-2xl">
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1">UNIT IDENTIFIER</p>
                  <p className="text-xl font-black text-blue-400 break-all">{scanningDetail.qr_id}</p>
                </div>
                <DetailItemDark label="Bundle Pcs" value={scanningDetail.bundle_qty.toString()} />
                <DetailItemDark label="Style" value={scanningDetail.style} />
              </div>

              {/* Action Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <ActionSection title="01. Cutting" icon="✂️" color="blue">
                  <button onClick={() => handleQuickPost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-lg active:scale-95 transition-all">Post Cutting Done</button>
                </ActionSection>
                <ActionSection title="02. Sewing" icon="🧵" color="indigo">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={15} onPost={(line) => handleQuickPost('Sewing Input', `Line-${line}`)} color="indigo" />
                    <ProcessGrid title="Output" lines={15} onPost={(line) => handleQuickPost('Sewing Output', `Line-${line}`)} color="emerald" />
                  </div>
                </ActionSection>
                <ActionSection title="03. Wash" icon="🧼" color="cyan">
                   <div className="grid grid-cols-2 gap-3">
                     <button onClick={() => handleQuickPost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash In</button>
                     <button onClick={() => handleQuickPost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash Out</button>
                   </div>
                </ActionSection>
                <ActionSection title="04. Finishing" icon="🏁" color="emerald">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={10} onPost={(line) => handleQuickPost('Finishing Input', `Line-${line}`)} color="violet" />
                    <ProcessGrid title="Output" lines={10} onPost={(line) => handleQuickPost('Finishing Output', `Line-${line}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 uppercase">Scan History</h3>
            <div className="flex space-x-3">
              <button onClick={handleResetAll} className="bg-red-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Reset</button>
              <button onClick={() => handleDownloadExcel('history')} className="bg-slate-900 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Export</button>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                 <tr><th className="px-8 py-5">Time</th><th className="px-8 py-5">Unit</th><th className="px-8 py-5">Process</th><th className="px-8 py-5 text-right">Qty</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                 {scans.slice().reverse().map(scan => (
                   <tr key={scan.id} className="hover:bg-slate-50 transition-colors">
                     <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleTimeString()}</td>
                     <td className="px-8 py-4 text-slate-900">{scan.qr_id}</td>
                     <td className="px-8 py-4"><span className="px-3 py-1 bg-slate-100 rounded-full text-[10px] uppercase">{scan.process}</span></td>
                     <td className="px-8 py-4 text-right">{scan.qty}</td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode, color: string }> = ({ title, icon, children }) => (
  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
    <div className="absolute top-2 right-2 opacity-5 text-3xl group-hover:scale-125 transition-transform">{icon}</div>
    <h4 className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">{title}</h4>
    {children}
  </div>
);

const ProcessGrid: React.FC<{ title: string, lines: number, onPost: (l: number) => void, color: string }> = ({ title, lines, onPost, color }) => (
  <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-100">
    <p className={`text-[9px] font-black uppercase text-center mb-3 text-${color}-600 tracking-widest`}>{title}</p>
    <div className="grid grid-cols-3 gap-1.5">
      {Array.from({ length: lines }).map((_, i) => (
        <button key={i} onClick={() => onPost(i + 1)} className="py-2 bg-white border border-slate-200 rounded-lg text-[10px] font-black hover:bg-slate-900 hover:text-white transition-all">{i + 1}</button>
      ))}
    </div>
  </div>
);

const DashboardCard: React.FC<{ icon: string, title: string, value: number, color: string, label: string, subMetrics: any[] }> = ({ icon, title, value, color, label, subMetrics }) => {
  const theme = color === 'blue' ? 'text-blue-600 border-t-blue-500 bg-blue-50/30' : color === 'indigo' ? 'text-indigo-600 border-t-indigo-500 bg-indigo-50/30' : color === 'cyan' ? 'text-cyan-600 border-t-cyan-500 bg-cyan-50/30' : 'text-emerald-600 border-t-emerald-500 bg-emerald-50/30';
  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 border-t-4 ${theme.split(' ')[1]} ${theme.split(' ')[2]} hover:shadow-xl transition-all relative overflow-hidden group`}>
      <div className={`absolute -right-4 -top-4 ${theme.split(' ')[0]} opacity-5 group-hover:opacity-10 transition-opacity`}><span className="text-7xl font-black">{label}</span></div>
      <div className="flex items-center space-x-3 mb-4"><div className="w-10 h-10 rounded-xl bg-white shadow-sm flex items-center justify-center text-lg">{icon}</div><p className="text-xs font-black uppercase tracking-tight">{title}</p></div>
      <div className="mb-4"><p className={`text-4xl font-black tracking-tighter ${theme.split(' ')[0]}`}>{value.toLocaleString()}</p></div>
      <div className="space-y-3 pt-4 border-t border-slate-200/50">
        {subMetrics.map((m, i) => (
          <div key={i} className="flex flex-col">
            <div className="flex justify-between items-end mb-1"><p className="text-[9px] font-bold text-slate-400 uppercase">{m.label}</p><p className="text-xs font-black">{m.value}</p></div>
            {m.showProgress && <div className="w-full h-1 bg-white/50 rounded-full overflow-hidden"><div className={`h-full ${theme.split(' ')[0].replace('text-', 'bg-')}`} style={{ width: `${m.value}` }}></div></div>}
          </div>
        ))}
      </div>
    </div>
  );
};

const FilterButton: React.FC<{ label: string, active: boolean, onClick: () => void, color: string }> = ({ label, active, onClick }) => (
  <button onClick={onClick} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'}`}>{label}</button>
);

const DetailItemDark: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div className="group">
    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5 group-hover:text-blue-400">{label}</p>
    <p className="text-sm font-black text-white tracking-tight break-words uppercase">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  const [orderSearch, setOrderSearch] = useState({ buyer: '', style: '', po: '', qr: '' });
  const [historyFilters, setHistoryFilters] = useState({ qr: '', date: '', process: '' });

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Fetch initial data from Supabase
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleResetAll = async () => {
    if (window.confirm("CRITICAL ACTION: Are you sure you want to permanently delete ALL data? This cannot be undone.")) {
      try {
        await supabase.from('scans').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        await supabase.from('qr_codes').delete().neq('qr_id', 'none');
        await supabase.from('orders').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        setScans([]); setOrders([]); setQrCodes([]);
        setScanStatus({ message: 'Database cleared.', type: 'success' });
      } catch (error) {
        setScanStatus({ message: 'Reset failed.', type: 'error' });
      }
    }
  };

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      cutInput: TARGETS.cutting, cutOutput, cutWIP: Math.max(0, TARGETS.cutting - cutOutput), cutEff: Math.round((cutOutput / TARGETS.cutting) * 100) || 0,
      sewInput, sewOutput, sewWIP: Math.max(0, sewInput - sewOutput), sewEff: Math.round((sewOutput / TARGETS.sewing) * 100) || 0,
      washInput, washOutput, washWIP: Math.max(0, washInput - washOutput), washEff: Math.round((washOutput / TARGETS.wash) * 100) || 0,
      finInput, finOutput, finWIP: Math.max(0, finInput - finOutput), finEff: Math.round((finOutput / TARGETS.finishing) * 100) || 0,
    };
  }, [scans]);

  const linePerformanceData = useMemo(() => {
    const lineCount = performanceView === 'Sewing' ? 15 : 10;
    const lines = Array.from({ length: lineCount }, (_, i) => `Line-${i + 1}`);
    return lines.map(line => {
      const input = scans.filter(s => s.line === line && s.process === `${performanceView} Input`).reduce((sum, item) => sum + item.qty, 0);
      const output = scans.filter(s => s.line === line && s.process === `${performanceView} Output`).reduce((sum, item) => sum + item.qty, 0);
      return { line, input, output, wip: Math.max(0, input - output) };
    });
  }, [scans, performanceView]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([...qrCodes.map(q => q.qr_id), ...scans.map(s => s.qr_id)]));
    return allUniqueQRs.map(qrId => {
      const masterQR = qrCodes.find(q => q.qr_id === qrId);
      const masterOrder = masterQR ? orders.find(o => o.id === masterQR.order_id) : orders.find(o => qrId.includes(o.style)); 
      if (!masterOrder) return null;
      const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);
      return {
        qr_unique_id: qrId, timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
        buyer: masterOrder.buyer, style: masterOrder.style, po: masterOrder.po, country: masterOrder.country, color: masterOrder.color,
        size: masterOrder.size, po_qty: masterOrder.po_qty, bundle_qty: masterQR?.bundle_qty || 20,
        cut: getP('Cutting Done'), sewIn: getP('Sewing Input'), sewOut: getP('Sewing Output'),
        washIn: getP('Wash Input'), washOut: getP('Wash Output'), finIn: getP('Finishing Input'), finOut: getP('Finishing Output')
      };
    }).filter((item): item is NonNullable<typeof item> => item !== null);
  }, [orders, qrCodes, scans]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans.filter(s => s.qr_id === scanningDetail.qr_id).sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => qrProductionHistory.length > 0 ? qrProductionHistory[qrProductionHistory.length - 1].process : null, [qrProductionHistory]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const normalizedQR = (qrVal || currentQR).trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style));
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder?.id || 'unknown',
         bundle_qty: 20,
         created_at: new Date().toISOString(),
         buyer: matchingOrder?.buyer || 'New Entry',
         style: matchingOrder?.style || 'New Style',
         po: matchingOrder?.po || 'N/A',
         color: matchingOrder?.color || 'N/A',
         country: matchingOrder?.country || 'N/A',
         size: matchingOrder?.size || 'N/A',
         po_qty: matchingOrder?.po_qty || 0
       });
       setScanStatus({ message: 'Bundle Ready.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid Bundle ID.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.play();
        requestAnimationFrame(tick);
      }
    } catch (err) {
      console.error(err);
      setScanStatus({ message: 'Camera access denied.', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const tick = () => {
    if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      if (context) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        context.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'dontInvert' });
        if (code) {
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) requestAnimationFrame(tick);
  };

  const handleQuickPost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;
    const sequence = PROCESS_FLOW;
    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    if (currentIndex !== lastIndex + 1) {
      setScanStatus({ message: currentIndex <= lastIndex ? `Already at ${process}` : `Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(), qr_id: scanningDetail.qr_id, process, qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED, line, scanned_by: 'Rakibul', scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Posted ${process} successfully!`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Database sync failed.', type: 'error' });
    }
  };

  const handleDownloadExcel = (type: 'orders' | 'history') => {
    let headers: string[] = []; let csvRows: string[] = [];
    if (type === 'orders') {
      headers = ["QR Code", "Timestamp", "Buyer", "Style", "PO", "Country", "Color", "Size", "PO Qty", "Cut", "Sew In", "Sew Out", "Wash In", "Wash Out", "Fin In", "Fin Out"];
      csvRows = aggregatedOrdersData.map(o => [o.qr_unique_id, o.timestamp, o.buyer, o.style, o.po, o.country, o.color, o.size, o.po_qty, o.cut, o.sewIn, o.sewOut, o.washIn, o.washOut, o.finIn, o.finOut].map(v => `"${v}"`).join(','));
    } else {
      headers = ["Time", "QR", "Process", "Qty", "Line"];
      csvRows = scans.map(s => [new Date(s.scan_time).toLocaleString(), s.qr_id, s.process, s.qty, s.line].map(v => `"${v}"`).join(','));
    }
    const blob = new Blob([[headers.join(','), ...csvRows].join('\n')], { type: 'text/csv' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `PG_${type}_${Date.now()}.csv`;
    link.click();
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm font-black uppercase tracking-widest text-slate-400">Syncing Cloud Database...</p>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Section" value={dashboardStats.cutOutput} color="blue" label="CUT" subMetrics={[{ label: 'WIP', value: dashboardStats.cutWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.cutEff}%`, showProgress: true }]} />
            <DashboardCard icon="🧵" title="Sewing Floor" value={dashboardStats.sewOutput} color="indigo" label="SEW" subMetrics={[{ label: 'WIP', value: dashboardStats.sewWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.sewEff}%`, showProgress: true }]} />
            <DashboardCard icon="🧼" title="Wash Plant" value={dashboardStats.washOutput} color="cyan" label="WSH" subMetrics={[{ label: 'WIP', value: dashboardStats.washWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.washEff}%`, showProgress: true }]} />
            <DashboardCard icon="🏁" title="Finishing Floor" value={dashboardStats.finOutput} color="emerald" label="FIN" subMetrics={[{ label: 'WIP', value: dashboardStats.finWIP.toLocaleString() }, { label: 'Efficiency', value: `${dashboardStats.finEff}%`, showProgress: true }]} />
          </div>
          <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 flex flex-col lg:flex-row justify-between items-center">
              <div><h3 className="text-2xl font-black text-white uppercase tracking-tight">LINE WISE PERFORMANCE</h3></div>
              <div className="flex bg-slate-800 p-1 rounded-xl mt-4 lg:mt-0">
                {(['Sewing', 'Finishing'] as const).map(view => (
                  <button key={view} onClick={() => setPerformanceView(view)} className={`px-6 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${performanceView === view ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>{view}</button>
                ))}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] border-b border-slate-100">
                  <tr><th className="px-8 py-5">Line ID</th><th className="px-8 py-5 text-right">Input</th><th className="px-8 py-5 text-right">Output</th><th className="px-8 py-5 text-right">WIP</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-700">
                  {linePerformanceData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-all"><td className="px-8 py-4 font-black">{item.line}</td><td className="px-8 py-4 text-right">{item.input.toLocaleString()}</td><td className="px-8 py-4 text-right text-indigo-600">{item.output.toLocaleString()}</td><td className="px-8 py-4 text-right text-slate-400">{item.wip.toLocaleString()}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
            <div><h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Order Matrix</h3></div>
            <div className="flex flex-wrap gap-2">
              <FilterButton label="All" active={activeOrderFilter === 'all'} onClick={() => setActiveOrderFilter('all')} color="slate" />
              <FilterButton label="Cutting" active={activeOrderFilter === 'cutting'} onClick={() => setActiveOrderFilter('cutting')} color="blue" />
              <FilterButton label="Sewing" active={activeOrderFilter === 'sewing'} onClick={() => setActiveOrderFilter('sewing')} color="indigo" />
              <button onClick={() => handleDownloadExcel('orders')} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase shadow-lg">Export</button>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest">
                  <tr><th className="px-4 py-5">Unit ID</th><th className="px-4 py-5">Style</th><th className="px-4 py-5 text-right">PO Qty</th><th className="px-4 py-5 text-center">Cut</th><th className="px-4 py-5 text-center">Sew In</th><th className="px-4 py-5 text-center">Sew Out</th><th className="px-4 py-5 text-center">Wash In</th><th className="px-4 py-5 text-center">Wash Out</th><th className="px-4 py-5 text-center">Fin Out</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[11px] font-bold text-slate-700">
                  {aggregatedOrdersData.map(o => (
                    <tr key={o.qr_unique_id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 font-black">{o.qr_unique_id}</td><td className="px-4 py-4 text-blue-600">{o.style}</td><td className="px-4 py-4 text-right">{o.po_qty.toLocaleString()}</td><td className="px-4 py-4 text-center">{o.cut || '-'}</td><td className="px-4 py-4 text-center">{o.sewIn || '-'}</td><td className="px-4 py-4 text-center text-indigo-700">{o.sewOut || '-'}</td><td className="px-4 py-4 text-center">{o.washIn || '-'}</td><td className="px-4 py-4 text-center text-cyan-700">{o.washOut || '-'}</td><td className="px-4 py-4 text-center text-emerald-700">{o.finOut || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-12">
          {/* Small Sized Scan Bar */}
          <div className="bg-white p-4 rounded-2xl shadow-md border border-slate-100">
            <div className="flex items-center space-x-2">
              <div className="relative flex-1">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-sm text-slate-400">🔍</span>
                <input 
                  type="text" 
                  value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Enter or Scan Bundle ID" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-9 pr-3 py-2 font-bold uppercase tracking-wider text-xs focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all outline-none"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button 
                onClick={startScanner} 
                className="bg-blue-600 text-white w-9 h-9 rounded-xl flex items-center justify-center text-base hover:bg-blue-700 shadow-lg shadow-blue-100 transition-transform active:scale-90"
                title="Scan QR Code"
              >
                📷
              </button>
              <button 
                onClick={() => handleQRSearch()} 
                className="bg-slate-900 text-white px-5 h-9 rounded-xl font-black uppercase text-[10px] hover:bg-black shadow-lg transition-all"
              >
                Identify
              </button>
            </div>
            {scanStatus.message && <p className={`mt-2 text-[9px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}
          </div>

          {/* Camera Modal Overlay */}
          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 animate-fadeIn">
              <div className="relative w-full max-w-md aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-64 h-64 border-2 border-blue-500/50 rounded-3xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-8 text-white font-black uppercase tracking-[0.3em] text-[10px]">Scanning for QR Code...</p>
                </div>
                <button onClick={stopScanner} className="absolute top-6 right-6 w-10 h-10 bg-white/10 hover:bg-white/20 rounded-full text-white flex items-center justify-center font-bold">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-4 shadow-2xl">
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1">UNIT IDENTIFIER</p>
                  <p className="text-xl font-black text-blue-400 break-all">{scanningDetail.qr_id}</p>
                </div>
                <DetailItemDark label="Bundle Pcs" value={scanningDetail.bundle_qty.toString()} />
                <DetailItemDark label="Style" value={scanningDetail.style} />
              </div>

              {/* Action Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <ActionSection title="01. Cutting" icon="✂️" color="blue">
                  <button onClick={() => handleQuickPost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-lg active:scale-95 transition-all">Post Cutting Done</button>
                </ActionSection>
                <ActionSection title="02. Sewing" icon="🧵" color="indigo">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={15} onPost={(line) => handleQuickPost('Sewing Input', `Line-${line}`)} color="indigo" />
                    <ProcessGrid title="Output" lines={15} onPost={(line) => handleQuickPost('Sewing Output', `Line-${line}`)} color="emerald" />
                  </div>
                </ActionSection>
                <ActionSection title="03. Wash" icon="🧼" color="cyan">
                   <div className="grid grid-cols-2 gap-3">
                     <button onClick={() => handleQuickPost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash In</button>
                     <button onClick={() => handleQuickPost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash Out</button>
                   </div>
                </ActionSection>
                <ActionSection title="04. Finishing" icon="🏁" color="emerald">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={10} onPost={(line) => handleQuickPost('Finishing Input', `Line-${line}`)} color="violet" />
                    <ProcessGrid title="Output" lines={10} onPost={(line) => handleQuickPost('Finishing Output', `Line-${line}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 uppercase">Scan History</h3>
            <div className="flex space-x-3">
              <button onClick={handleResetAll} className="bg-red-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Reset</button>
              <button onClick={() => handleDownloadExcel('history')} className="bg-slate-900 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Export</button>
            </div>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                 <tr><th className="px-8 py-5">Time</th><th className="px-8 py-5">Unit</th><th className="px-8 py-5">Process</th><th className="px-8 py-5 text-right">Qty</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                 {scans.slice().reverse().map(scan => (
                   <tr key={scan.id} className="hover:bg-slate-50 transition-colors">
                     <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleTimeString()}</td>
                     <td className="px-8 py-4 text-slate-900">{scan.qr_id}</td>
                     <td className="px-8 py-4"><span className="px-3 py-1 bg-slate-100 rounded-full text-[10px] uppercase">{scan.process}</span></td>
                     <td className="px-8 py-4 text-right">{scan.qty}</td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode, color: string }> = ({ title, icon, children }) => (
  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
    <div className="absolute top-2 right-2 opacity-5 text-3xl group-hover:scale-125 transition-transform">{icon}</div>
    <h4 className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">{title}</h4>
    {children}
  </div>
);

const ProcessGrid: React.FC<{ title: string, lines: number, onPost: (l: number) => void, color: string }> = ({ title, lines, onPost, color }) => (
  <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-100">
    <p className={`text-[9px] font-black uppercase text-center mb-3 text-${color}-600 tracking-widest`}>{title}</p>
    <div className="grid grid-cols-3 gap-1.5">
      {Array.from({ length: lines }).map((_, i) => (
        <button key={i} onClick={() => onPost(i + 1)} className="py-2 bg-white border border-slate-200 rounded-lg text-[10px] font-black hover:bg-slate-900 hover:text-white transition-all">{i + 1}</button>
      ))}
