  </div>
);

const DashboardCard: React.FC<{ icon: string, title: string, value: number, color: string, label: string, subMetrics: any[] }> = ({ icon, title, value, color, label, subMetrics }) => {
  const theme = color === 'blue' ? 'text-blue-600 border-t-blue-500 bg-blue-50/30' : color === 'indigo' ? 'text-indigo-600 border-t-indigo-500 bg-indigo-50/30' : color === 'cyan' ? 'text-cyan-600 border-t-cyan-500 bg-cyan-50/30' : 'text-emerald-600 border-t-emerald-500 bg-emerald-50/30';
  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 border-t-4 ${theme.split(' ')[1]} ${theme.split(' ')[2]} hover:shadow-xl transition-all relative overflow-hidden group`}>
      <div className={`absolute -right-4 -top-4 ${theme.split(' ')[0]} opacity-5 group-hover:opacity-10 transition-opacity`}><span className="text-7xl font-black">{label}</span></div>
      <div className="flex items-center space-x-3 mb-4"><div className="w-10 h-10 rounded-xl bg-white shadow-sm flex items-center justify-center text-lg">{icon}</div><p className="text-xs font-black uppercase tracking-tight">{title}</p></div>
      <div className="mb-4"><p className={`text-4xl font-black tracking-tighter ${theme.split(' ')[0]}`}>{value.toLocaleString()}</p></div>
      <div className="space-y-3 pt-4 border-t border-slate-200/50">
        {subMetrics.map((m, i) => (
          <div key={i} className="flex flex-col">
            <div className="flex justify-between items-end mb-1"><p className="text-[9px] font-bold text-slate-400 uppercase">{m.label}</p><p className="text-xs font-black">{m.value}</p></div>
            {m.showProgress && <div className="w-full h-1 bg-white/50 rounded-full overflow-hidden"><div className={`h-full ${theme.split(' ')[0].replace('text-', 'bg-')}`} style={{ width: `${m.value}` }}></div></div>}
          </div>
        ))}
      </div>
    </div>
  );
};

const FilterButton: React.FC<{ label: string, active: boolean, onClick: () => void, color: string }> = ({ label, active, onClick }) => (
  <button onClick={onClick} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'}`}>{label}</button>
);

const DetailItemDark: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div className="group">
    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5 group-hover:text-blue-400">{label}</p>
    <p className="text-sm font-black text-white tracking-tight break-words uppercase">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Enterprise Daily Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

type OrderFilterType = 'all' | 'cutting' | 'sewing' | 'wash' | 'finishing';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [performanceView, setPerformanceView] = useState<'Sewing' | 'Finishing'>('Sewing');
  const [activeOrderFilter, setActiveOrderFilter] = useState<OrderFilterType>('all');

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleResetAll = async () => {
    if (window.confirm("CRITICAL ACTION: Are you sure you want to permanently delete ALL data?")) {
      try {
        await supabase.from('scans').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        await supabase.from('qr_codes').delete().neq('qr_id', 'none');
        await supabase.from('orders').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        setScans([]); setOrders([]); setQrCodes([]);
        setScanStatus({ message: 'Database cleared.', type: 'success' });
      } catch (error) {
        setScanStatus({ message: 'Reset failed.', type: 'error' });
      }
    }
  };

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      cutInput: TARGETS.cutting, cutOutput, cutWIP: Math.max(0, TARGETS.cutting - cutOutput), cutEff: Math.round((cutOutput / TARGETS.cutting) * 100) || 0,
      sewInput, sewOutput, sewWIP: Math.max(0, sewInput - sewOutput), sewEff: Math.round((sewOutput / TARGETS.sewing) * 100) || 0,
      washInput, washOutput, washWIP: Math.max(0, washInput - washOutput), washEff: Math.round((washOutput / TARGETS.wash) * 100) || 0,
      finInput, finOutput, finWIP: Math.max(0, finInput - finOutput), finEff: Math.round((finOutput / TARGETS.finishing) * 100) || 0,
    };
  }, [scans]);

  const aggregatedOrdersData = useMemo(() => {
    const allUniqueQRs = Array.from(new Set([...qrCodes.map(q => q.qr_id), ...scans.map(s => s.qr_id)]));
    return allUniqueQRs.map(qrId => {
      const masterQR = qrCodes.find(q => q.qr_id === qrId);
      const masterOrder = masterQR ? orders.find(o => o.id === masterQR.order_id) : orders.find(o => qrId.includes(o.style)); 
      if (!masterOrder) return null;
      const getP = (p: string) => scans.filter(s => s.qr_id === qrId && s.process === p).reduce((sum, item) => sum + item.qty, 0);
      return {
        qr_unique_id: qrId, timestamp: masterQR?.created_at || scans.find(s => s.qr_id === qrId)?.scan_time || masterOrder.created_at,
        buyer: masterOrder.buyer, style: masterOrder.style, po: masterOrder.po, country: masterOrder.country, color: masterOrder.color,
        size: masterOrder.size, po_qty: masterOrder.po_qty, bundle_qty: masterQR?.bundle_qty || 20,
        cut: getP('Cutting Done'), sewIn: getP('Sewing Input'), sewOut: getP('Sewing Output'),
        washIn: getP('Wash Input'), washOut: getP('Wash Output'), finIn: getP('Finishing Input'), finOut: getP('Finishing Output')
      };
    }).filter((item): item is NonNullable<typeof item> => item !== null);
  }, [orders, qrCodes, scans]);

  const qrProductionHistory = useMemo(() => {
    if (!scanningDetail) return [];
    return scans.filter(s => s.qr_id === scanningDetail.qr_id).sort((a, b) => new Date(a.scan_time).getTime() - new Date(b.scan_time).getTime());
  }, [scanningDetail, scans]);

  const lastCompletedProcess = useMemo(() => qrProductionHistory.length > 0 ? qrProductionHistory[qrProductionHistory.length - 1].process : null, [qrProductionHistory]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const normalizedQR = (qrVal || currentQR).trim().toUpperCase();
    if (!normalizedQR) return;

    const foundQR = qrCodes.find(q => q.qr_id === normalizedQR);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'QR Identified.', type: 'success' });
        return;
      }
    }

    if (normalizedQR.startsWith('PG-')) {
       const matchingOrder = orders.find(o => normalizedQR.includes(o.style));
       setScanningDetail({
         qr_id: normalizedQR,
         order_id: matchingOrder?.id || 'unknown',
         bundle_qty: 20,
         created_at: new Date().toISOString(),
         buyer: matchingOrder?.buyer || 'New Entry',
         style: matchingOrder?.style || 'New Style',
         po: matchingOrder?.po || 'N/A',
         color: matchingOrder?.color || 'N/A',
         country: matchingOrder?.country || 'N/A',
         size: matchingOrder?.size || 'N/A',
         po_qty: matchingOrder?.po_qty || 0
       });
       setScanStatus({ message: 'Bundle Ready.', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid Bundle ID.', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.play();
        requestAnimationFrame(tick);
      }
    } catch (err) {
      setScanStatus({ message: 'Camera access denied.', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const tick = () => {
    if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      if (context) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        context.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'dontInvert' });
        if (code) {
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) requestAnimationFrame(tick);
  };

  const handleQuickPost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;
    const sequence = PROCESS_FLOW;
    const currentIndex = sequence.indexOf(process);
    const lastIndex = lastCompletedProcess ? sequence.indexOf(lastCompletedProcess) : -1;

    if (currentIndex !== lastIndex + 1) {
      setScanStatus({ message: currentIndex <= lastIndex ? `Already at ${process}` : `Expected: ${sequence[lastIndex + 1]}`, type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(), qr_id: scanningDetail.qr_id, process, qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED, line, scanned_by: 'Rakibul', scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Posted ${process} successfully!`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Database sync failed.', type: 'error' });
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm font-black uppercase tracking-widest text-slate-400">Syncing Cloud Database...</p>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-10 animate-fadeIn">
          {/* Dashboard Cards focused on Input, WIP, Effi */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard 
              icon="✂️" title="Cutting Section" 
              value={dashboardStats.cutInput} color="blue" label="CUT" 
              subMetrics={[
                { label: 'WIP', value: dashboardStats.cutWIP.toLocaleString() }, 
                { label: 'EFFICIENCY', value: `${dashboardStats.cutEff}%`, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🧵" title="Sewing Floor" 
              value={dashboardStats.sewInput} color="indigo" label="SEW" 
              subMetrics={[
                { label: 'WIP', value: dashboardStats.sewWIP.toLocaleString() }, 
                { label: 'EFFICIENCY', value: `${dashboardStats.sewEff}%`, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🧼" title="Wash Plant" 
              value={dashboardStats.washInput} color="cyan" label="WSH" 
              subMetrics={[
                { label: 'WIP', value: dashboardStats.washWIP.toLocaleString() }, 
                { label: 'EFFICIENCY', value: `${dashboardStats.washEff}%`, showProgress: true }
              ]} 
            />
            <DashboardCard 
              icon="🏁" title="Finishing Floor" 
              value={dashboardStats.finInput} color="emerald" label="FIN" 
              subMetrics={[
                { label: 'WIP', value: dashboardStats.finWIP.toLocaleString() }, 
                { label: 'EFFICIENCY', value: `${dashboardStats.finEff}%`, showProgress: true }
              ]} 
            />
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 uppercase">Order Matrix</h3>
          </div>
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest">
                  <tr><th className="px-4 py-5">Unit ID</th><th className="px-4 py-5">Style</th><th className="px-4 py-5 text-right">Qty</th><th className="px-4 py-5 text-center">Cut</th><th className="px-4 py-5 text-center">Sew In</th><th className="px-4 py-5 text-center">Sew Out</th><th className="px-4 py-5 text-center">Fin Out</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[11px] font-bold text-slate-700">
                  {aggregatedOrdersData.map(o => (
                    <tr key={o.qr_unique_id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 font-black">{o.qr_unique_id}</td><td className="px-4 py-4">{o.style}</td><td className="px-4 py-4 text-right">{o.po_qty}</td><td className="px-4 py-4 text-center">{o.cut || '-'}</td><td className="px-4 py-4 text-center">{o.sewIn || '-'}</td><td className="px-4 py-4 text-center">{o.sewOut || '-'}</td><td className="px-4 py-4 text-center">{o.finOut || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-12">
          {/* Small Sized Scan Bar */}
          <div className="bg-white p-4 rounded-2xl shadow-md border border-slate-100">
            <div className="flex items-center space-x-2">
              <div className="relative flex-1">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-sm text-slate-400">🔍</span>
                <input 
                  type="text" 
                  value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Enter or Scan Bundle ID" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-9 pr-3 py-2 font-bold uppercase tracking-wider text-xs focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all outline-none"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button 
                onClick={startScanner} 
                className="bg-blue-600 text-white w-9 h-9 rounded-xl flex items-center justify-center text-base hover:bg-blue-700 shadow-lg shadow-blue-100 transition-transform active:scale-90"
                title="Scan QR Code"
              >
                📷
              </button>
              <button 
                onClick={() => handleQRSearch()} 
                className="bg-slate-900 text-white px-5 h-9 rounded-xl font-black uppercase text-[10px] hover:bg-black shadow-lg transition-all"
              >
                Identify
              </button>
            </div>
            {scanStatus.message && <p className={`mt-2 text-[9px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}
          </div>

          {/* Camera Modal Overlay */}
          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 animate-fadeIn">
              <div className="relative w-full max-w-md aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-64 h-64 border-2 border-blue-500/50 rounded-3xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-8 text-white font-black uppercase tracking-[0.3em] text-[10px]">Scanning QR Code...</p>
                </div>
                <button onClick={stopScanner} className="absolute top-6 right-6 w-10 h-10 bg-white/10 hover:bg-white/20 rounded-full text-white flex items-center justify-center font-bold">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-4 shadow-2xl">
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1">UNIT IDENTIFIER</p>
                  <p className="text-xl font-black text-blue-400 break-all">{scanningDetail.qr_id}</p>
                </div>
                <DetailItemDark label="Bundle Pcs" value={scanningDetail.bundle_qty.toString()} />
                <DetailItemDark label="Style" value={scanningDetail.style} />
              </div>

              {/* Action Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <ActionSection title="01. Cutting" icon="✂️" color="blue">
                  <button onClick={() => handleQuickPost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-lg active:scale-95 transition-all">Post Cutting Done</button>
                </ActionSection>
                <ActionSection title="02. Sewing" icon="🧵" color="indigo">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={15} onPost={(line) => handleQuickPost('Sewing Input', `Line-${line}`)} color="indigo" />
                    <ProcessGrid title="Output" lines={15} onPost={(line) => handleQuickPost('Sewing Output', `Line-${line}`)} color="emerald" />
                  </div>
                </ActionSection>
                <ActionSection title="03. Wash" icon="🧼" color="cyan">
                   <div className="grid grid-cols-2 gap-3">
                     <button onClick={() => handleQuickPost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash In</button>
                     <button onClick={() => handleQuickPost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 rounded-2xl font-black uppercase text-[10px] border border-cyan-100 hover:bg-cyan-600 hover:text-white transition-all">Wash Out</button>
                   </div>
                </ActionSection>
                <ActionSection title="04. Finishing" icon="🏁" color="emerald">
                  <div className="grid grid-cols-2 gap-3">
                    <ProcessGrid title="Input" lines={10} onPost={(line) => handleQuickPost('Finishing Input', `Line-${line}`)} color="violet" />
                    <ProcessGrid title="Output" lines={10} onPost={(line) => handleQuickPost('Finishing Output', `Line-${line}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
            <h3 className="text-2xl font-black text-slate-900 uppercase">Scan History</h3>
            <button onClick={handleResetAll} className="bg-red-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase">Reset</button>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
                 <tr><th className="px-8 py-5">Time</th><th className="px-8 py-5">Unit</th><th className="px-8 py-5">Process</th><th className="px-8 py-5 text-right">Qty</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-sm font-bold text-slate-600">
                 {scans.slice().reverse().map(scan => (
                   <tr key={scan.id} className="hover:bg-slate-50 transition-colors">
                     <td className="px-8 py-4 text-slate-400">{new Date(scan.scan_time).toLocaleTimeString()}</td>
                     <td className="px-8 py-4 text-slate-900">{scan.qr_id}</td>
                     <td className="px-8 py-4"><span className="px-3 py-1 bg-slate-100 rounded-full text-[10px] uppercase">{scan.process}</span></td>
                     <td className="px-8 py-4 text-right">{scan.qty}</td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DashboardCard: React.FC<{ icon: string, title: string, value: number, color: string, label: string, subMetrics: any[] }> = ({ icon, title, value, color, label, subMetrics }) => {
  const theme = color === 'blue' ? 'text-blue-600 border-t-blue-500 bg-blue-50/30' : color === 'indigo' ? 'text-indigo-600 border-t-indigo-500 bg-indigo-50/30' : color === 'cyan' ? 'text-cyan-600 border-t-cyan-500 bg-cyan-50/30' : 'text-emerald-600 border-t-emerald-500 bg-emerald-50/30';
  return (
    <div className={`rounded-[2rem] p-6 shadow-sm border border-slate-100 border-t-4 ${theme.split(' ')[1]} ${theme.split(' ')[2]} hover:shadow-xl transition-all relative overflow-hidden group`}>
      <div className={`absolute -right-4 -top-4 ${theme.split(' ')[0]} opacity-5 group-hover:opacity-10 transition-opacity`}><span className="text-7xl font-black">{label}</span></div>
      <div className="flex items-center space-x-3 mb-4"><div className="w-10 h-10 rounded-xl bg-white shadow-sm flex items-center justify-center text-lg">{icon}</div><p className="text-xs font-black uppercase tracking-tight">{title}</p></div>
      <div className="mb-4"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">INPUT</p><p className={`text-4xl font-black tracking-tighter ${theme.split(' ')[0]}`}>{value.toLocaleString()}</p></div>
      <div className="space-y-3 pt-4 border-t border-slate-200/50">
        {subMetrics.map((m, i) => (
          <div key={i} className="flex flex-col">
            <div className="flex justify-between items-end mb-1"><p className="text-[9px] font-bold text-slate-400 uppercase">{m.label}</p><p className="text-xs font-black">{m.value}</p></div>
            {m.showProgress && <div className="w-full h-1 bg-white/50 rounded-full overflow-hidden"><div className={`h-full ${theme.split(' ')[0].replace('text-', 'bg-')}`} style={{ width: `${m.value}` }}></div></div>}
          </div>
        ))}
      </div>
    </div>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode, color: string }> = ({ title, icon, children }) => (
  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
    <div className="absolute top-2 right-2 opacity-5 text-3xl group-hover:scale-125 transition-transform">{icon}</div>
    <h4 className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">{title}</h4>
    {children}
  </div>
);

const ProcessGrid: React.FC<{ title: string, lines: number, onPost: (l: number) => void, color: string }> = ({ title, lines, onPost, color }) => (
  <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-100">
    <p className={`text-[9px] font-black uppercase text-center mb-3 text-${color}-600 tracking-widest`}>{title}</p>
    <div className="grid grid-cols-3 gap-1.5">
      {Array.from({ length: lines }).map((_, i) => (
        <button key={i} onClick={() => onPost(i + 1)} className="py-2 bg-white border border-slate-200 rounded-lg text-[10px] font-black hover:bg-slate-900 hover:text-white transition-all">{i + 1}</button>
      ))}
    </div>
  </div>
);

const DetailItemDark: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div className="group">
    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5 group-hover:text-blue-400">{label}</p>
    <p className="text-sm font-black text-white tracking-tight break-words uppercase">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');
      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const dashboardStats = useMemo(() => {
    const getSum = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cutOutput = getSum('Cutting Done');
    const sewInput = getSum('Sewing Input');
    const sewOutput = getSum('Sewing Output');
    const washInput = getSum('Wash Input');
    const washOutput = getSum('Wash Output');
    const finInput = getSum('Finishing Input');
    const finOutput = getSum('Finishing Output');

    return {
      cut: { input: TARGETS.cutting, wip: Math.max(0, TARGETS.cutting - cutOutput), eff: Math.round((cutOutput / TARGETS.cutting) * 100) || 0 },
      sew: { input: sewInput, wip: Math.max(0, sewInput - sewOutput), eff: Math.round((sewOutput / TARGETS.sewing) * 100) || 0 },
      wash: { input: washInput, wip: Math.max(0, washInput - washOutput), eff: Math.round((washOutput / TARGETS.wash) * 100) || 0 },
      fin: { input: finInput, wip: Math.max(0, finInput - finOutput), eff: Math.round((finOutput / TARGETS.finishing) * 100) || 0 },
    };
  }, [scans]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const val = (qrVal || currentQR).trim().toUpperCase();
    if (!val) return;

    const foundQR = qrCodes.find(q => q.qr_id === val);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'Bundle Identified', type: 'success' });
        return;
      }
    }

    if (val.startsWith('PG-')) {
       const matchingOrder = orders.find(o => val.includes(o.style));
       setScanningDetail({
         qr_id: val, order_id: matchingOrder?.id || 'unknown', bundle_qty: 20,
         created_at: new Date().toISOString(), buyer: matchingOrder?.buyer || 'N/A',
         style: matchingOrder?.style || 'N/A', po: matchingOrder?.po || 'N/A',
         color: matchingOrder?.color || 'N/A', country: matchingOrder?.country || 'N/A',
         size: matchingOrder?.size || 'N/A', po_qty: matchingOrder?.po_qty || 0
       });
       setScanStatus({ message: 'Ready to Track (20pcs)', type: 'success' });
    } else {
      setScanningDetail(null);
      setScanStatus({ message: 'Invalid ID', type: 'error' });
    }
  }, [currentQR, qrCodes, orders]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.play();
        requestAnimationFrame(tick);
      }
    } catch (err) {
      setScanStatus({ message: 'Camera Error', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current?.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
    }
    setIsCameraOpen(false);
  };

  const tick = () => {
    if (videoRef.current?.readyState === videoRef.current?.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const img = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(img.data, img.width, img.height, { inversionAttempts: 'dontInvert' });
        if (code) {
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) requestAnimationFrame(tick);
  };

  const handlePost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;
    const newScan: ScanningData = {
      id: crypto.randomUUID(), qr_id: scanningDetail.qr_id, process, qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED, line, scanned_by: 'Rakibul', scan_time: new Date().toISOString()
    };
    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Data added to ${process}`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Sync failed', type: 'error' });
    }
  };

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-slate-900 text-white">Loading...</div>;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting" stats={dashboardStats.cut} color="blue" />
            <DashboardCard icon="🧵" title="Sewing" stats={dashboardStats.sew} color="indigo" />
            <DashboardCard icon="🧼" title="Wash" stats={dashboardStats.wash} color="cyan" />
            <DashboardCard icon="🏁" title="Finishing" stats={dashboardStats.fin} color="emerald" />
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-12">
          <div className="bg-white p-4 rounded-2xl shadow-md border border-slate-100">
            <div className="flex items-center space-x-2">
              <div className="relative flex-1">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-slate-400">🔍</span>
                <input 
                  type="text" value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Bundle ID" 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-8 pr-3 py-2 text-xs font-bold uppercase outline-none focus:ring-2 focus:ring-blue-100"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button onClick={startScanner} className="bg-blue-600 text-white w-9 h-9 rounded-xl flex items-center justify-center text-sm shadow-md transition-transform active:scale-90">📷</button>
              <button onClick={() => handleQRSearch()} className="bg-slate-900 text-white px-5 h-9 rounded-xl font-black uppercase text-[10px]">Identify</button>
            </div>
            {scanStatus.message && <p className={`mt-2 text-[9px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}
          </div>

          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95">
              <div className="relative w-full max-w-sm aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-48 h-48 border-2 border-blue-500/50 rounded-2xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                </div>
                <button onClick={stopScanner} className="absolute top-4 right-4 w-8 h-8 bg-white/10 rounded-full text-white flex items-center justify-center">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-3xl p-6 grid grid-cols-2 gap-4 shadow-xl">
                <div><p className="text-[9px] font-bold text-slate-500 uppercase">Unit</p><p className="text-sm font-black text-blue-400">{scanningDetail.qr_id}</p></div>
                <div><p className="text-[9px] font-bold text-slate-500 uppercase">Style</p><p className="text-sm font-black">{scanningDetail.style}</p></div>
                <div><p className="text-[9px] font-bold text-slate-500 uppercase">Bundle Pcs</p><p className="text-sm font-black">{scanningDetail.bundle_qty}</p></div>
                <div><p className="text-[9px] font-bold text-slate-500 uppercase">Size</p><p className="text-sm font-black">{scanningDetail.size}</p></div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <ActionSection title="Cutting" icon="✂️">
                  <button onClick={() => handlePost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-lg">Identify & Add to Cutting</button>
                </ActionSection>
                <ActionSection title="Sewing" icon="🧵">
                  <div className="grid grid-cols-2 gap-2">
                    <LineGrid title="Input" lines={15} onSelect={(l) => handlePost('Sewing Input', `Line-${l}`)} color="indigo" />
                    <LineGrid title="Output" lines={15} onSelect={(l) => handlePost('Sewing Output', `Line-${l}`)} color="emerald" />
                  </div>
                </ActionSection>
                <ActionSection title="Wash" icon="🧼">
                  <div className="grid grid-cols-2 gap-2">
                    <button onClick={() => handlePost('Wash Input')} className="py-4 bg-cyan-600 text-white rounded-2xl font-black uppercase text-xs">Wash Input</button>
                    <button onClick={() => handlePost('Wash Output')} className="py-4 bg-cyan-600 text-white rounded-2xl font-black uppercase text-xs">Wash Output</button>
                  </div>
                </ActionSection>
                <ActionSection title="Finishing" icon="🏁">
                  <div className="grid grid-cols-2 gap-2">
                    <LineGrid title="Input" lines={10} onSelect={(l) => handlePost('Finishing Input', `Line-${l}`)} color="violet" />
                    <LineGrid title="Output" lines={10} onSelect={(l) => handlePost('Finishing Output', `Line-${l}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl border border-slate-100 flex justify-between items-center">
            <h3 className="text-xl font-black text-slate-900 uppercase">History</h3>
            <button onClick={() => setScans([])} className="bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold uppercase">Reset</button>
          </div>
          <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black">
                 <tr><th className="px-6 py-4">Time</th><th className="px-6 py-4">Unit</th><th className="px-6 py-4">Process</th><th className="px-6 py-4 text-right">Qty</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-xs font-bold text-slate-600">
                 {scans.slice().reverse().map(s => (
                   <tr key={s.id}>
                     <td className="px-6 py-3 text-slate-400">{new Date(s.scan_time).toLocaleTimeString()}</td>
                     <td className="px-6 py-3">{s.qr_id}</td>
                     <td className="px-6 py-3 uppercase">{s.process}</td>
                     <td className="px-6 py-3 text-right">{s.qty}</td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const DashboardCard: React.FC<{ icon: string, title: string, stats: any, color: string }> = ({ icon, title, stats, color }) => {
  const c = color === 'blue' ? 'text-blue-600 bg-blue-50' : color === 'indigo' ? 'text-indigo-600 bg-indigo-50' : color === 'cyan' ? 'text-cyan-600 bg-cyan-50' : 'text-emerald-600 bg-emerald-50';
  return (
    <div className={`p-6 rounded-3xl border border-slate-100 bg-white shadow-sm hover:shadow-lg transition-all`}>
      <div className="flex items-center space-x-3 mb-4"><span className="text-xl">{icon}</span><h4 className="text-xs font-black uppercase text-slate-400">{title}</h4></div>
      <div className="mb-4"><p className="text-[9px] font-bold text-slate-400 uppercase">Input</p><p className={`text-3xl font-black ${c.split(' ')[0]}`}>{stats.input.toLocaleString()}</p></div>
      <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-100">
        <div><p className="text-[9px] font-bold text-slate-400 uppercase">WIP</p><p className="text-sm font-black">{stats.wip.toLocaleString()}</p></div>
        <div><p className="text-[9px] font-bold text-slate-400 uppercase">Efficiency</p><p className={`text-sm font-black ${c.split(' ')[0]}`}>{stats.eff}%</p></div>
      </div>
    </div>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
    <div className="flex items-center space-x-2 mb-4"><span className="text-lg">{icon}</span><h4 className="text-[10px] font-black uppercase text-slate-400">{title}</h4></div>
    {children}
  </div>
);

const LineGrid: React.FC<{ title: string, lines: number, onSelect: (l: number) => void, color: string }> = ({ title, lines, onSelect, color }) => (
  <div className="bg-slate-50 p-2 rounded-xl">
    <p className="text-[8px] font-black text-center mb-2 uppercase text-slate-400">{title}</p>
    <div className="grid grid-cols-3 gap-1">
      {Array.from({ length: lines }).map((_, i) => (
        <button key={i} onClick={() => onSelect(i + 1)} className="py-1.5 bg-white border border-slate-200 rounded text-[9px] font-black hover:bg-slate-900 hover:text-white transition-all">{i + 1}</button>
      ))}
    </div>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Standard Enterprise Targets
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*');
      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Supabase Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Dashboard Aggregation: Input, WIP, Effi
  const dashboardStats = useMemo(() => {
    const getOutput = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const getInput = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);

    const cutOut = getOutput('Cutting Done');
    const sewIn = getInput('Sewing Input');
    const sewOut = getOutput('Sewing Output');
    const washIn = getInput('Wash Input');
    const washOut = getOutput('Wash Output');
    const finIn = getInput('Finishing Input');
    const finOut = getOutput('Finishing Output');

    return {
      cut: { input: TARGETS.cutting, wip: Math.max(0, TARGETS.cutting - cutOut), eff: Math.round((cutOut / TARGETS.cutting) * 100) || 0 },
      sew: { input: sewIn, wip: Math.max(0, sewIn - sewOut), eff: Math.round((sewOut / TARGETS.sewing) * 100) || 0 },
      wash: { input: washIn, wip: Math.max(0, washIn - washOut), eff: Math.round((washOut / TARGETS.wash) * 100) || 0 },
      fin: { input: finIn, wip: Math.max(0, finIn - finOut), eff: Math.round((finOut / TARGETS.finishing) * 100) || 0 },
    };
  }, [scans]);

  // Orders Aggregation: Multi-column Matrix (Buyer, Style, PO, Country, Color, Size, Qty, Processes)
  const orderMatrix = useMemo(() => {
    // We group by order ID or combined attributes to show progress
    return orders.map(order => {
      const relatedQRs = qrCodes.filter(q => q.order_id === order.id).map(q => q.qr_id);

      const getSum = (proc: string) => {
        return scans
          .filter(s => relatedQRs.includes(s.qr_id) && s.process === proc)
          .reduce((sum, item) => sum + item.qty, 0);
      };

      return {
        ...order,
        cut: getSum('Cutting Done'),
        sewIn: getSum('Sewing Input'),
        sewOut: getSum('Sewing Output'),
        washIn: getSum('Wash Input'),
        washOut: getSum('Wash Output'),
        finIn: getSum('Finishing Input'),
        finOut: getSum('Finishing Output')
      };
    });
  }, [orders, qrCodes, scans]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const val = (qrVal || currentQR).trim().toUpperCase();
    if (!val) return;

    // 1. Find in QR Master
    const foundQR = qrCodes.find(q => q.qr_id === val);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'Bundle Verified', type: 'success' });
        return;
      }
    }

    // 2. Fallback: Dynamic matching for PG-prefixed codes if order exists by style
    if (val.startsWith('PG-')) {
       const styleGuess = orders.find(o => val.includes(o.style));
       if (styleGuess) {
         setScanningDetail({
           qr_id: val, order_id: styleGuess.id, bundle_qty: 20,
           created_at: new Date().toISOString(), ...styleGuess
         });
         setScanStatus({ message: 'Dynamic Bundle Match (20pcs)', type: 'success' });
         return;
       }
    }

    setScanningDetail(null);
    setScanStatus({ message: 'Unknown Bundle ID', type: 'error' });
  }, [currentQR, qrCodes, orders]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.play();
        requestAnimationFrame(tick);
      }
    } catch (err) {
      setScanStatus({ message: 'Camera Access Failed', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current?.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
    }
    setIsCameraOpen(false);
  };

  const tick = () => {
    if (videoRef.current?.readyState === videoRef.current?.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const img = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(img.data, img.width, img.height, { inversionAttempts: 'dontInvert' });
        if (code) {
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) requestAnimationFrame(tick);
  };

  const handlePost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) {
      setScanStatus({ message: 'No Bundle Identified', type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Added ${scanningDetail.bundle_qty} pcs to ${process}`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Cloud Sync Failed', type: 'error' });
    }
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-slate-950 text-white font-bold uppercase tracking-widest text-xs">
      <div className="w-12 h-12 border-2 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
      Syncing Database...
    </div>
  );

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Section" stats={dashboardStats.cut} color="blue" label="CUT" />
            <DashboardCard icon="🧵" title="Sewing Floor" stats={dashboardStats.sew} color="indigo" label="SEW" />
            <DashboardCard icon="🧼" title="Wash Plant" stats={dashboardStats.wash} color="cyan" label="WSH" />
            <DashboardCard icon="🏁" title="Finishing Floor" stats={dashboardStats.fin} color="emerald" label="FIN" />
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl border border-slate-100 flex justify-between items-center shadow-sm">
            <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Order Production Matrix</h3>
            <button onClick={fetchData} className="bg-slate-100 text-slate-600 px-4 py-2 rounded-xl text-[10px] font-black uppercase hover:bg-slate-200">Refresh</button>
          </div>
          <div className="bg-white rounded-3xl border border-slate-100 shadow-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest">
                  <tr>
                    <th className="px-4 py-5 border-r border-slate-800">Buyer</th>
                    <th className="px-4 py-5 border-r border-slate-800">Style</th>
                    <th className="px-4 py-5 border-r border-slate-800">PO #</th>
                    <th className="px-4 py-5 border-r border-slate-800">Country</th>
                    <th className="px-4 py-5 border-r border-slate-800">Color</th>
                    <th className="px-4 py-5 border-r border-slate-800">Size</th>
                    <th className="px-4 py-5 border-r border-slate-800 text-right">PO Qty</th>
                    <th className="px-4 py-5 text-center bg-blue-900">Cut Out</th>
                    <th className="px-4 py-5 text-center bg-indigo-900">Sew In</th>
                    <th className="px-4 py-5 text-center bg-indigo-800">Sew Out</th>
                    <th className="px-4 py-5 text-center bg-cyan-900">Wash In</th>
                    <th className="px-4 py-5 text-center bg-cyan-800">Wash Out</th>
                    <th className="px-4 py-5 text-center bg-emerald-900">Fin Out</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-[10px] font-bold text-slate-700">
                  {orderMatrix.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 border-r border-slate-50">{item.buyer}</td>
                      <td className="px-4 py-4 border-r border-slate-50 text-blue-600">{item.style}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.po}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.country}</td>
                      <td className="px-4 py-4 border-r border-slate-50 uppercase">{item.color}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.size}</td>
                      <td className="px-4 py-4 border-r border-slate-50 text-right">{item.po_qty.toLocaleString()}</td>
                      <td className="px-4 py-4 text-center font-black bg-blue-50 text-blue-700">{item.cut || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-indigo-50/30">{item.sewIn || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-indigo-50 text-indigo-700">{item.sewOut || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-cyan-50/30">{item.washIn || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-cyan-50 text-cyan-700">{item.washOut || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-emerald-50 text-emerald-700">{item.finOut || '-'}</td>
                    </tr>
                  ))}
                  {orderMatrix.length === 0 && (
                    <tr><td colSpan={13} className="px-4 py-10 text-center text-slate-400 font-medium">No active orders found in the production matrix.</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-24">
          {/* Ultra Compact Scan Bar */}
          <div className="flex justify-center">
            <div className="bg-white p-2 rounded-2xl shadow-lg border border-slate-100 flex items-center space-x-2 w-full max-w-sm">
              <div className="relative flex-1">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-slate-400">🔍</span>
                <input 
                  type="text" value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Scan Bundle ID" 
                  className="w-full bg-slate-50 border border-slate-100 rounded-xl pl-8 pr-2 py-1.5 text-[11px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button onClick={startScanner} className="bg-blue-600 text-white w-8 h-8 rounded-xl flex items-center justify-center text-sm shadow-md transition-all active:scale-90 hover:bg-blue-700">📷</button>
              <button onClick={() => handleQRSearch()} className="bg-slate-900 text-white px-4 h-8 rounded-xl font-black uppercase text-[9px] hover:bg-black">ID</button>
            </div>
          </div>
          {scanStatus.message && <p className={`text-[9px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}

          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95">
              <div className="relative w-full max-w-sm aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-48 h-48 border-2 border-blue-500/50 rounded-2xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-6 text-white text-[10px] font-black uppercase tracking-[0.3em]">Position QR in frame</p>
                </div>
                <button onClick={stopScanner} className="absolute top-4 right-4 w-8 h-8 bg-white/10 rounded-full text-white flex items-center justify-center font-bold">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-6 shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">BUNDLE UNIT</p>
                  <p className="text-xl font-black text-blue-400 break-all">{scanningDetail.qr_id}</p>
                </div>
                <div className="border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">PCS</p>
                  <p className="text-xl font-black">{scanningDetail.bundle_qty}</p>
                </div>
                <div>
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">STYLE</p>
                  <p className="text-lg font-black truncate">{scanningDetail.style}</p>
                </div>
                <div className="col-span-4 mt-2 flex flex-wrap gap-2">
                   <Tag label="PO" value={scanningDetail.po} />
                   <Tag label="Color" value={scanningDetail.color} />
                   <Tag label="Size" value={scanningDetail.size} />
                   <Tag label="Buyer" value={scanningDetail.buyer} />
                </div>
              </div>

              {/* Action Grid: Add information to order chart process wise */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <ActionSection title="01. Cutting Process" icon="✂️">
                  <button onClick={() => handlePost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-xl shadow-blue-200 active:scale-95 transition-all">Add to Cutting Chart</button>
                </ActionSection>

                <ActionSection title="02. Sewing Section" icon="🧵">
                  <div className="grid grid-cols-2 gap-3">
                    <LinePicker title="In (Line 1-15)" count={15} onSelect={(l) => handlePost('Sewing Input', `Line-${l}`)} color="indigo" />
                    <LinePicker title="Out (Line 1-15)" count={15} onSelect={(l) => handlePost('Sewing Output', `Line-${l}`)} color="emerald" />
                  </div>
                </ActionSection>

                <ActionSection title="03. Wash Plant" icon="🧼">
                  <div className="grid grid-cols-2 gap-3">
                    <button onClick={() => handlePost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 border border-cyan-100 rounded-2xl font-black uppercase text-[10px] hover:bg-cyan-600 hover:text-white transition-all">Wash Input</button>
                    <button onClick={() => handlePost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 border border-cyan-100 rounded-2xl font-black uppercase text-[10px] hover:bg-cyan-600 hover:text-white transition-all">Wash Output</button>
                  </div>
                </ActionSection>

                <ActionSection title="04. Finishing Section" icon="🏁">
                  <div className="grid grid-cols-2 gap-3">
                    <LinePicker title="In (Line 1-10)" count={10} onSelect={(l) => handlePost('Finishing Input', `Line-${l}`)} color="violet" />
                    <LinePicker title="Out (Line 1-10)" count={10} onSelect={(l) => handlePost('Finishing Output', `Line-${l}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl border border-slate-100 flex justify-between items-center shadow-sm">
            <h3 className="text-xl font-black text-slate-900 uppercase">Scan History Log</h3>
            <button onClick={() => setScans([])} className="bg-red-600 text-white px-6 py-2 rounded-xl text-xs font-bold uppercase shadow-lg shadow-red-200">Clear Logs</button>
          </div>
          <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black">
                 <tr><th className="px-8 py-5">Time</th><th className="px-8 py-5">Bundle ID</th><th className="px-8 py-5">Process</th><th className="px-8 py-5 text-right">Qty</th><th className="px-8 py-5">Line</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-xs font-bold text-slate-600">
                 {scans.slice().reverse().map(s => (
                   <tr key={s.id} className="hover:bg-slate-50">
                     <td className="px-8 py-4 text-slate-400">{new Date(s.scan_time).toLocaleTimeString()}</td>
                     <td className="px-8 py-4 text-slate-900">{s.qr_id}</td>
                     <td className="px-8 py-4 uppercase"><span className="bg-slate-100 px-3 py-1 rounded-full">{s.process}</span></td>
                     <td className="px-8 py-4 text-right font-black">{s.qty}</td>
                     <td className="px-8 py-4 text-slate-400">{s.line}</td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const Tag: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <span className="bg-slate-800 px-3 py-1 rounded-lg text-[10px] font-bold border border-slate-700">
    <span className="text-slate-500 mr-1 uppercase">{label}:</span>
    <span className="text-blue-200 uppercase">{value}</span>
  </span>
);

const DashboardCard: React.FC<{ icon: string, title: string, stats: any, color: string, label: string }> = ({ icon, title, stats, color, label }) => {
  const c = color === 'blue' ? 'text-blue-600 border-t-blue-500' : color === 'indigo' ? 'text-indigo-600 border-t-indigo-500' : color === 'cyan' ? 'text-cyan-600 border-t-cyan-500' : 'text-emerald-600 border-t-emerald-500';
  return (
    <div className={`p-6 rounded-[2rem] border border-slate-100 border-t-4 bg-white shadow-sm hover:shadow-xl transition-all relative group overflow-hidden ${c.split(' ')[1]}`}>
      <div className={`absolute -right-2 -top-2 ${c.split(' ')[0]} opacity-5 text-6xl font-black transition-transform group-hover:scale-110`}>{label}</div>
      <div className="flex items-center space-x-3 mb-6">
        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-xl shadow-inner">{icon}</div>
        <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{title}</h4>
      </div>
      <div className="space-y-4">
        <div>
          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">INPUT (PCS)</p>
          <p className={`text-3xl font-black ${c.split(' ')[0]}`}>{stats.input.toLocaleString()}</p>
        </div>
        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-50">
          <div><p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">WIP</p><p className="text-sm font-black text-slate-800">{stats.wip.toLocaleString()}</p></div>
          <div><p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">EFFI</p><p className={`text-sm font-black ${c.split(' ')[0]}`}>{stats.eff}%</p></div>
        </div>
      </div>
    </div>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
    <div className="flex items-center space-x-3 mb-5">
      <div className="w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-lg">{icon}</div>
      <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{title}</h4>
    </div>
    {children}
  </div>
);

const LinePicker: React.FC<{ title: string, count: number, onSelect: (l: number) => void, color: string }> = ({ title, count, onSelect, color }) => (
  <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-50">
    <p className={`text-[8px] font-black text-center mb-2 uppercase tracking-widest text-${color}-600`}>{title}</p>
    <div className="grid grid-cols-3 gap-1">
      {Array.from({ length: count }).map((_, i) => (
        <button key={i} onClick={() => onSelect(i + 1)} className="py-2 bg-white border border-slate-200 rounded-lg text-[9px] font-black hover:bg-slate-900 hover:text-white transition-all active:scale-90">{i + 1}</button>
      ))}
    </div>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Enterprise Daily Targets for Efficiency Calculation
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(null);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*').order('scan_time', { ascending: false });

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Supabase Sync Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Dashboard Metrics: Input, WIP, Effi
  const dashboardStats = useMemo(() => {
    const getQty = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);

    const cutOut = getQty('Cutting Done');
    const sewIn = getQty('Sewing Input');
    const sewOut = getQty('Sewing Output');
    const washIn = getQty('Wash Input');
    const washOut = getQty('Wash Output');
    const finIn = getQty('Finishing Input');
    const finOut = getQty('Finishing Output');

    return {
      cut: { input: TARGETS.cutting, wip: Math.max(0, TARGETS.cutting - cutOut), eff: Math.round((cutOut / TARGETS.cutting) * 100) || 0 },
      sew: { input: sewIn, wip: Math.max(0, sewIn - sewOut), eff: Math.round((sewOut / TARGETS.sewing) * 100) || 0 },
      wash: { input: washIn, wip: Math.max(0, washIn - washOut), eff: Math.round((washOut / TARGETS.wash) * 100) || 0 },
      fin: { input: finIn, wip: Math.max(0, finIn - finOut), eff: Math.round((finOut / TARGETS.finishing) * 100) || 0 },
    };
  }, [scans]);

  // Comprehensive Order Production Matrix
  const orderMatrix = useMemo(() => {
    return orders.map(order => {
      // Find all QRs belonging to this order
      const relatedQRs = qrCodes.filter(q => q.order_id === order.id).map(q => q.qr_id);

      const getSum = (proc: string) => {
        return scans
          .filter(s => relatedQRs.includes(s.qr_id) && s.process === proc)
          .reduce((sum, item) => sum + item.qty, 0);
      };

      return {
        ...order,
        cutOut: getSum('Cutting Done'),
        sewIn: getSum('Sewing Input'),
        sewOut: getSum('Sewing Output'),
        washIn: getSum('Wash Input'),
        washOut: getSum('Wash Output'),
        finIn: getSum('Finishing Input'),
        finOut: getSum('Finishing Output')
      };
    });
  }, [orders, qrCodes, scans]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const val = (qrVal || currentQR).trim().toUpperCase();
    if (!val) return;

    // 1. Search in QR database
    const foundQR = qrCodes.find(q => q.qr_id === val);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'Bundle Linked Successfully', type: 'success' });
        return;
      }
    }

    // 2. Generic Bundle Handler (for simulation/unregistered IDs starting with PG-)
    if (val.startsWith('PG-')) {
       const styleGuess = orders.find(o => val.includes(o.style)) || orders[0];
       if (styleGuess) {
         setScanningDetail({
           qr_id: val, order_id: styleGuess.id, bundle_qty: 20,
           created_at: new Date().toISOString(), ...styleGuess
         });
         setScanStatus({ message: 'Auto-Matched to Order (20pcs)', type: 'success' });
         return;
       }
    }

    setScanningDetail(null);
    setScanStatus({ message: 'Bundle ID Not Found', type: 'error' });
  }, [currentQR, qrCodes, orders]);

  // Robust QR Scanning Logic
  const tick = useCallback(() => {
    if (videoRef.current?.readyState === videoRef.current?.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (ctx) {
        canvas.height = videoRef.current.videoHeight;
        canvas.width = videoRef.current.videoWidth;
        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const img = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(img.data, img.width, img.height, { inversionAttempts: 'attemptBoth' });

        if (code) {
          console.log("QR Found:", code.data);
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    if (isCameraOpen) {
      requestRef.current = requestAnimationFrame(tick);
    }
  }, [isCameraOpen, handleQRSearch]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    setScanStatus({ message: 'Starting Camera...', type: null });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        await videoRef.current.play();
        requestRef.current = requestAnimationFrame(tick);
      }
    } catch (err) {
      console.error("Camera Error:", err);
      setScanStatus({ message: 'Camera Permission Required', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const stopScanner = () => {
    if (videoRef.current?.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      videoRef.current.srcObject = null;
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    setIsCameraOpen(false);
  };

  const handlePost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) {
      setScanStatus({ message: 'Identify Bundle First', type: 'error' });
      return;
    }

    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Successfully Added to ${process}`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Cloud Sync Failed', type: 'error' });
    }
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-slate-950 text-white">
      <div className="w-10 h-10 border-2 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="text-[10px] font-black uppercase tracking-[0.2em]">Initialising Cloud Link...</p>
    </div>
  );

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Section" stats={dashboardStats.cut} color="blue" label="CUT" />
            <DashboardCard icon="🧵" title="Sewing Floor" stats={dashboardStats.sew} color="indigo" label="SEW" />
            <DashboardCard icon="🧼" title="Wash Plant" stats={dashboardStats.wash} color="cyan" label="WSH" />
            <DashboardCard icon="🏁" title="Finishing Floor" stats={dashboardStats.fin} color="emerald" label="FIN" />
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl border border-slate-100 flex justify-between items-center shadow-sm">
            <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Production Order Matrix</h3>
            <button onClick={fetchData} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg">Refresh Sync</button>
          </div>
          <div className="bg-white rounded-3xl border border-slate-100 shadow-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-900 text-white uppercase text-[9px] font-black tracking-widest whitespace-nowrap">
                  <tr>
                    <th className="px-4 py-5 border-r border-slate-800">Buyer</th>
                    <th className="px-4 py-5 border-r border-slate-800">Style</th>
                    <th className="px-4 py-5 border-r border-slate-800">PO #</th>
                    <th className="px-4 py-5 border-r border-slate-800">Country</th>
                    <th className="px-4 py-5 border-r border-slate-800">Color</th>
                    <th className="px-4 py-5 border-r border-slate-800">Size</th>
                    <th className="px-4 py-5 border-r border-slate-800 text-right">PO Qty</th>
                    <th className="px-4 py-5 text-center bg-blue-900">Cut Out</th>
                    <th className="px-4 py-5 text-center bg-indigo-900">Sew In</th>
                    <th className="px-4 py-5 text-center bg-indigo-800">Sew Out</th>
                    <th className="px-4 py-5 text-center bg-cyan-900">Wash In</th>
                    <th className="px-4 py-5 text-center bg-cyan-800">Wash Out</th>
                    <th className="px-4 py-5 text-center bg-emerald-900">Fin In</th>
                    <th className="px-4 py-5 text-center bg-emerald-800">Fin Out</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[10px] font-bold text-slate-700">
                  {orderMatrix.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 border-r border-slate-50">{item.buyer}</td>
                      <td className="px-4 py-4 border-r border-slate-50 text-blue-600 font-black">{item.style}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.po}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.country}</td>
                      <td className="px-4 py-4 border-r border-slate-50 uppercase text-slate-500">{item.color}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.size}</td>
                      <td className="px-4 py-4 border-r border-slate-50 text-right font-black">{item.po_qty.toLocaleString()}</td>
                      <td className="px-4 py-4 text-center font-black bg-blue-50/50 text-blue-700">{item.cutOut || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-indigo-50/20">{item.sewIn || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-indigo-50/40 text-indigo-700">{item.sewOut || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-cyan-50/20">{item.washIn || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-cyan-50/40 text-cyan-700">{item.washOut || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-emerald-50/20">{item.finIn || '-'}</td>
                      <td className="px-4 py-4 text-center font-black bg-emerald-50/40 text-emerald-700">{item.finOut || '-'}</td>
                    </tr>
                  ))}
                  {orderMatrix.length === 0 && (
                    <tr><td colSpan={14} className="px-4 py-12 text-center text-slate-400">No production data available.</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-24">
          {/* Ultra Compact Scan Bar - Small Length and Width */}
          <div className="flex justify-center">
            <div className="bg-white p-1.5 rounded-2xl shadow-xl border border-slate-100 flex items-center space-x-1 w-64 md:w-72">
              <div className="relative flex-1">
                <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-[10px] text-slate-400">🔍</span>
                <input 
                  type="text" value={currentQR} 
                  onChange={(e) => setCurrentQR(e.target.value)} 
                  placeholder="Bundle ID" 
                  className="w-full bg-slate-50 border border-transparent rounded-xl pl-7 pr-2 py-1.5 text-[10px] font-black uppercase outline-none focus:bg-white focus:ring-1 focus:ring-blue-400 transition-all"
                  onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
                />
              </div>
              <button 
                onClick={startScanner} 
                className="bg-blue-600 text-white w-7 h-7 rounded-xl flex items-center justify-center text-xs shadow-md hover:bg-blue-700 transition-transform active:scale-90"
                title="Scan QR"
              >
                📷
              </button>
              <button 
                onClick={() => handleQRSearch()} 
                className="bg-slate-900 text-white px-3 h-7 rounded-xl font-black uppercase text-[8px] hover:bg-black"
              >
                OK
              </button>
            </div>
          </div>
          {scanStatus.message && <p className={`text-[9px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{scanStatus.message}</p>}

          {/* Camera Modal Overlay */}
          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95">
              <div className="relative w-full max-w-sm aspect-square bg-slate-900 rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-56 h-56 border-2 border-blue-500/50 rounded-3xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-8 text-white text-[9px] font-black uppercase tracking-[0.4em]">Align QR Code</p>
                </div>
                <button onClick={stopScanner} className="absolute top-4 right-4 w-10 h-10 bg-white/10 rounded-full text-white flex items-center justify-center text-xl font-bold hover:bg-white/20">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              {/* Bundle Context Card */}
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-6 shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-40 h-40 bg-blue-600/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">BUNDLE ID</p>
                  <p className="text-xl font-black text-blue-400 truncate">{scanningDetail.qr_id}</p>
                </div>
                <div className="border-r border-slate-800 pr-4">
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">QTY</p>
                  <p className="text-xl font-black">{scanningDetail.bundle_qty} PCS</p>
                </div>
                <div>
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">STYLE</p>
                  <p className="text-lg font-black truncate">{scanningDetail.style}</p>
                </div>
                <div className="col-span-4 mt-2 flex flex-wrap gap-2">
                   <Tag label="PO" value={scanningDetail.po} />
                   <Tag label="Color" value={scanningDetail.color} />
                   <Tag label="Size" value={scanningDetail.size} />
                   <Tag label="Country" value={scanningDetail.country} />
                </div>
              </div>

              {/* Action Grid: Reflecting in Dashboard and Order Matrix */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <ActionSection title="01. Cutting Process" icon="✂️">
                  <button onClick={() => handlePost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-xl shadow-blue-200 active:scale-95 transition-all">Mark Cutting Complete</button>
                </ActionSection>

                <ActionSection title="02. Sewing Section" icon="🧵">
                  <div className="grid grid-cols-2 gap-3">
                    <LinePicker title="Input (1-15)" count={15} onSelect={(l) => handlePost('Sewing Input', `Line-${l}`)} color="indigo" />
                    <LinePicker title="Output (1-15)" count={15} onSelect={(l) => handlePost('Sewing Output', `Line-${l}`)} color="emerald" />
                  </div>
                </ActionSection>

                <ActionSection title="03. Wash Plant" icon="🧼">
                  <div className="grid grid-cols-2 gap-3">
                    <button onClick={() => handlePost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 border border-cyan-100 rounded-2xl font-black uppercase text-[10px] hover:bg-cyan-600 hover:text-white shadow-sm transition-all">Wash Input</button>
                    <button onClick={() => handlePost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 border border-cyan-100 rounded-2xl font-black uppercase text-[10px] hover:bg-cyan-600 hover:text-white shadow-sm transition-all">Wash Output</button>
                  </div>
                </ActionSection>

                <ActionSection title="04. Finishing Section" icon="🏁">
                  <div className="grid grid-cols-2 gap-3">
                    <LinePicker title="Input (1-10)" count={10} onSelect={(l) => handlePost('Finishing Input', `Line-${l}`)} color="violet" />
                    <LinePicker title="Output (1-10)" count={10} onSelect={(l) => handlePost('Finishing Output', `Line-${l}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-3xl border border-slate-100 flex justify-between items-center shadow-sm">
            <h3 className="text-xl font-black text-slate-900 uppercase">Live Log</h3>
            <button onClick={fetchData} className="bg-blue-600 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase">Refresh Log</button>
          </div>
          <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[9px] font-black">
                 <tr><th className="px-6 py-4">Scan Time</th><th className="px-6 py-4">Bundle ID</th><th className="px-6 py-4">Process</th><th className="px-6 py-4 text-right">Qty</th><th className="px-6 py-4">Line</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-[11px] font-bold text-slate-600">
                 {scans.map(s => (
                   <tr key={s.id} className="hover:bg-slate-50">
                     <td className="px-6 py-3 text-slate-400 font-medium">{new Date(s.scan_time).toLocaleString()}</td>
                     <td className="px-6 py-3 font-black text-slate-900">{s.qr_id}</td>
                     <td className="px-6 py-3 uppercase"><span className="bg-slate-100 px-3 py-1 rounded-full">{s.process}</span></td>
                     <td className="px-6 py-3 text-right font-black">{s.qty}</td>
                     <td className="px-6 py-3 text-slate-400">{s.line}</td>
                   </tr>
                 ))}
                 {scans.length === 0 && (
                   <tr><td colSpan={5} className="px-6 py-10 text-center text-slate-400">No recent scan activity found.</td></tr>
                 )}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const Tag: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <span className="bg-slate-800 px-3 py-1 rounded-lg text-[9px] font-bold border border-slate-700">
    <span className="text-slate-500 mr-1 uppercase">{label}:</span>
    <span className="text-blue-200 uppercase">{value}</span>
