        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-xl shadow-inner">{icon}</div>
        <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{title}</h4>
      </div>
      <div className="space-y-4">
        <div>
          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">INPUT PCS</p>
          <p className={`text-3xl font-black ${c.split(' ')[0]}`}>{stats.input.toLocaleString()}</p>
        </div>
        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-50">
          <div><p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">WIP</p><p className="text-sm font-black text-slate-800">{stats.wip.toLocaleString()}</p></div>
          <div><p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">EFFICIENCY</p><p className={`text-sm font-black ${c.split(' ')[0]}`}>{stats.eff}%</p></div>
        </div>
      </div>
    </div>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
    <div className="flex items-center space-x-3 mb-5">
      <div className="w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-lg">{icon}</div>
      <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{title}</h4>
