);

const LinePicker: React.FC<{ title: string, count: number, onSelect: (l: number) => void, color: string }> = ({ title, count, onSelect, color }) => (
  <div className="bg-slate-50/50 p-2 rounded-2xl border border-slate-50">
    <p className={`text-[7px] font-black text-center mb-2 uppercase tracking-widest text-slate-400`}>{title}</p>
    <div className="grid grid-cols-3 gap-1">
      {Array.from({ length: count }).map((_, i) => (
        <button key={i} onClick={() => onSelect(i + 1)} className="py-1.5 bg-white border border-slate-100 rounded-lg text-[8px] font-black hover:bg-slate-900 hover:text-white transition-all active:scale-90">{i + 1}</button>
      ))}
    </div>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import jsQR from 'jsqr';
import { 
  OrderMaster, 
  QRMaster, 
  ScanningData, 
  QRDetail, 
  ProductionProcess, 
  ProductionStatus 
} from './types';
import { PROCESS_FLOW } from './constants';
import Layout from './components/Layout';
import ProductionChart from './components/ProductionChart';
import { supabase } from './services/supabase';

// Production Targets for Efficiency calculation
const TARGETS = {
  cutting: 15000,
  sewing: 15000,
  wash: 15000,
  finishing: 15000
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<OrderMaster[]>([]);
  const [qrCodes, setQrCodes] = useState<QRMaster[]>([]);
  const [scans, setScans] = useState<ScanningData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [currentQR, setCurrentQR] = useState<string>('');
  const [scanningDetail, setScanningDetail] = useState<QRDetail | null>(null);
  const [scanStatus, setScanStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: orderData } = await supabase.from('orders').select('*');
      const { data: qrData } = await supabase.from('qr_codes').select('*');
      const { data: scanData } = await supabase.from('scans').select('*').order('scan_time', { ascending: false });

      if (orderData) setOrders(orderData);
      if (qrData) setQrCodes(qrData);
      if (scanData) setScans(scanData);
    } catch (error) {
      console.error("Supabase Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Aggregated Production Matrix for Orders Tab
  const orderMatrix = useMemo(() => {
    return orders.map(order => {
      // Find all QRs belonging to this order
      const relatedQRIds = qrCodes.filter(q => q.order_id === order.id).map(q => q.qr_id);

      const getSum = (proc: string) => {
        return scans
          .filter(s => {
            // Match by formal QR registration OR if the scan's QR ID contains the Style name (as a fallback)
            const isFormalMatch = relatedQRIds.includes(s.qr_id);
            const isStyleMatch = s.qr_id.toUpperCase().includes(order.style.toUpperCase());
            return (isFormalMatch || isStyleMatch) && s.process === proc;
          })
          .reduce((sum, item) => sum + item.qty, 0);
      };

      return {
        ...order,
        cut: getSum('Cutting Done'),
        sewIn: getSum('Sewing Input'),
        sewOut: getSum('Sewing Output'),
        washIn: getSum('Wash Input'),
        washOut: getSum('Wash Output'),
        finIn: getSum('Finishing Input'),
        finOut: getSum('Finishing Output')
      };
    });
  }, [orders, qrCodes, scans]);

  // Dashboard Stats
  const dashboardStats = useMemo(() => {
    const totalByProc = (proc: string) => scans.filter(s => s.process === proc).reduce((sum, item) => sum + item.qty, 0);
    const cut = totalByProc('Cutting Done');
    const sewIn = totalByProc('Sewing Input');
    const sewOut = totalByProc('Sewing Output');
    const washIn = totalByProc('Wash Input');
    const washOut = totalByProc('Wash Output');
    const finIn = totalByProc('Finishing Input');
    const finOut = totalByProc('Finishing Output');

    return {
      cut: { input: TARGETS.cutting, wip: Math.max(0, TARGETS.cutting - cut), eff: Math.round((cut / TARGETS.cutting) * 100) || 0 },
      sew: { input: sewIn, wip: Math.max(0, sewIn - sewOut), eff: Math.round((sewOut / TARGETS.sewing) * 100) || 0 },
      wash: { input: washIn, wip: Math.max(0, washIn - washOut), eff: Math.round((washOut / TARGETS.wash) * 100) || 0 },
      fin: { input: finIn, wip: Math.max(0, finIn - finOut), eff: Math.round((finOut / TARGETS.finishing) * 100) || 0 },
    };
  }, [scans]);

  const handleQRSearch = useCallback((qrVal?: string) => {
    const val = (qrVal || currentQR).trim().toUpperCase();
    if (!val) return;

    // Explicit requirement: Must start with PG-
    if (!val.startsWith('PG-')) {
      setScanStatus({ message: 'Invalid ID: Prefix PG- required', type: 'error' });
      setScanningDetail(null);
      return;
    }

    // 1. Search in formal QR registry
    const foundQR = qrCodes.find(q => q.qr_id === val);
    if (foundQR) {
      const order = orders.find(o => o.id === foundQR.order_id);
      if (order) {
        setScanningDetail({ ...foundQR, ...order });
        setScanStatus({ message: 'Bundle Recognized', type: 'success' });
        return;
      }
    }

    // 2. Fallback: Heuristic matching (if the scanned ID contains a known Style name)
    const styleMatch = orders.find(o => val.includes(o.style.toUpperCase()));
    if (styleMatch) {
      setScanningDetail({
        qr_id: val,
        order_id: styleMatch.id,
        bundle_qty: 20, // Default bundle size for unidentified codes
        created_at: new Date().toISOString(),
        ...styleMatch
      });
      setScanStatus({ message: 'Linked via Style Match', type: 'success' });
      return;
    }

    setScanningDetail(null);
    setScanStatus({ message: 'ID number not recognized in DB', type: 'error' });
  }, [currentQR, qrCodes, orders]);

  const stopScanner = useCallback(() => {
    if (videoRef.current?.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      videoRef.current.srcObject = null;
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    setIsCameraOpen(false);
  }, []);

  const tick = useCallback(() => {
    if (videoRef.current?.readyState === videoRef.current.HAVE_ENOUGH_DATA && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (ctx) {
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(imageData.data, imageData.width, imageData.height, {
          inversionAttempts: 'attemptBoth',
        });

        if (code && code.data) {
          console.log("Captured:", code.data);
          setCurrentQR(code.data);
          handleQRSearch(code.data);
          stopScanner();
          return;
        }
      }
    }
    requestRef.current = requestAnimationFrame(tick);
  }, [handleQRSearch, stopScanner]);

  const startScanner = async () => {
    setIsCameraOpen(true);
    setScanStatus({ message: 'Align PG- ID in center', type: null });
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', 'true');
        await videoRef.current.play();
        requestRef.current = requestAnimationFrame(tick);
      }
    } catch (err) {
      setScanStatus({ message: 'Access Denied', type: 'error' });
      setIsCameraOpen(false);
    }
  };

  const handlePost = async (process: string, line: string = 'N/A') => {
    if (!scanningDetail) return;

    const newScan: ScanningData = {
      id: crypto.randomUUID(),
      qr_id: scanningDetail.qr_id,
      process,
      qty: scanningDetail.bundle_qty,
      status: ProductionStatus.COMPLETED,
      line,
      scanned_by: 'Rakibul',
      scan_time: new Date().toISOString()
    };

    try {
      const { error } = await supabase.from('scans').insert([newScan]);
      if (error) throw error;
      setScans(prev => [newScan, ...prev]);
      setScanStatus({ message: `Scanned: ${process}`, type: 'success' });
    } catch (error) {
      setScanStatus({ message: 'Network Sync Error', type: 'error' });
    }
  };

  if (isLoading) return (
    <div className="h-screen flex items-center justify-center bg-slate-900 text-white font-black uppercase tracking-widest text-[9px]">
      Linking Pioneer Cloud...
    </div>
  );

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <DashboardCard icon="✂️" title="Cutting Section" stats={dashboardStats.cut} color="blue" label="CUT" />
            <DashboardCard icon="🧵" title="Sewing Floor" stats={dashboardStats.sew} color="indigo" label="SEW" />
            <DashboardCard icon="🧼" title="Wash Plant" stats={dashboardStats.wash} color="cyan" label="WSH" />
            <DashboardCard icon="🏁" title="Finishing Floor" stats={dashboardStats.fin} color="emerald" label="FIN" />
          </div>
          <ProductionChart data={scans} />
        </div>
      )}

      {activeTab === 'orders' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-4 rounded-2xl border border-slate-100 flex justify-between items-center shadow-sm">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Order Production Matrix</h3>
            <button onClick={fetchData} className="bg-slate-900 text-white px-5 py-1.5 rounded-xl text-[8px] font-black uppercase shadow-lg active:scale-95 transition-transform">Refresh Data</button>
          </div>
          <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-2xl">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[1200px]">
                <thead className="bg-slate-900 text-white uppercase text-[8px] font-black tracking-widest">
                  <tr>
                    <th className="px-4 py-4 border-r border-slate-800">Buyer</th>
                    <th className="px-4 py-4 border-r border-slate-800">Style</th>
                    <th className="px-4 py-4 border-r border-slate-800">PO #</th>
                    <th className="px-4 py-4 border-r border-slate-800">Country</th>
                    <th className="px-4 py-4 border-r border-slate-800">Color</th>
                    <th className="px-4 py-4 border-r border-slate-800">Size</th>
                    <th className="px-4 py-4 border-r border-slate-800 text-right">PO Qty</th>
                    <th className="px-4 py-4 text-center bg-blue-800">Cut Out</th>
                    <th className="px-4 py-4 text-center bg-indigo-900">Sew In</th>
                    <th className="px-4 py-4 text-center bg-indigo-800">Sew Out</th>
                    <th className="px-4 py-4 text-center bg-cyan-900">Wash In</th>
                    <th className="px-4 py-4 text-center bg-cyan-800">Wash Out</th>
                    <th className="px-4 py-4 text-center bg-emerald-900">Fin In</th>
                    <th className="px-4 py-4 text-center bg-emerald-800">Fin Out</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[10px] font-black text-slate-700">
                  {orderMatrix.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 border-r border-slate-50">{item.buyer}</td>
                      <td className="px-4 py-4 border-r border-slate-50 text-blue-600">{item.style}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.po}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.country}</td>
                      <td className="px-4 py-4 border-r border-slate-50 uppercase text-slate-500">{item.color}</td>
                      <td className="px-4 py-4 border-r border-slate-50">{item.size}</td>
                      <td className="px-4 py-4 border-r border-slate-50 text-right font-black">{item.po_qty.toLocaleString()}</td>
                      <td className="px-4 py-4 text-center bg-blue-50 font-black text-blue-800">{item.cut || '-'}</td>
                      <td className="px-4 py-4 text-center bg-indigo-50/30">{item.sewIn || '-'}</td>
                      <td className="px-4 py-4 text-center bg-indigo-50 font-black text-indigo-800">{item.sewOut || '-'}</td>
                      <td className="px-4 py-4 text-center bg-cyan-50/30">{item.washIn || '-'}</td>
                      <td className="px-4 py-4 text-center bg-cyan-50 font-black text-cyan-800">{item.washOut || '-'}</td>
                      <td className="px-4 py-4 text-center bg-emerald-50/30">{item.finIn || '-'}</td>
                      <td className="px-4 py-4 text-center bg-emerald-50 font-black text-emerald-800">{item.finOut || '-'}</td>
                    </tr>
                  ))}
                  {orderMatrix.length === 0 && (
                    <tr><td colSpan={14} className="py-12 text-center text-slate-400 font-bold uppercase text-[9px]">No data in production matrix</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'scan' && (
        <div className="max-w-4xl mx-auto space-y-4 animate-fadeIn pb-24">
          {/* Ultra Compact Scan Bar */}
          <div className="flex justify-center">
            <div className="bg-white p-1 rounded-xl shadow-xl border border-slate-200 flex items-center space-x-1 w-52 md:w-64 h-9">
              <input 
                type="text" value={currentQR} 
                onChange={(e) => setCurrentQR(e.target.value)} 
                placeholder="PG- ID #" 
                className="flex-1 bg-slate-50 border-none rounded-lg px-2 py-1 text-[9px] font-black uppercase outline-none focus:bg-white transition-colors"
                onKeyDown={(e) => e.key === 'Enter' && handleQRSearch()}
              />
              <button onClick={startScanner} className="bg-blue-600 text-white w-7 h-7 rounded-lg flex items-center justify-center text-[10px] hover:bg-blue-700 active:scale-90 transition-transform">📷</button>
              <button onClick={() => handleQRSearch()} className="bg-slate-900 text-white px-2.5 h-7 rounded-lg font-black uppercase text-[8px] active:scale-95">GO</button>
            </div>
          </div>
          {scanStatus.message && (
            <p className={`text-[8px] font-black uppercase text-center ${scanStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
              {scanStatus.message}
            </p>
          )}

          {isCameraOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95">
              <div className="relative w-full max-w-sm aspect-square bg-slate-900 rounded-[2.5rem] overflow-hidden border-4 border-slate-800 shadow-2xl mx-4">
                <video ref={videoRef} className="w-full h-full object-cover" />
                <canvas ref={canvasRef} className="hidden" />
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <div className="w-52 h-52 border-2 border-blue-500/40 rounded-3xl relative overflow-hidden">
                    <div className="scan-line"></div>
                  </div>
                  <p className="mt-8 text-white text-[8px] font-black uppercase tracking-[0.3em] opacity-50">PG- ID Recognition</p>
                </div>
                <button onClick={stopScanner} className="absolute top-4 right-4 w-10 h-10 bg-white/10 rounded-full text-white flex items-center justify-center font-bold text-lg hover:bg-white/20 transition-colors">✕</button>
              </div>
            </div>
          )}

          {scanningDetail && (
            <div className="space-y-6 animate-slideUp">
              <div className="bg-slate-950 text-white rounded-[2rem] p-6 grid grid-cols-2 md:grid-cols-4 gap-6 shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-40 h-40 bg-blue-600/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
                <div className="col-span-2 border-r border-slate-800 pr-4">
                  <p className="text-[8px] font-bold text-slate-500 uppercase mb-1 tracking-widest">Identified Bundle</p>
                  <p className="text-xl font-black text-blue-400 truncate">{scanningDetail.qr_id}</p>
                </div>
                <div className="border-r border-slate-800 pr-4">
                  <p className="text-[8px] font-bold text-slate-500 uppercase mb-1 tracking-widest">Qty (Pcs)</p>
                  <p className="text-xl font-black">{scanningDetail.bundle_qty}</p>
                </div>
                <div>
                  <p className="text-[8px] font-bold text-slate-500 uppercase mb-1 tracking-widest">Style Ref</p>
                  <p className="text-xl font-black truncate">{scanningDetail.style}</p>
                </div>
                <div className="col-span-4 mt-2 flex flex-wrap gap-2 border-t border-slate-800 pt-4">
                   <Tag label="PO" value={scanningDetail.po} />
                   <Tag label="Color" value={scanningDetail.color} />
                   <Tag label="Size" value={scanningDetail.size} />
                   <Tag label="Buyer" value={scanningDetail.buyer} />
                   <Tag label="Country" value={scanningDetail.country} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <ActionSection title="Cutting Process" icon="✂️">
                  <button onClick={() => handlePost('Cutting Done')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs hover:bg-blue-700 shadow-xl shadow-blue-500/20 active:scale-95 transition-all">Add to Cutting Chart</button>
                </ActionSection>

                <ActionSection title="Sewing Section" icon="🧵">
                  <div className="grid grid-cols-2 gap-3">
                    <LinePicker title="Input (1-15)" count={15} onSelect={(l) => handlePost('Sewing Input', `Line-${l}`)} color="indigo" />
                    <LinePicker title="Output (1-15)" count={15} onSelect={(l) => handlePost('Sewing Output', `Line-${l}`)} color="emerald" />
                  </div>
                </ActionSection>

                <ActionSection title="Wash Plant" icon="🧼">
                  <div className="grid grid-cols-2 gap-3">
                    <button onClick={() => handlePost('Wash Input')} className="py-4 bg-cyan-50 text-cyan-700 border border-cyan-100 rounded-2xl font-black uppercase text-[9px] hover:bg-cyan-600 hover:text-white transition-all shadow-sm">Wash In</button>
                    <button onClick={() => handlePost('Wash Output')} className="py-4 bg-cyan-50 text-cyan-700 border border-cyan-100 rounded-2xl font-black uppercase text-[9px] hover:bg-cyan-600 hover:text-white transition-all shadow-sm">Wash Out</button>
                  </div>
                </ActionSection>

                <ActionSection title="Finishing Floor" icon="🏁">
                  <div className="grid grid-cols-2 gap-3">
                    <LinePicker title="Input (1-10)" count={10} onSelect={(l) => handlePost('Finishing Input', `Line-${l}`)} color="violet" />
                    <LinePicker title="Output (1-10)" count={10} onSelect={(l) => handlePost('Finishing Output', `Line-${l}`)} color="pink" />
                  </div>
                </ActionSection>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 flex justify-between items-center shadow-sm">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Transaction Log</h3>
            <button onClick={fetchData} className="bg-slate-900 text-white px-5 py-2 rounded-xl text-[8px] font-black uppercase shadow-lg">Cloud Sync</button>
          </div>
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 uppercase text-[8px] font-black">
                 <tr><th className="px-6 py-4">Time</th><th className="px-6 py-4">Bundle ID</th><th className="px-6 py-4">Process</th><th className="px-6 py-4 text-right">Qty</th><th className="px-6 py-4">Line</th></tr>
               </thead>
               <tbody className="divide-y divide-slate-50 text-[10px] font-bold text-slate-600">
                 {scans.map(s => (
                   <tr key={s.id} className="hover:bg-slate-50 transition-colors">
                     <td className="px-6 py-3 text-slate-400">{new Date(s.scan_time).toLocaleTimeString()}</td>
                     <td className="px-6 py-3 font-black text-slate-900">{s.qr_id}</td>
                     <td className="px-6 py-3 uppercase"><span className="bg-slate-100 px-3 py-1 rounded-full text-[8px]">{s.process}</span></td>
                     <td className="px-6 py-3 text-right font-black">{s.qty}</td>
                     <td className="px-6 py-3 text-slate-400 italic text-[9px]">{s.line}</td>
                   </tr>
                 ))}
                 {scans.length === 0 && (
                   <tr><td colSpan={5} className="py-10 text-center text-slate-300 uppercase text-[9px] font-black">No recent scans recorded</td></tr>
                 )}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </Layout>
  );
};

const Tag: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <span className="bg-slate-800 px-3 py-1 rounded-lg text-[8px] font-bold border border-slate-700">
    <span className="text-slate-500 mr-1 uppercase tracking-tighter">{label}:</span>
    <span className="text-blue-200 uppercase">{value}</span>
  </span>
);

const DashboardCard: React.FC<{ icon: string, title: string, stats: any, color: string, label: string }> = ({ icon, title, stats, color, label }) => {
  const c = color === 'blue' ? 'text-blue-600 border-t-blue-500' : color === 'indigo' ? 'text-indigo-600 border-t-indigo-500' : color === 'cyan' ? 'text-cyan-600 border-t-cyan-500' : 'text-emerald-600 border-t-emerald-500';
  return (
    <div className={`p-6 rounded-[2rem] border border-slate-100 border-t-4 bg-white shadow-sm hover:shadow-xl transition-all relative group overflow-hidden ${c.split(' ')[1]}`}>
      <div className={`absolute -right-2 -top-2 ${c.split(' ')[0]} opacity-5 text-6xl font-black transition-transform group-hover:scale-110`}>{label}</div>
      <div className="flex items-center space-x-3 mb-6">
        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-xl shadow-inner">{icon}</div>
        <h4 className="text-[9px] font-black uppercase text-slate-400 tracking-widest">{title}</h4>
      </div>
      <div className="space-y-4">
        <div>
          <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mb-1">TOTAL INPUT</p>
          <p className={`text-3xl font-black ${c.split(' ')[0]}`}>{stats.input.toLocaleString()}</p>
        </div>
        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-50">
          <div><p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">WIP</p><p className="text-[11px] font-black text-slate-800">{stats.wip.toLocaleString()}</p></div>
          <div><p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">EFFICIENCY</p><p className={`text-[11px] font-black ${c.split(' ')[0]}`}>{stats.eff}%</p></div>
        </div>
      </div>
    </div>
  );
};

const ActionSection: React.FC<{ title: string, icon: string, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
    <div className="flex items-center space-x-3 mb-4">
      <div className="w-7 h-7 rounded-lg bg-slate-50 flex items-center justify-center text-lg">{icon}</div>
      <h4 className="text-[9px] font-black uppercase text-slate-400 tracking-widest">{title}</h4>
    </div>
    {children}
  </div>
);

const LinePicker: React.FC<{ title: string, count: number, onSelect: (l: number) => void, color: string }> = ({ title, count, onSelect, color }) => (
  <div className="bg-slate-50/50 p-2 rounded-2xl border border-slate-50">
    <p className={`text-[7px] font-black text-center mb-2 uppercase tracking-widest text-slate-400`}>{title}</p>
    <div className="grid grid-cols-3 gap-1">
      {Array.from({ length: count }).map((_, i) => (
        <button key={i} onClick={() => onSelect(i + 1)} className="py-1.5 bg-white border border-slate-200 rounded-lg text-[8px] font-black hover:bg-slate-900 hover:text-white transition-all active:scale-90">{i + 1}</button>
      ))}
    </div>
  </div>
);

export default App;
